import { exploreActivities24 } from './exploreActivities24';
import { dailyActivities12to18 } from './dailyActivities12to18';
import { dailyActivities18to24 } from './dailyActivities18to24';
import { homeActivitiesGreek } from './homeActivitiesGreek';

export type Category = 'spark' | 'move' | 'play';
export type LocalizedText = { en: string; el: string };

export interface HomeActivity {
  id: string;
  category: Category;
  ageRangeStart: number;
  ageRangeEnd: number;
  title: LocalizedText;
  instruction: LocalizedText;
  why: LocalizedText;
  imageDescription: string;
}

export interface ExploreActivity {
  id: string;
  category: Category;
  ageRangeStart: number;
  ageRangeEnd: number;
  title: string;
  instruction: string;
  why: string;
  imageDescription: string;
}

type RawActivity = Omit<HomeActivity, "title" | "instruction" | "why"> & {
  title: string;
  instruction: string;
  why: string;
};

function remapPseudoWeekToRealWeek(pseudoWeek: number): number {
  return Math.round((pseudoWeek / 4) * (52 / 12));
}

function remapActivitiesToRealWeeks(activities: RawActivity[]): RawActivity[] {
  return activities.map((activity) => ({
    ...activity,
    ageRangeStart: remapPseudoWeekToRealWeek(activity.ageRangeStart),
    ageRangeEnd: remapPseudoWeekToRealWeek(activity.ageRangeEnd),
  }));
}

const dailyActivities12to18RealWeeks = remapActivitiesToRealWeeks(dailyActivities12to18 as RawActivity[]);
const dailyActivities18to24RealWeeks = remapActivitiesToRealWeeks(dailyActivities18to24 as RawActivity[]);

const dailyActivitiesRaw: RawActivity[] = [
  { id: 's-0-1', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Face Study', instruction: 'Hold your face about 8–10 inches from your baby\'s eyes, roughly the distance from your elbow to your fist. Stay still and let them look at you for a full minute.', why: 'Newborns can only focus at about that distance, and human faces are the most interesting thing in their world right now.', imageDescription: 'Close-up of a newborn gazing up at their parent\'s face, warm afternoon window light, soft focus background.' },
  { id: 's-0-2', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Stick Out Your Tongue', instruction: 'When your baby is calm and alert, look right at them and slowly stick your tongue out. Hold it there for a few seconds, then pull it back in. Repeat a few times.', why: 'Babies can imitate facial movements from just days old, it\'s their first sign of social learning.', imageDescription: 'Parent lying face-to-face with newborn on a white pillow, both with mouths slightly open, natural light.' },
  { id: 's-0-3', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'High-Contrast Card Time', instruction: 'Hold a black-and-white striped or checked card about 10 inches from baby\'s face and move it very slowly from left to right. Watch their eyes try to follow.', why: 'Newborn vision is drawn to strong contrast, this is literally the most visually stimulating thing you can show them right now.', imageDescription: 'Newborn lying on a cream blanket with a bold black-and-white card propped nearby, soft natural light.' },
  { id: 's-0-4', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Window Light Watching', instruction: 'Hold your baby facing a bright window (not direct sunlight) and let them stare at the light and moving shadows outside for a few minutes. No need to say anything.', why: 'Changes in light and shadow are natural visual puzzles that gently exercise a newborn\'s developing visual system.', imageDescription: 'Parent holding newborn facing large window, baby\'s face lit by soft daylight, cozy curtains framing the scene.' },
  { id: 's-0-5', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Coo Back at Me', instruction: 'When your baby makes any sound, a little grunt, a sigh, a coo, respond with the same sound back. Pause and wait for them to go again. Keep the \'conversation\' going.', why: 'This back-and-forth is your baby\'s very first experience of communication, and it wires their brain for language.', imageDescription: 'Parent leaning close to awake newborn in a bouncy seat, both mid-expression, warm kitchen light.' },
  { id: 's-0-6', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Name Everything You Touch', instruction: 'During a diaper change or feed, narrate everything you pick up: \'Here\'s the wipe, it\'s a little cold! Now the diaper. Now the cream.\' Keep your voice warm and calm.', why: 'Your baby\'s brain is cataloguing words even before they can speak, the more they hear, the bigger the vocabulary bank.', imageDescription: 'Parent changing newborn on a wooden changing table, talking to baby who gazes up, warm lamp light.' },
  { id: 's-0-7', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Soft Music Pause', instruction: 'Play a short piece of gentle music and just hold your baby quietly. When the music stops, watch their face, some babies change expression noticeably at the silence.', why: 'Noticing the difference between sound and silence is one of the earliest auditory thinking skills.', imageDescription: 'Parent sitting in an armchair holding swaddled newborn, small speaker nearby, soft morning light.' },
  { id: 's-0-8', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Track the Toy', instruction: 'Hold a bright-colored rattle or small toy about 10 inches from baby\'s face. Once their eyes lock onto it, slowly move it to one side, just a few inches at first.', why: 'Visual tracking strengthens the neural pathways between the eyes and brain that underpin all future learning.', imageDescription: 'Newborn lying on a play mat, parent\'s hand holding a small colorful toy nearby, soft natural light.' },
  { id: 's-0-9', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Different Voices', instruction: 'Talk to your baby in your normal voice, then try a slightly higher pitch, then a whisper. Watch which one makes them most alert or turns their head toward you.', why: 'Babies process different vocal tones differently, exploring this helps you learn their preferences and sharpens their auditory attention.', imageDescription: 'Parent holding newborn close, face-to-face, mid-conversation, warm overhead light in a nursery.' },
  { id: 's-0-10', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Calm Stare', instruction: 'Find a quiet moment when your baby is awake and content. Sit them in your lap facing you, and just look at each other with a soft expression for a couple of minutes.', why: 'Extended mutual gaze activates deep social bonding circuits and teaches your baby that eye contact is meaningful.', imageDescription: 'Parent and newborn in a sunny nook, baby propped against parent\'s knees, both gazing at each other.' },
  { id: 's-0-11', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Rattle Sound Discovery', instruction: 'Hold a soft rattle out of your baby\'s line of sight, slightly to their left or right, and give it a gentle shake. See if their eyes shift or they turn toward the sound.', why: 'Locating where a sound is coming from is an early cognitive skill that links hearing and spatial awareness.', imageDescription: 'Newborn on a blanket, parent shaking a pastel rattle just beside their head, warm natural light.' },
  { id: 's-0-12', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Mobile Moments', instruction: 'Place your baby under a hanging mobile and let them look up at it for 3–5 minutes. If the pieces move slowly in airflow, even better, watch their eyes follow.', why: 'Tracking slowly moving objects overhead is a perfect workout for developing visual focus and concentration.', imageDescription: 'Newborn lying on a white play gym mat, looking up at a pastel mobile, soft window light from the side.' },
  { id: 's-0-13', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Read Aloud Anything', instruction: 'Pick up any book, even your own novel, and read a few paragraphs out loud to your baby while they lie on your chest or in your lap. Vary your tone naturally.', why: 'It\'s not the content but the experience of language rhythm, tone, and the sound of your voice that matters at this age.', imageDescription: 'Parent reading a paperback while newborn rests on their chest, afternoon light through a window.' },
  { id: 's-0-14', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Touch and Name', instruction: 'During a calm moment, gently touch your baby\'s hand and say \'hand.\' Touch their foot, \'foot.\' Cheek, \'cheek.\' Take it slow and look at their face each time.', why: 'Pairing touch with a word is the earliest form of concept learning, building a mental map of the body.', imageDescription: 'Parent gently holding a newborn\'s tiny hand, both in soft natural light, close-up warm-toned image.' },
  { id: 's-0-15', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bright vs Dim', instruction: 'Carry your baby through a bright room, then step into a dimmer one. Pause in each spot for 30 seconds and watch how their eyes and expression change.', why: 'Reacting to changes in light is one of the brain\'s first environmental processing tasks.', imageDescription: 'Parent walking through a hallway from a bright kitchen into a softer-lit living room, baby in arms looking around.' },
  { id: 's-0-16', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Mirror Hello', instruction: 'Hold your baby in front of a mirror and let them look at their reflection. Point to the baby in the mirror and say \'That\'s you!\' Keep it brief, a minute is plenty.', why: 'Babies find faces endlessly interesting, and the mirror doubles the amount of face-gazing they can do.', imageDescription: 'Parent holding newborn in front of a bathroom mirror, baby\'s reflection visible, soft morning light.' },
  { id: 's-0-17', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Whisper vs Normal', instruction: 'Say \'hello little one\' in your normal voice, pause, then whisper the exact same words. Do this a few times and watch whether your baby responds differently each time.', why: 'Noticing vocal contrast is the beginning of understanding that communication comes in many forms.', imageDescription: 'Parent leaning close to newborn lying on a blanket, soft expression, quiet room, warm lamp light.' },
  { id: 's-0-18', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Slow Color Scarf', instruction: 'Hold a brightly colored scarf about 10 inches above your baby\'s face and let it drift gently downward toward them, not touching, then lift it back up slowly.', why: 'Tracking an object that moves toward and away from them teaches babies about depth and object movement.', imageDescription: 'Newborn on a white blanket, colorful silk scarf held above them floating in the air, soft natural light.' },
  { id: 's-0-19', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Sing a Simple Song', instruction: 'Sing any short, repetitive song, \'Twinkle Twinkle,\' \'Row Your Boat,\' or one you make up, while making eye contact. Sing it twice in a row the same way.', why: 'Repetition and melody help the brain recognize patterns, which is a foundational thinking skill.', imageDescription: 'Parent singing to newborn resting on their lap, smiling warmly, soft window light behind them.' },
  { id: 's-0-20', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Waiting Game', instruction: 'After you do something that gets a reaction, like a funny sound or a smile, pause and just wait with an expectant face. Give baby a full 10 seconds to respond.', why: 'Pausing gives your baby space to initiate communication, which builds conversational thinking from the very start.', imageDescription: 'Parent smiling gently at newborn lying in front of them, both in quiet moment of eye contact, warm light.' },
  { id: 's-0-21', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Watch the Ceiling Fan', instruction: 'Hold your baby so they can watch a slowly turning ceiling fan (from a safe distance). Let them stare as long as they want, no need to comment.', why: 'Moving objects that repeat a predictable pattern are fascinating and calming for a newborn\'s developing brain.', imageDescription: 'Newborn lying on a blanket gazing upward, ceiling fan visible softly blurred above, gentle natural light.' },
  { id: 's-0-22', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Sounds of the House', instruction: 'Carry your baby slowly through the house and pause near different sounds, a ticking clock, the dishwasher, a radio. Watch their face with each one.', why: 'Identifying and responding to different environmental sounds is early auditory discrimination in action.', imageDescription: 'Parent carrying newborn through a cozy kitchen, pausing near the sound of something cooking, warm light.' },
  { id: 's-0-23', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Gentle Head Turn', instruction: 'While baby lies on their back, softly call their name from one side, just out of view. Give them time to slowly turn their head toward your voice.', why: 'Orienting to a familiar voice is one of the first signs of recognition, your baby already knows who you are.', imageDescription: 'Newborn lying on a play mat, parent leaning in from the side softly calling their name, warm natural light.' },
  { id: 's-0-24', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Two Colors, Two Reactions', instruction: 'Show your baby a red object for about 30 seconds, then swap it for a yellow one at the same distance. Watch whether they look longer at one color than the other.', why: 'Babies show early color preferences, and noticing them gives you a window into your baby\'s visual processing.', imageDescription: 'Parent holding two small colorful toys in turn in front of a calm newborn, bright natural window light.' },
  { id: 's-0-25', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Talk Through the Routine', instruction: 'Pick one daily routine, bath time, getting dressed, going to sleep, and say the same simple words in the same order every time you do it.', why: 'Predictable language sequences teach babies that words follow patterns, priming their brain for speech.', imageDescription: 'Parent talking to newborn during bath in a small white baby tub, steam and soft bathroom light, calm atmosphere.' },
  { id: 's-0-26', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Watch the Trees', instruction: 'Take your baby outside and hold them facing a tree or leaves moving in the breeze. Just let them look, you don\'t need to say anything unless you want to.', why: 'The complex, unpredictable movement of leaves and branches is some of the richest visual input available in nature.', imageDescription: 'Parent standing outdoors holding newborn facing trees, dappled sunlight through leaves, peaceful garden setting.' },
  { id: 's-0-27', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Pause the Feed', instruction: 'During a feed, pause briefly and make eye contact with your baby. See if they look up at you. Resume and pause again a minute later.', why: 'These tiny moments of shared gaze during feeding build the neural foundation for joint attention, crucial for learning.', imageDescription: 'Parent nursing or bottle-feeding newborn, pausing to make eye contact, soft warm light in a calm room.' },
  { id: 's-0-28', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Soft Bell Ring', instruction: 'Hold a small, soft-sounding bell just behind and to the side of your baby\'s ear and give it one gentle ring. Wait and watch their reaction before trying the other side.', why: 'Responding to a soft unexpected sound shows that the auditory system is working and learning to prioritize input.', imageDescription: 'Parent holding a small fabric bell near a swaddled newborn, soft morning light, peaceful nursery setting.' },
  { id: 's-0-29', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Copy Their Face', instruction: 'Watch your baby\'s expression for a moment, then mirror whatever they\'re doing, a wide mouth, raised eyebrows, a scrunch. Hold the expression and see if they react.', why: 'Facial imitation is a two-way street, and when you mirror your baby it teaches them that their expressions have meaning.', imageDescription: 'Parent face-to-face with newborn on a white pillow, both with matching open-mouthed expressions, natural light.' },
  { id: 's-0-30', category: 'spark', ageRangeStart: 0, ageRangeEnd: 8, title: 'Story Time at Night', instruction: 'In your bedtime routine, read one short board book in the same calm tone every night. Even if your baby is drowsy, keep going, the rhythm and your voice matter.', why: 'A consistent bedtime story builds auditory memory and signals to the brain that sleep is coming.', imageDescription: 'Parent reading a small board book to a sleepy newborn in dim lamp light, warm and cozy bedroom atmosphere.' },
  { id: 'm-0-1', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Chest Tummy Time', instruction: 'Recline slightly on the sofa and place your baby face-down on your chest. Support their bottom and just let them lift their head a little when they\'re ready.', why: 'This is the gentlest way to start tummy time, the warmth and familiar smell of you makes the effort much easier.', imageDescription: 'Parent reclining on a sofa with newborn lying chest-to-chest, baby\'s head lifting slightly, cozy afternoon light.' },
  { id: 'm-0-2', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Stretch and Open', instruction: 'Lay your baby on their back and very gently open their arms out wide, then bring them back in across their chest. Do this 3–4 times slowly and smoothly.', why: 'Gentle bilateral arm movement builds early body awareness and starts to develop the shoulder muscles.', imageDescription: 'Newborn lying on a soft play mat, parent gently stretching baby\'s arms wide, warm natural light.' },
  { id: 'm-0-3', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bicycle Kick', instruction: 'Hold your baby\'s ankles and gently cycle their legs, left leg forward as right goes back, like they\'re pedalling a tiny bike. Go slowly and say \'round and round.\'', why: 'This movement activates the hip flexors, aids digestion, and gives baby their first sense of intentional leg motion.', imageDescription: 'Newborn on a changing mat, parent gently moving their legs in a cycling motion, bright clean light.' },
  { id: 'm-0-4', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Time on Lap', instruction: 'Sit in a chair and lay your baby face-down across your thighs. Put one hand gently on their back for security. Let them lift their head briefly when they feel like it.', why: 'The slight curve of your lap creates a gentle incline that makes head-lifting a little easier for tiny neck muscles.', imageDescription: 'Parent sitting in a kitchen chair with newborn lying across their lap face-down, looking comfortable, natural light.' },
  { id: 'm-0-5', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Kick the Air', instruction: 'Lay your baby on a firm surface and hold your hands just above their feet, not touching. Watch them kick. You can let them push against your palms when they make contact.', why: 'Kicking against gentle resistance builds leg strength and teaches your baby that their body can affect the world.', imageDescription: 'Newborn lying on a play mat, parent\'s hands hovering above baby\'s feet ready to feel them kick, bright light.' },
  { id: 'm-0-6', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Hands to Face', instruction: 'Place your baby\'s hands near their face (not over the eyes) when they\'re lying on their back. Watch whether they bring a hand to their mouth on their own.', why: 'Hand-to-mouth is one of the earliest purposeful movements, it builds self-soothing and early fine motor awareness.', imageDescription: 'Newborn lying on a white blanket, tiny hands near their mouth, peaceful close-up shot, soft natural light.' },
  { id: 'm-0-7', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Supported Head Lift', instruction: 'Hold your baby upright against your shoulder and very gently ease your supporting hand back slightly, just enough so their head needs to do a tiny bit of the work.', why: 'Brief unsupported moments give the neck muscles a chance to fire, building the head control they\'ll need for everything ahead.', imageDescription: 'Parent holding newborn over their shoulder, baby\'s head slightly lifted, parent ready to catch, warm indoor light.' },
  { id: 'm-0-8', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Leg Press', instruction: 'Hold your baby on your lap facing you and let the bottoms of their feet press against your belly. Let them push and straighten their legs at their own pace.', why: 'Weight-bearing through the feet starts strengthening leg bones and muscles, and babies find the pushing sensation satisfying.', imageDescription: 'Parent with newborn on their lap, baby\'s feet pressed against parent\'s tummy, baby mid-push, warm afternoon light.' },
  { id: 'm-0-9', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Gentle Roll to Side', instruction: 'While your baby lies on their back, bend one knee toward their chest and let it naturally tip them gently onto their side. Hold for 5 seconds, then return. Do the other side.', why: 'Experiencing lateral rotation teaches the body what rolling feels like long before baby can initiate it.', imageDescription: 'Parent gently guiding a newborn onto their side on a soft mat, one hand supporting, natural light.' },
  { id: 'm-0-10', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Time with Rolled Blanket', instruction: 'Roll a small blanket and tuck it under your baby\'s chest during tummy time, so their upper body is gently elevated. Put a colorful toy in front of them.', why: 'The incline reduces effort and makes tummy time accessible for babies who find the flat version frustrating.', imageDescription: 'Newborn on tummy propped over a rolled blanket on a play mat, colorful toy in front, soft side lighting.' },
  { id: 'm-0-11', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Pull-Up Practice', instruction: 'Hold your baby\'s forearms (not hands) and slowly pull them partway to sitting, letting their head lag behind naturally. Stop halfway, hold briefly, and lower back down.', why: 'The lag and recovery engage the deep neck muscles in the safest possible way.', imageDescription: 'Parent pulling newborn gently to a semi-sitting position on a blanket, holding baby\'s forearms, soft light.' },
  { id: 'm-0-12', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Arm Cross', instruction: 'Gently hold baby\'s wrists and cross their arms over their chest, then open them out wide again. Repeat 3 times slowly. Say \'open\' and \'close\' as you go.', why: 'This builds early chest and shoulder flexibility and gives your baby a sense of where their arms are in space.', imageDescription: 'Newborn lying on a soft play mat, parent gently crossing their arms over their chest, bright natural window light.' },
  { id: 'm-0-13', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bouncy Walk', instruction: 'Hold your baby securely in both arms and walk slowly with a gentle, rhythmic bounce, like a very slow rock. Keep the movement subtle and predictable.', why: 'Gentle rhythmic movement activates the vestibular system, which underpins balance, coordination, and calm.', imageDescription: 'Parent walking slowly through a cozy living room, holding newborn in a gentle bouncing carry, warm afternoon light.' },
  { id: 'm-0-14', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Head Turn Stretch', instruction: 'While your baby lies on their back, gently turn their head to one side and hold for 5 seconds. Then center, then the other side. Always move slowly without forcing.', why: 'Gentle neck rotation keeps range of motion healthy and can help if your baby tends to look only one direction.', imageDescription: 'Newborn on a white changing mat, parent gently turning baby\'s head to the side, calm neutral light.' },
  { id: 'm-0-15', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Floor Tummy Time', instruction: 'Place your baby face-down on a firm, flat surface for 1–2 minutes. Get down on their level and make eye contact to give them a reason to lift their head.', why: 'Even a minute or two of tummy time daily builds the shoulder and neck strength that rolling and sitting depend on.', imageDescription: 'Newborn on a colorful play mat in tummy time position, parent lying on the floor in front, both at eye level.' },
  { id: 'm-0-16', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Finger Grasp', instruction: 'Lay your baby on their back and put one of your fingers in each of their palms. Feel them grip. Gently try to pull your finger away and feel them hold on.', why: 'The palmar grasp is a newborn reflex that, through gentle practice, begins to develop into intentional grasping.', imageDescription: 'Newborn\'s tiny hand gripping a parent\'s finger, close-up shot, warm natural light, soft background.' },
  { id: 'm-0-17', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Kick the Toy', instruction: 'Hang a soft toy or crinkle tag from a ribbon just above baby\'s feet during floor time. Let them discover through random kicks that their movement makes something happen.', why: 'When baby realizes their kick causes a reaction, it\'s the beginning of intentional motor control.', imageDescription: 'Newborn on a play gym with feet near a dangling toy, one foot mid-kick, bright soft room light.' },
  { id: 'm-0-18', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Time on the Ball', instruction: 'Place your baby face-down on a large, firm exercise ball (hold them securely at all times) and gently tilt the ball just slightly forward and back.', why: 'The gentle motion adds a vestibular challenge to tummy time and makes it novel enough to engage babies who resist the mat.', imageDescription: 'Parent holding newborn face-down on a large exercise ball, tilting slightly, bright playroom light.' },
  { id: 'm-0-19', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Upright Carry', instruction: 'Hold your baby upright against your chest so their feet dangle and they can look outward over your arm. Take a slow walk through the house for 5 minutes.', why: 'The upright position against gravity is a gentle core workout, and the changing view stimulates both brain and body.', imageDescription: 'Parent carrying newborn upright facing outward, arm supporting baby\'s bottom, walking through a bright home.' },
  { id: 'm-0-20', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Back of Hand Stroke', instruction: 'Place a finger gently on the back of your baby\'s fist and stroke outward toward their fingers. Watch them slowly open their hand in response.', why: 'Stimulating the back of the hand triggers the hand-opening reflex and begins to develop hand awareness.', imageDescription: 'Parent gently stroking the back of a newborn\'s tiny closed fist, close-up warm-toned image, soft natural light.' },
  { id: 'm-0-21', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Carrier Time', instruction: 'Pop your baby in a soft carrier or wrap for 20–30 minutes while you go about your day. The closer and more upright, the better.', why: 'Being carried activates the vestibular system through your natural movement, richer stimulation than lying still.', imageDescription: 'Parent wearing newborn in a soft wrap carrier, walking through a bright kitchen, calm everyday atmosphere.' },
  { id: 'm-0-22', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Time After Every Nap', instruction: 'Build the habit of placing your baby on their tummy for one minute right after they wake from a nap, before you pick them up. Stay right there with them.', why: 'Habit-stacking tummy time onto nap waking makes it consistent without any extra effort.', imageDescription: 'Newborn placed face-down on a crib mattress just after waking, parent leaning over them, soft morning light.' },
  { id: 'm-0-23', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Knee to Chest', instruction: 'Gently bend one of your baby\'s knees up toward their tummy, hold for 3 seconds, then straighten it back out. Alternate legs and do 4 slow repetitions each side.', why: 'This movement eases gas, promotes digestion, and gently activates the hip and core muscles.', imageDescription: 'Parent doing gentle knee-to-chest stretches with a newborn on a changing mat, warm nursery light.' },
  { id: 'm-0-24', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Back Float in Arms', instruction: 'Hold your baby on their back in your arms, letting their head rest in the crook of your elbow. Sway gently from side to side like a hammock.', why: 'The lateral rocking motion activates the inner ear balance system, which is connected to everything from coordination to calm.', imageDescription: 'Parent swaying newborn in their arms in a back-lying position, soft living room light, peaceful mood.' },
  { id: 'm-0-25', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Foot Flex', instruction: 'Hold your baby\'s foot and gently press the ball of their foot upward so the toes flex back. Then point the foot down. Alternate in a slow rhythm.', why: 'Ankle and foot flexion activates the leg\'s proprioceptive receptors, helping your baby start to sense where their body is.', imageDescription: 'Parent holding newborn\'s foot and gently flexing it, close-up of baby feet, warm soft light.' },
  { id: 'm-0-26', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Airplane Hold', instruction: 'Slide one hand under your baby\'s tummy between their legs and hold them face-down horizontally on your forearm, your other hand free to steady them. Gently sway.', why: 'This carry position is essentially unsupported tummy time in motion, a double dose of core and vestibular work.', imageDescription: 'Parent holding newborn in a face-down airplane position on their forearm, walking through the living room.' },
  { id: 'm-0-27', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Time with Voice', instruction: 'Place your baby on their tummy and kneel behind their head. Call their name softly so they try to turn and lift toward your voice.', why: 'Adding a reason to lift, your voice, makes tummy time more effective and much more engaging for your baby.', imageDescription: 'Newborn in tummy time position, parent kneeling close behind calling their name, bright play mat, warm light.' },
  { id: 'm-0-28', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Gentle Pat-a-Cake', instruction: 'Take your baby\'s hands in yours and bring them together in a soft clap, then open them wide. Do it slowly and say \'pat-a-cake\' as you go, just two or three times.', why: 'This gentle bilateral movement begins to develop the sense that both hands can work together.', imageDescription: 'Parent holding newborn\'s hands together in a soft clap, both hands visible in warm natural light, close-up.' },
  { id: 'm-0-29', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bare Feet on Grass', instruction: 'On a mild day, let your baby\'s bare feet touch cool grass for 30 seconds while you hold them securely in your arms. Watch their reaction.', why: 'The soles of the feet are full of nerve endings, novel textures activate the tactile-proprioceptive pathways.', imageDescription: 'Parent holding newborn with tiny bare feet just touching green grass, warm outdoor light, spring setting.' },
  { id: 'm-0-30', category: 'move', ageRangeStart: 0, ageRangeEnd: 8, title: 'Resistance Kick', instruction: 'Hold your palm firmly against the soles of your baby\'s feet while they lie on their back. Let them push against you. Follow their pace, don\'t push back.', why: 'Pushing against resistance is a baby\'s first strength exercise, building the muscles they need to eventually stand.', imageDescription: 'Parent holding palm against newborn\'s feet while baby pushes, bright nursery light, warm-toned image.' },
  { id: 'p-0-1', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Skin-to-Skin Hour', instruction: 'Hold your bare baby against your bare chest under a warm blanket. No screen, no phone, just you both. Even 20 minutes counts.', why: 'Skin-to-skin contact regulates your baby\'s heart rate, temperature, and stress hormones in ways nothing else can match.', imageDescription: 'Parent lying back with newborn on bare chest, both under a soft blanket, warm afternoon light, intimate and calm.' },
  { id: 'p-0-2', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Morning Hello', instruction: 'When your baby wakes up, take a breath before you do anything else and greet them with a warm, relaxed face. Say their name slowly. Let them find your eyes.', why: 'The way you greet your baby in calm moments sets the emotional tone for how they expect interactions to feel.', imageDescription: 'Parent leaning over a bassinet greeting a just-awake newborn, soft morning light, warm and tender expression.' },
  { id: 'p-0-3', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Sing Your Name', instruction: 'Make up a tiny song using just your baby\'s name, it can be three words set to any tune you like. Sing it the same way every day, especially during care routines.', why: 'Hearing their own name sung is deeply familiar and comforting, and builds a sense of identity from the very start.', imageDescription: 'Parent holding newborn and singing softly, warm natural light, peaceful home setting.' },
  { id: 'p-0-4', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tell Them Your Day', instruction: 'Hold your baby and talk through what\'s going to happen today in a calm, matter-of-fact way, even if they have no idea what you\'re saying. Your voice is the point.', why: 'Your voice is the most comforting sound your baby knows. Talking to them builds trust and lays groundwork for language.', imageDescription: 'Parent sitting with newborn in their lap, talking to them, mid-morning light, relaxed home environment.' },
  { id: 'p-0-5', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Smell Sharing', instruction: 'Sleep with a small soft cloth for one night, then tuck it near your baby when they sleep (outside the sleep area, not in the crib). Your scent is there even when you\'re not.', why: 'Babies recognize the primary caregiver by smell before sight, your scent is comfort, safety, and you.', imageDescription: 'Newborn sleeping near a soft cloth peeking from the side of a bassinet, dim peaceful nursery light.' },
  { id: 'p-0-6', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Long Gaze', instruction: 'When your baby is calm and alert, sit with them and make soft eye contact for as long as they\'ll hold it, sometimes they go for several minutes.', why: 'Sustained mutual eye contact is one of the most powerful bonding experiences, building attachment and trust.', imageDescription: 'Parent lying on their side, face-to-face with newborn, both gazing at each other, warm golden light.' },
  { id: 'p-0-7', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bedtime Ritual', instruction: 'Pick three simple things, a bath, a song, a cuddle, and do them in exactly the same order every night before sleep. Consistency is the whole point.', why: 'Predictable routines reduce your baby\'s stress and build a deep sense of safety and trust in the world.', imageDescription: 'Parent wrapping newborn in a towel after bath, soft bathroom light, calm evening atmosphere.' },
  { id: 'p-0-8', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Heartbeat Hold', instruction: 'Hold your baby against the left side of your chest so they can feel and hear your heartbeat. Breathe slowly and steadily.', why: 'Your heartbeat was the soundtrack to their nine months in the womb, it\'s still the most comforting sound they know.', imageDescription: 'Parent holding newborn against their left chest, baby\'s ear pressed gently in place, quiet home light.' },
  { id: 'p-0-9', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Mirror Smile', instruction: 'Hold your baby in front of a mirror and smile at the reflection. Say \'look at us!\' in a warm voice. See if they look at the mirror baby or at your reflection.', why: 'Social referencing, looking to you to see how you react, starts in these early weeks.', imageDescription: 'Parent and newborn looking at their reflection in a large mirror, both visible, warm natural light.' },
  { id: 'p-0-10', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tell Them What You Feel', instruction: 'Hold your baby and say out loud, simply and calmly: \'I love you\' or \'I\'m so happy you\'re here\' or \'you made me smile today.\' It doesn\'t need to be elaborate.', why: 'The emotional warmth in your voice when you say words of love registers even before language is understood.', imageDescription: 'Parent holding newborn close to their face, eyes soft and tender, warm golden-hour window light.' },
  { id: 'p-0-11', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Slow Dance', instruction: 'Hold your baby close and slow-dance to one song, something you love. Sway gently and hum along if you know the words.', why: 'Movement, music, and closeness combined create a deeply soothing multi-sensory bonding experience.', imageDescription: 'Parent slowly dancing in a living room with newborn held against their chest, soft lamp light, evening mood.' },
  { id: 'p-0-12', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Talk Through the Feed', instruction: 'During feeding, talk softly to your baby, tell them how well they\'re doing, what you\'re thinking, or just describe the room. Look at them when they look up.', why: 'Feeding is already a time of closeness, layering in eye contact and voice makes it a full bonding experience.', imageDescription: 'Parent nursing or bottle-feeding newborn, looking down at baby with a gentle smile, warm soft light.' },
  { id: 'p-0-13', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Welcome Name', instruction: 'Every time you come into the room where your baby is, say their name first in a warm, bright voice before you do anything else.', why: 'Consistently hearing their name spoken warmly helps your baby connect that sound to themselves and to your arrival, safety.', imageDescription: 'Parent stepping into a nursery doorway, leaning toward bassinet with a warm expression, soft morning light.' },
  { id: 'p-0-14', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Describe Their Face', instruction: 'With your baby calm and awake, trace the outline of their face with one finger and narrate quietly: \'little nose... soft cheek... tiny ear...\'', why: 'Gentle physical attention paired with a calm voice deepens both physical and emotional awareness together.', imageDescription: 'Parent gently tracing a newborn\'s face with one finger, baby lying still, warm close-up natural light shot.' },
  { id: 'p-0-15', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Nap Together', instruction: 'If you can, take one nap with your baby resting on your chest (safely, on a firm surface or in a carrier). Let yourself actually rest.', why: 'Shared rest is bonding too, your baby regulates to your breathing and heartbeat while you both recover.', imageDescription: 'Parent napping in a reclined position with newborn sleeping on their chest, cozy warm light, peaceful scene.' },
  { id: 'p-0-16', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Bath Talking Time', instruction: 'During bath time, keep up a gentle running commentary: \'now we\'re washing your arm... doesn\'t the warm water feel nice?... there\'s your little foot.\'', why: 'Bath time is already a sensory experience, your warm voice turns it into a full bonding and language moment.', imageDescription: 'Parent washing newborn in a small baby bath, talking down at baby, warm bathroom light, relaxed expression.' },
  { id: 'p-0-17', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Share a Breath', instruction: 'Hold your baby close and take three slow, deep breaths. Breathe out gently near their face. Let them feel the rise and fall of your chest.', why: 'When you slow your breathing, your baby tends to follow, it\'s one of the earliest forms of emotional co-regulation.', imageDescription: 'Parent holding newborn very close, both breathing quietly, eyes closed or soft, warm intimate lighting.' },
  { id: 'p-0-18', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Play Peekaboo With Your Voice', instruction: 'Say your baby\'s name in a warm normal tone. Then go quiet for 5 seconds. Then say it again. Let the silence be its own moment.', why: 'The contrast between sound and quiet teaches your baby that you\'re still there even when they can\'t hear you, the first trust lesson.', imageDescription: 'Parent leaning toward newborn in a bouncy seat, mid-expression of calling their name, soft indoor light.' },
  { id: 'p-0-19', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Evening Recap', instruction: 'At the end of the day, hold your baby and quietly recap: \'We had a bath this morning... Grandma visited... you slept really well...\' Keep your voice calm and narrative.', why: 'A consistent end-of-day recap becomes a wind-down ritual that helps your baby associate nighttime with calm and safety.', imageDescription: 'Parent sitting in a nursing chair in soft lamp light, holding newborn and speaking quietly, evening atmosphere.' },
  { id: 'p-0-20', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Tummy Massage', instruction: 'Using two warm fingertips, make small clockwise circles on your baby\'s tummy. Start at the navel and move gently outward. Do this when they\'re calm and not right after a feed.', why: 'Gentle belly massage builds body trust and can ease gas, a practical form of comfort-based bonding.', imageDescription: 'Parent doing gentle tummy massage on bare-tummied newborn on a changing mat, warm natural light.' },
  { id: 'p-0-21', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Partner Handover Ritual', instruction: 'When handing the baby to your partner, say \'I love you, I\'m passing you to [name]\', every time, the same calm words. This is for the baby, not each other.', why: 'Consistent transition words help babies anticipate handovers without anxiety, building security with multiple caregivers.', imageDescription: 'Two parents doing a gentle handover of newborn, both smiling, warm kitchen light, relaxed home setting.' },
  { id: 'p-0-22', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Read Your Emotions', instruction: 'When you\'re having a hard moment, instead of masking it, say calmly to your baby: \'Mama\'s feeling a little tired right now. We\'re okay.\' Then take a breath.', why: 'Honest, calm emotional narration teaches your baby that feelings exist and can be handled, the root of emotional intelligence.', imageDescription: 'Parent holding newborn with a tired but calm expression, soft honest moment, natural window light.' },
  { id: 'p-0-23', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Settling Hold', instruction: 'When your baby is fussy, try holding them face-down on your forearm with your hand supporting their chest. Sway gently. This position is often magically soothing.', why: 'The pressure on their tummy and the motion together activate calming reflexes that help them self-regulate.', imageDescription: 'Parent holding fussy newborn in a face-down settling hold, standing in a living room, warm light, focused expression.' },
  { id: 'p-0-24', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Wake-Up Whispering', instruction: 'When you hear your baby stirring but not yet crying, go in and whisper softly: \'I\'m here. Good morning.\' Let them fully wake to your voice before you pick them up.', why: 'Responding before they cry teaches your baby that you\'re reliably present, this is how secure attachment is built.', imageDescription: 'Parent leaning over a bassinet whispering to stirring newborn, early morning soft light, peaceful nursery.' },
  { id: 'p-0-25', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Gratitude Hold', instruction: 'Once a day, find 60 seconds to just hold your baby and mentally name one thing you love about them. You don\'t have to say it out loud, but you can.', why: 'Intentional moments of warmth and appreciation shape how you show up for your baby, and they sense the difference.', imageDescription: 'Parent holding newborn with a deeply content expression, sitting by a window, soft natural afternoon light.' },
  { id: 'p-0-26', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Respond to Every Cue', instruction: 'For one hour, respond to every single sound your baby makes, a grunt, a sigh, a stretch, with a warm sound or word back. See how the conversation builds.', why: 'Consistent responsiveness to small cues is the single biggest driver of secure attachment in the first months.', imageDescription: 'Parent in an armchair with newborn in their lap, both awake and \'conversing,\' warm home light.' },
  { id: 'p-0-27', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Family Photo Time', instruction: 'Sit with a few printed photos of family members and slowly show them to your baby. Say each person\'s name: \'This is Grandma. This is Uncle Tom.\'', why: 'Faces are a newborn\'s primary social input, surrounding them with familiar faces builds their emotional social world.', imageDescription: 'Parent holding printed family photos in front of alert newborn, warm light, comfortable home setting.' },
  { id: 'p-0-28', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'The Goodnight Routine', instruction: 'At the same time every evening, dim the lights, lower your voice, and hold your baby through a quiet 5 minutes before putting them down. Same order, every night.', why: 'Consistent pre-sleep rituals teach the nervous system that the day is ending and it\'s safe to let go.', imageDescription: 'Parent dimming a nursery lamp and settling into a rocking chair with swaddled newborn, calm evening light.' },
  { id: 'p-0-29', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Narrate Your Love', instruction: 'While doing something routine, folding laundry, making tea, talk to your baby nearby: \'I\'m making tea because I love you and I need to keep my energy up for you.\'', why: 'Weaving warmth into ordinary moments teaches your baby that love is continuous, not just occasional.', imageDescription: 'Parent making tea in a kitchen, newborn in a nearby bouncy seat, parent talking down to them, warm morning light.' },
  { id: 'p-0-30', category: 'play', ageRangeStart: 0, ageRangeEnd: 8, title: 'Partner Story Time', instruction: 'Have a different family member read to or talk to your baby for 10 minutes each day, other parent, grandparent, sibling. Keep the tone warm and calm.', why: 'Babies benefit from bonding with multiple trusted caregivers early, it builds a wider circle of felt security.', imageDescription: 'Grandparent or partner reading softly to a newborn lying in their lap, warm household light, cozy scene.' },
  { id: 's-8-1', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'First Real Smile', instruction: 'When your baby smiles, smile straight back, big, warm, and immediate. Then wait with an expectant expression to see if they do it again.', why: 'Smiling is your baby\'s first social tool. When you reward it instantly, they learn that communication gets results.', imageDescription: 'Parent beaming at a smiling 3-month-old in their lap, joyful close-up, bright natural indoor light.' },
  { id: 's-8-2', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Track the Red Ball', instruction: 'Hold a bright red ball about 12 inches from your baby\'s face. Once they focus on it, move it in a slow arc from one side to the other, watching their eyes track it.', why: 'Visual tracking is developing rapidly at this age, and following a moving object all the way across is a new challenge.', imageDescription: 'Parent holding a bright red ball in front of an alert 3-month-old, baby\'s eyes following it, soft window light.' },
  { id: 's-8-3', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Conversation Pause', instruction: 'Talk to your baby, then stop and hold your face still and expectant. Count to 10 in your head. See what they do with the silence.', why: 'The pause invites your baby to initiate communication, which is far more valuable than them just receiving it.', imageDescription: 'Parent with expectant expression pausing in conversation with baby lying on a playmat, warm cozy light.' },
  { id: 's-8-4', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Introduce a New Toy', instruction: 'Show your baby something they haven\'t seen before, even just a wooden spoon or a colorful scarf. Hold it within their gaze and let them look for a full minute without moving it.', why: 'Novelty drives attention. When babies stare at something new, the brain is forming its first impression of that object.', imageDescription: 'Parent holding an interesting household object in front of a curious 3-month-old, bright natural light.' },
  { id: 's-8-5', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Hand Watching', instruction: 'Hold your baby on your lap and hold your own hand up in their line of sight. Move your fingers slowly. Watch their eyes follow.', why: 'At around 8 weeks, babies discover their own hands, watching hands move is one of the most captivating early visual experiences.', imageDescription: 'Parent holding their hand up in front of a gazing baby in their lap, soft afternoon light, close-up.' },
  { id: 's-8-6', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Two Sounds, Which Way?', instruction: 'Shake a rattle softly to one side of your baby, then quietly move to the other side and shake again. Watch which direction they turn their head each time.', why: 'Sound localization is a key cognitive-auditory skill at this age, and it\'s developing fast.', imageDescription: 'Parent shaking a soft rattle beside a 2-month-old lying on a mat, baby turning their head, warm light.' },
  { id: 's-8-7', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Describe Your Face', instruction: 'Hold your baby close and slowly point to your nose, mouth, and eyes while saying the words. Move very slowly and pause on each feature.', why: 'Learning that faces have parts and names is an early building block of language and social cognition.', imageDescription: 'Parent pointing to their own nose while a baby in their lap gazes up at them, natural light, warm and calm.' },
  { id: 's-8-8', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Book with Big Faces', instruction: 'Get a board book with large, clear photos of baby faces. Show each page slowly and point to the expression: \'This baby looks happy! See the big smile?\'', why: 'Face processing is a key cognitive task right now, books with realistic baby faces give the brain extra practice.', imageDescription: 'Parent showing a board book with a face photo to a baby lying in their lap, bright natural light.' },
  { id: 's-8-9', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Pattern Recognition', instruction: 'Show your baby a striped card, then swap it for a polka-dot card. Watch whether their gaze shifts, if they look longer at the new one, they noticed the difference.', why: 'Recognizing that two things are different is the earliest form of categorization, foundational cognitive work.', imageDescription: 'Parent holding a striped card then a dotted card in front of an alert baby, close-up, warm clean light.' },
  { id: 's-8-10', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Follow the Scarf', instruction: 'Hold a colorful silk scarf and drift it slowly through the air in front of your baby. Let it float and settle. Move it again. Let them watch without trying to grab it yet.', why: 'Tracking an unpredictably moving object, like floating fabric, is more complex than tracking a straight-line toy.', imageDescription: 'Parent drifting a colorful scarf in front of a fascinated 3-month-old on a play mat, bright airy room.' },
  { id: 's-8-11', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Name the Room', instruction: 'Carry your baby through the room and name each major object slowly: \'This is the sofa. This is the lamp. This is the window.\' Point to each as you say it.', why: 'Pairing pointing with naming introduces the concept that everything has a word, a huge early language insight.', imageDescription: 'Parent carrying baby through a living room, pointing to a lamp, baby looking at it, warm natural light.' },
  { id: 's-8-12', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Tummy Time with Mirror', instruction: 'Place an unbreakable baby-safe mirror flat on the mat in front of your baby during tummy time so they can look at themselves.', why: 'Seeing a face (even their own) during tummy time gives a reason to lift the head, and the mirror adds a cognitive layer.', imageDescription: 'Baby in tummy time position looking at a small mirror propped on a play mat, soft window light.' },
  { id: 's-8-13', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Slow vs Fast', instruction: 'Shake a rattle slowly for 5 seconds, then fast for 5 seconds, then slow again. Watch whether your baby\'s expression or body changes between the two speeds.', why: 'Noticing the difference between slow and fast is an early temporal-auditory concept, rhythm is cognitive.', imageDescription: 'Parent shaking a rattle at different speeds in front of baby in a bouncy seat, bright room, alert baby.' },
  { id: 's-8-14', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Animal Sound Book', instruction: 'Get a book with animal pictures and make the animal sound for each one as you turn the page. Keep it the same sound every time, consistency matters.', why: 'Pairing a picture with a sound builds the first symbolic associations, a photo of a dog means \'woof.\'', imageDescription: 'Parent reading an animal book to baby in their lap, parent\'s mouth open making a sound, warm afternoon light.' },
  { id: 's-8-15', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Watch You Eat', instruction: 'Sit your baby in a bouncy seat facing you during a meal. Eat normally and describe what you\'re tasting: \'This is apple, sweet and a bit tangy!\'', why: 'Watching you eat and hearing you describe it begins to build an understanding of food, useful groundwork for weaning.', imageDescription: 'Parent eating a meal with baby in a bouncy seat watching from nearby, casual home setting, warm light.' },
  { id: 's-8-16', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Anticipation Game', instruction: 'Sing the first line of a familiar song, then pause right before the last word and wait with a big expectant face. As baby gets older, they\'ll start to expect it.', why: 'Anticipating what comes next in a sequence is a major cognitive milestone, games like this teach it in the most joyful way.', imageDescription: 'Parent singing to baby in their lap, pausing with a wide expectant smile, baby\'s face alert and watching.' },
  { id: 's-8-17', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Object in, Object Out', instruction: 'Put a soft toy inside a small basket and lift it out again, saying \'in\' and \'out.\' Do it slowly, three times. Let your baby\'s eyes follow the toy each time.', why: 'In and out are some of the very first spatial concepts a baby\'s brain processes, simple but foundational.', imageDescription: 'Parent demonstrating in-and-out with a small toy and basket in front of a watching baby, warm home light.' },
  { id: 's-8-18', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Watch the Clock', instruction: 'Hold your baby facing a large clock with a moving second hand. Let them watch it tick for a minute. Point to the hand and say \'tick, tick, tick.\'', why: 'Tracking a small, regular movement is more advanced visual work than following a large toy, a good challenge at this age.', imageDescription: 'Parent holding baby facing an analog wall clock, baby\'s eyes on the second hand, soft afternoon light.' },
  { id: 's-8-19', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'New Room, New World', instruction: 'Take your baby to a room they don\'t usually spend time in. Lay them on a blanket and let them look around for 5 minutes. No need to narrate, just let them look.', why: 'Novel environments trigger curiosity and produce a cascade of new neural connections as the brain maps new input.', imageDescription: 'Baby lying on a blanket in an unfamiliar room looking around, natural light, parent nearby but quiet.' },
  { id: 's-8-20', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Copy the Coo', instruction: 'When your baby makes a vowel sound, \'ooh\' or \'aah\', copy it back immediately, then wait. When they repeat it, copy again. Keep the loop going.', why: 'Vocal turn-taking at this age is language rehearsal, baby is learning the structure of conversation.', imageDescription: 'Parent face-to-face with baby in a bouncy seat, both mid-vocalization, warm bright indoor light.' },
  { id: 's-8-21', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Peek Behind Your Hands', instruction: 'Hold your face behind your hands, then open your hands like a curtain revealing your face. Say \'BOO!\' softly. At this age, the reveal itself is the fun part.', why: 'The disappear-reappear game is the earliest form of object permanence play, baby is learning that things continue to exist.', imageDescription: 'Parent playing peek-a-boo with hands in front of baby in a bouncy seat, baby\'s wide eyes, warm light.' },
  { id: 's-8-22', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Hang Something New', instruction: 'Swap out a toy on your baby\'s play gym for something different, a wooden ring, a fabric star, a metallic crinkle tag. Let them look at it during floor time.', why: 'Novelty drives brain activity. Regularly rotating play gym items keeps the environment cognitively stimulating.', imageDescription: 'Baby lying under a play gym with an interesting new item hanging, gazing up with curiosity, soft room light.' },
  { id: 's-8-23', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Wet and Dry', instruction: 'During bath time, let your baby feel a dry towel on one hand and the warm water on the other. Say \'wet\' and \'dry\' as they experience each.', why: 'Comparing contrasting sensations side by side builds the brain\'s ability to categorize physical experiences.', imageDescription: 'Parent holding baby\'s hand in water and then on a dry towel during bath time, warm bathroom light.' },
  { id: 's-8-24', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Watch the Dog or Cat', instruction: 'Hold your baby so they can safely watch a pet moving around. Say the animal\'s name and narrate what it\'s doing: \'The cat is walking... now she\'s sitting down.\'', why: 'Watching an unpredictable, living moving thing is some of the richest visual-cognitive input a baby can get.', imageDescription: 'Parent holding baby who is watching a cat across the room, both calm, warm natural home light.' },
  { id: 's-8-25', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Two Toy Choice', instruction: 'Hold one toy in each hand, both within baby\'s sight, and wait. Watch which one they look at more. Offer the preferred one a bit closer.', why: 'Preferring one thing over another is early decision-making, your baby is already exercising choice.', imageDescription: 'Parent holding two different small toys in front of baby in a bouncy seat, baby\'s eyes choosing one, warm light.' },
  { id: 's-8-26', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Rhyming Time', instruction: 'Pick one simple nursery rhyme, \'Hickory Dickory Dock\' or \'Humpty Dumpty\', and recite it twice a day. After a week, see if your baby reacts when they hear the first line.', why: 'Rhymes build auditory pattern recognition and are the first exposure to the rhythmic structure of language.', imageDescription: 'Parent reciting a rhyme to baby lying on a blanket, expressive face, warm soft indoor light.' },
  { id: 's-8-27', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Watch the Mobile Slowly', instruction: 'Wind up or spin a crib mobile slowly and lie your baby underneath it. Watch whether their eyes track individual pieces or just take in the whole thing.', why: 'At this age, babies begin to track individual moving objects within a broader visual field, a new cognitive step.', imageDescription: 'Baby lying under a slowly spinning crib mobile, eyes wide tracking the pieces, soft nursery morning light.' },
  { id: 's-8-28', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Light and Shadow Play', instruction: 'In a dim room, shine a torch on the wall and move it slowly. Then make simple shadow shapes with your hand, a bird, a dog. Say the name of each shape.', why: 'Understanding that a 2D shadow represents a 3D hand is complex visual thinking, babies find it irresistible.', imageDescription: 'Parent and baby in a dim room watching a hand shadow on the wall from a torch beam, magical atmosphere.' },
  { id: 's-8-29', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Feel the Wind', instruction: 'Take your baby outside on a breezy day and hold them so they can feel the wind on their face and hands for a few minutes. Say \'wind!\' each time a gust comes.', why: 'Invisible things that have a physical effect, like wind, are genuinely puzzling and interesting to a developing brain.', imageDescription: 'Parent holding baby outdoors on a gentle breezy day, baby\'s hair and clothing moving, squinting eyes, natural light.' },
  { id: 's-8-30', category: 'spark', ageRangeStart: 8, ageRangeEnd: 16, title: 'Big Expression, Small Expression', instruction: 'Make an exaggerated surprised face at your baby, wide eyes, open mouth, then slowly relax into a calm expression. Let them see the full transition.', why: 'Reading emotional transitions, not just fixed expressions, is a more advanced social-cognitive skill.', imageDescription: 'Parent making a big exaggerated expression at baby in their lap, then showing calm face, both mid-expression.' },
  { id: 'm-8-1', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Tummy Time Toy Reach', instruction: 'During tummy time, place a colorful toy just a couple of inches beyond your baby\'s reach. Don\'t move it closer, let them strain forward for it.', why: 'Reaching during tummy time builds shoulder and arm strength far more than passive lying does.', imageDescription: 'Baby in tummy time straining toward a small toy just out of reach, focused expression, bright play mat.' },
  { id: 'm-8-2', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Bat the Toy', instruction: 'Suspend a toy on a ribbon above your baby\'s hands during floor time. Watch them swipe at it. Move it slightly if they miss so they succeed every few attempts.', why: 'Intentional arm swiping is a leap from random movement to goal-directed motor control.', imageDescription: 'Baby lying on a play gym, arm raised to bat at a hanging toy, focused expression, soft room light.' },
  { id: 'm-8-3', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Kick the Crinkle Toy', instruction: 'Tie a crinkle toy loosely to baby\'s ankle while they lie on their back. Watch them realize that their kicking makes a sound. Let them figure it out on their own.', why: 'When a movement produces a sound, babies repeat it intentionally, this is voluntary motor control emerging.', imageDescription: 'Baby lying on back with a small crinkle toy tied to their ankle, mid-kick, surprised expression, warm light.' },
  { id: 'm-8-4', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Rolling Prompt', instruction: 'Lie your baby on their back with a toy to one side. Get their attention with the toy, then let them try to twist toward it. Be ready to support but not guide.', why: 'The twisting motivation, wanting a toy, is what drives the first roll attempts. Let their desire do the work.', imageDescription: 'Baby lying on a mat twisting toward a toy to the side, parent\'s hands hovering nearby, bright play mat.' },
  { id: 'm-8-5', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Supported Sitting Try', instruction: 'Hold your baby in a sitting position with your hands supporting their hips (not their trunk). Let their back and belly do some of the balancing work. 30 seconds is enough.', why: 'Even a few seconds of supported upright sitting activates the core muscles needed for independent sitting later.', imageDescription: 'Parent holding baby in a supported sit on a blanket, both smiling, baby slightly wobbly, warm natural light.' },
  { id: 'm-8-6', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Arm Batting Practice', instruction: 'Hold a soft rattle about 8 inches from your baby\'s hand. Gently touch the back of their hand with it to prompt them to swipe. Cheer every hit.', why: 'Intentional arm extension toward a target is the fine motor skill that leads to grasping, it starts with batting.', imageDescription: 'Parent holding a rattle near baby\'s hand, baby\'s arm raised to bat at it, warm natural home light.' },
  { id: 'm-8-7', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Leg Weight Bearing', instruction: 'Hold your baby upright with their feet pressing on your thighs. Let them push and straighten. Don\'t support the knees, let the legs do the work.', why: 'Bearing weight through straight legs builds the bones and muscles that walking will eventually depend on.', imageDescription: 'Baby standing upright on parent\'s thighs, pushing down through feet, both smiling, warm household light.' },
  { id: 'm-8-8', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Assisted Tummy Roll', instruction: 'With baby on their tummy, place one hand on their hip and gently nudge them to roll onto their back. Go very slowly and let them feel every part of the movement.', why: 'Feeling the full arc of a roll, even when guided, lays down the movement pattern the brain will later initiate on its own.', imageDescription: 'Parent assisting a baby\'s roll from tummy to back on a soft mat, hands gentle and steady, bright room light.' },
  { id: 'm-8-9', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Midline Reach', instruction: 'Hold a toy directly above your baby\'s chest, at their midline, while they\'re on their back. See if both hands come up together to reach for it.', why: 'Reaching across the midline begins to link the two brain hemispheres, laying groundwork for coordination.', imageDescription: 'Baby lying on back reaching up with both hands toward a toy held directly above them, bright natural light.' },
  { id: 'm-8-10', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Head Up Tummy Time', instruction: 'During tummy time, get down on your belly directly in front of your baby. Talk or sing to give them a reason to hold their head up as long as possible.', why: 'Holding the head up during tummy time is the first and most important step toward all gross motor milestones.', imageDescription: 'Parent lying face-down on the floor, face-to-face with baby in tummy time, both at eye level, bright mat.' },
  { id: 'm-8-11', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Bounce and Hold', instruction: 'Stand and hold your baby upright, feet on your thighs. Gently bounce up and down in a steady rhythm for 30 seconds, then stop and let them absorb the stillness.', why: 'The contrast between movement and stillness trains the vestibular system to adapt quickly.', imageDescription: 'Parent bouncing baby upright on their thighs, baby with a wide expression of delight, warm natural light.' },
  { id: 'm-8-12', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Reach for Your Face', instruction: 'Hold your baby close and let their hands reach your face. Don\'t pull away, let them touch your nose, cheek, and mouth. Guide their hand if needed.', why: 'Touching your face while you react teaches that hands can interact with the world and that touch means connection.', imageDescription: 'Baby reaching up to touch parent\'s face, parent laughing softly, warm golden light, intimate moment.' },
  { id: 'm-8-13', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Grasp and Hold', instruction: 'Press a small, light toy into your baby\'s palm and wait for them to grip it. Don\'t let go immediately, hold the toy for a second so they feel resistance, then release.', why: 'Deliberate grasping against gentle resistance is the transition from reflex grip to intentional hold.', imageDescription: 'Parent placing a small ring toy in baby\'s palm, baby\'s fingers curling around it, close-up, warm soft light.' },
  { id: 'm-8-14', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Tummy Time Song', instruction: 'Every time you do tummy time, sing the same short song, same tune, same words. Make it just for tummy time. The song becomes a cue that helps baby settle into it.', why: 'Pairing a physical routine with a consistent sensory cue (the song) helps the nervous system prepare and cooperate.', imageDescription: 'Baby in tummy time lifting head, parent singing from nearby on the floor, bright colorful play mat.' },
  { id: 'm-8-15', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Prop Sitting with Bolster', instruction: 'Place a firm rolled towel or nursing pillow in a U-shape and sit your baby inside it, facing outward. Sit in front of them to keep them engaged.', why: 'The bolster provides support while still allowing the trunk to work, a safe way to practice the posture of sitting.', imageDescription: 'Baby propped in a small pillow bolster, looking forward at parent, bright room, alert expression.' },
  { id: 'm-8-16', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Two-Hand Transfer', instruction: 'Put a toy in your baby\'s right hand. See if they move it to their left. If not, try nudging it gently toward the other hand. Don\'t force it, just offer the opportunity.', why: 'Hand-to-hand transfer at this age is an emerging fine motor skill that crosses the brain\'s midline.', imageDescription: 'Baby passing a small toy from one hand to the other, parent watching nearby, bright natural light.' },
  { id: 'm-8-17', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Bath Float', instruction: 'During bath time, support your baby on their back in the water with both hands under them and let their body float for a few seconds. Keep the water shallow and warm.', why: 'The weightless sensation in water activates the vestibular system in a uniquely calming, novel way.', imageDescription: 'Baby floating gently on their back in a shallow baby bath, parent\'s hands visible underneath, warm light.' },
  { id: 'm-8-18', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Reach to the Side', instruction: 'While your baby lies on their back, hold a toy to one side so they have to reach across their body to get it. Then do the other side.', why: 'Lateral reaching builds the asymmetrical muscle patterns that rolling, and later crawling, will depend on.', imageDescription: 'Baby lying on back with one arm stretching toward a toy held to the side, focused, bright room light.' },
  { id: 'm-8-19', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Upright Look Around', instruction: 'Hold your baby upright facing outward for a few minutes and slowly turn in a circle so they can take in a 360-degree view of the room.', why: 'Upright head control against gravity is advancing fast, and novel visual input gives the head a reason to stay up.', imageDescription: 'Parent holding baby facing outward, slowly turning, baby looking around the room, bright window light.' },
  { id: 'm-8-20', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Foot to Foot', instruction: 'Hold your baby on their back and bring their two feet together so the soles are touching. Let them push their feet against each other in a clap.', why: 'Bringing feet together builds midline awareness in the lower body and activates the hip adductor muscles.', imageDescription: 'Baby on their back, parent bringing baby\'s feet together sole-to-sole, close-up, warm natural light.' },
  { id: 'm-8-21', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Tummy Time Treasure Hunt', instruction: 'Place several small, interesting objects in a loose row in front of your baby during tummy time, a foil square, a rattle, a mirror card. Let them look at each.', why: 'Multiple visual targets give baby a reason to move their head side to side, building neck rotation and strength.', imageDescription: 'Baby in tummy time looking at a row of interesting small objects on the mat, lifting head, bright play space.' },
  { id: 'm-8-22', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Chest Press', instruction: 'Lie your baby on their back and hold your hands flat on their chest. Let them push your hands away by straightening their arms and kicking. Be a gentle, moveable resistance.', why: 'Pushing against a surface is a precursor to pushing up during tummy time and crawling.', imageDescription: 'Parent and baby on the floor, baby pushing against parent\'s hands on their chest, playful, bright room.' },
  { id: 'm-8-23', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Slow Sway', instruction: 'Hold your baby upright and sway very slowly from side to side, about one full sway per 2 seconds. Let each sway go a little further than feels necessary.', why: 'Slow, wide lateral movement challenges the vestibular system to recalibrate for each position change.', imageDescription: 'Parent standing and swaying slowly with baby held upright against their chest, calm room, warm light.' },
  { id: 'm-8-24', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Forearm Prop', instruction: 'During tummy time, gently position your baby\'s elbows under their shoulders so they can prop up on their forearms rather than flat on the mat. Help them feel the position.', why: 'The forearm prop position is the gateway to all upper-body strength needed for sitting and crawling.', imageDescription: 'Baby propped on forearms during tummy time, head elevated, focused expression, colorful mat, warm light.' },
  { id: 'm-8-25', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Grip and Release', instruction: 'Put a light toy in your baby\'s hand and, after they\'ve gripped it for a few seconds, gently open their fingers and take it away. Wait to see if they reach for it again.', why: 'The intentional release of a grip, as much as the grip itself, is an important emerging fine motor skill.', imageDescription: 'Parent gently opening baby\'s hand to remove a toy, baby\'s fingers opening, close-up, warm soft light.' },
  { id: 'm-8-26', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Balance Gym', instruction: 'During tummy time, very gently shift your baby\'s weight by lifting one hip slightly, then the other. Do it slowly so they can feel and respond to each shift.', why: 'Weight shifting activates the lateral trunk muscles and begins to teach the body to balance.', imageDescription: 'Parent very gently shifting baby\'s hips during tummy time on a mat, hands steady, bright warm light.' },
  { id: 'm-8-27', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Swing Time', instruction: 'If you have access to a baby swing outdoors, put your baby in and give the gentlest possible push, just enough for a small arc. Watch their face throughout.', why: 'Gentle outdoor swinging provides rich vestibular input and novel visual stimulation in one simple activity.', imageDescription: 'Baby in an outdoor infant swing, gently swaying, parent nearby, dappled sunlight through trees.' },
  { id: 'm-8-28', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Wrist Rattle Kick', instruction: 'Slip a soft wrist rattle onto your baby\'s ankle and lay them on their back. Watch them discover that kicking makes a sound. Don\'t point it out, let them find it.', why: 'Discovering that a body movement produces a sound is the birth of voluntary motor control.', imageDescription: 'Baby on their back with a wrist rattle on their ankle, one leg mid-kick, surprised expression, warm room light.' },
  { id: 'm-8-29', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Supported Stomach Roll', instruction: 'Lay your baby belly-down on a large inflated beach ball and gently tilt it side to side while holding them securely. Keep the motion small and slow.', why: 'Lateral rolling on a curved unstable surface fires the deep trunk stabilizers in a uniquely challenging way.', imageDescription: 'Parent holding baby belly-down on a large inflated ball, gently tilting, bright playroom, alert baby.' },
  { id: 'm-8-30', category: 'move', ageRangeStart: 8, ageRangeEnd: 16, title: 'Diagonal Reach', instruction: 'Hold a toy up and to the right while baby lies on their back. Watch whether they reach with the right hand (easy) or the left (harder). Then try the other side.', why: 'Reaching diagonally across the body begins to link the two brain hemispheres even before full midline crossing.', imageDescription: 'Baby lying on back reaching diagonally toward a toy held to the opposite side, focused, warm natural light.' },
  { id: 'p-8-1', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Social Smile', instruction: 'The first time your baby smiles at you, really smiles at you, write down the date and the time and what you were doing. Then tell them: \'That smile is my favorite thing.\'', why: 'Celebrating milestones builds your own emotional investment and tells your baby that what they do matters to you.', imageDescription: 'Baby beaming a genuine social smile at a parent, close-up of baby\'s face, joyful warm natural light.' },
  { id: 'p-8-2', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Laugh Practice', instruction: 'Make your most ridiculous sound or face, the one that makes your baby absolutely lose it. Do it once, then wait. Then again. Let them lead the pace.', why: 'Shared laughter at this age is one of the most bonding experiences there is, it\'s joy as connection.', imageDescription: 'Parent making a silly face at a giggling 3-month-old in their lap, both mid-laugh, warm bright room.' },
  { id: 'p-8-3', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Same Song Daily', instruction: 'Pick one song that you\'ll sing to your baby every single day, during a nap, a feed, or a walk. Keep it the same song for a month at least.', why: 'Familiarity in music creates an emotional anchor, when baby hears that song, they feel safe and seen.', imageDescription: 'Parent singing to baby in a feeding position, both calm and connected, warm indoor light, peaceful mood.' },
  { id: 'p-8-4', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Discover Their Laugh Trigger', instruction: 'Spend 10 minutes trying different sounds, faces, and movements to figure out what makes your baby laugh. Try a zerbert, a clicking sound, a slow blink.', why: 'Every baby has specific laugh triggers, finding yours deepens your understanding of this particular person.', imageDescription: 'Parent exploring silly sounds with a delighted 3-month-old, both animated, warm bright home light.' },
  { id: 'p-8-5', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Story Before Sleep', instruction: 'Read the same short book every night before sleep in the same calm tone, even if they\'re almost asleep. Let the rhythm of your voice be the lullaby.', why: 'Ritual and consistency are the primary building blocks of trust at this age, a repeated story is a promise kept.', imageDescription: 'Parent reading a small board book in dim lamp light to a sleepy baby, quiet and cozy evening scene.' },
  { id: 'p-8-6', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Mirror Game', instruction: 'When your baby is happy and alert, try to hold a full minute of back-and-forth interaction, you make a face, they respond, you copy, they react. Stay in it.', why: 'Extended face-to-face interaction builds the capacity for sustained social attention, a crucial social skill.', imageDescription: 'Parent and 3-month-old in animated face-to-face play on the floor, both expressive, bright window light.' },
  { id: 'p-8-7', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Body Awareness Song', instruction: 'Make up a simple song where you touch each body part as you sing it, \'little nose, little toes, little ears, here it goes.\' Do it the same way every time.', why: 'A physical-social routine with a consistent song builds body awareness and bonds through rhythm and touch.', imageDescription: 'Parent touching baby\'s nose and toes while singing, baby in their lap, warm natural light, both engaged.' },
  { id: 'p-8-8', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Talk About What You See', instruction: 'During a walk, describe everything you pass in a calm, interested voice, the red letter box, the brown dog, the sound of the wind. Your baby is listening to all of it.', why: 'The richer and more varied your commentary, the more your baby\'s brain connects your voice with the living world.', imageDescription: 'Parent on a walk with baby in a carrier, talking animatedly, pointing at something outside, bright day.' },
  { id: 'p-8-9', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Post-Feed Cuddle', instruction: 'After every feed, build in a 2-minute quiet cuddle before putting baby down. Hold them upright or on your chest and breathe slowly. No screens, no rushing.', why: 'Post-feed calm creates a regular window of pure connection, separate from the functional business of feeding.', imageDescription: 'Parent quietly holding a drowsy fed baby against their chest, soft afternoon light, contented expression.' },
  { id: 'p-8-10', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Name the Feeling', instruction: 'When your baby seems frustrated, excited, or curious, name it: \'You look a bit frustrated right now. That toy is tricky, isn\'t it?\' Keep your tone warm not worried.', why: 'Naming emotions, even before baby understands the words, is the foundation of emotional intelligence.', imageDescription: 'Parent speaking warmly to a slightly fussy baby in a bouncy seat, empathetic expression, warm home light.' },
  { id: 'p-8-11', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Introduce Music Genres', instruction: 'Play your baby jazz for a few minutes one day, classical the next, then folk or soul. Watch how they respond differently to each.', why: 'Music is emotional data, and your baby\'s varied reactions to different styles are a window into their personality.', imageDescription: 'Parent sitting with baby, playing different music from a small speaker nearby, both listening, warm home light.' },
  { id: 'p-8-12', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Morning Stretch Together', instruction: 'When you wake up in the morning, stretch your own arms above your head and legs out long, then do the same gently with your baby. Say \'good morning!\' as you go.', why: 'Shared physical rituals at the start of the day build routine and the sense that you begin the day together.', imageDescription: 'Parent and baby doing morning stretches together on a bed, both arms up, bright morning window light.' },
  { id: 'p-8-13', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Carry and Describe', instruction: 'Wear your baby in a carrier for at least one 20-minute period each day and narrate your activity: \'Now I\'m making coffee... now I\'m opening the post...\'', why: 'Babywearing keeps baby physically close and involved in your world, a form of bonding that requires no dedicated time.', imageDescription: 'Parent wearing baby in a carrier while doing something in the kitchen, talking down to baby, warm light.' },
  { id: 'p-8-14', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Pause Response', instruction: 'The next time your baby is crying, pause before you respond, take one breath, then go in with a completely calm voice: \'I hear you. I\'m right here.\'', why: 'Responding to distress with calm (not panic) teaches your baby that feelings are manageable, the core of emotional security.', imageDescription: 'Parent responding calmly to a crying baby in a crib, face composed and warm, reaching in, soft nursery light.' },
  { id: 'p-8-15', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Baby\'s First Dance', instruction: 'Put on a song you love and dance with your baby, properly, not just a sway. Dip, spin gently, change your height. Let the music move you both.', why: 'Shared movement to music creates one of the earliest forms of synchronized joy.', imageDescription: 'Parent dancing with baby held to their chest, both mid-motion, bright living room, pure joy on parent\'s face.' },
  { id: 'p-8-16', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Read the Mood', instruction: 'Three times today, pause whatever you\'re doing and just watch your baby for 30 seconds. Notice what state they\'re in, then respond to that, not to what you expected.', why: 'Reading and responding to your baby\'s actual state (not their assumed state) is the core practice of attunement.', imageDescription: 'Parent pausing to quietly observe their baby lying on a play mat, thoughtful expression, warm natural light.' },
  { id: 'p-8-17', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Long Hold', instruction: 'Sit in a comfortable chair and hold your baby for 15 minutes without doing anything else, no phone, no TV. Just be there. Let them set the energy.', why: 'Undivided presence is what attachment is built from. It\'s not about doing anything. It\'s about being fully available.', imageDescription: 'Parent sitting peacefully in a chair holding their baby, no screens, quiet room, warm lamp light.' },
  { id: 'p-8-18', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Bath Together', instruction: 'Try a shared bath, climb in first, then have a partner hand the baby to you. Keep the water warm and hold them safely. Skin-to-skin in water is uniquely soothing.', why: 'The combination of warm water, skin contact, and your heartbeat is one of the most calming possible experiences.', imageDescription: 'Parent in a bath with newborn lying on their chest, both calm and content, soft warm bathroom light.' },
  { id: 'p-8-19', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Describe the World Outside', instruction: 'Hold your baby at a window and describe what you see together: \'There\'s a pigeon on the fence. Now it flew away! And there are some clouds up there.\'', why: 'Sharing your attention, pointing to the same thing and naming it, is the foundation of joint attention.', imageDescription: 'Parent and baby at a window looking out, parent pointing at something outside, warm light, curious baby.' },
  { id: 'p-8-20', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Whisper Secrets', instruction: 'Lean very close to your baby and whisper something sweet, real or made up. \'You are the best thing that happened to me this year.\' Watch their face.', why: 'Proximity, warmth, and the sound of your voice just for them creates an intimate, exclusive bond.', imageDescription: 'Parent whispering very close to baby\'s ear, baby\'s eyes wide and attentive, soft close-up warm light.' },
  { id: 'p-8-21', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Night Feed as Ritual', instruction: 'During night feeds, instead of staying silent (or going on your phone), whisper one thing you appreciate about your baby. Then one thing about yourself. Keep it short.', why: 'Turning night feeds into micro-rituals of warmth transforms exhaustion into something intentional.', imageDescription: 'Parent feeding baby in dim blue nighttime light, leaning close, both in a quiet warm bubble.' },
  { id: 'p-8-22', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Sibling Introduction', instruction: 'If there\'s an older sibling, make regular time for them to \'talk\' to the baby, let them narrate what they\'re doing. Teach them the baby\'s name and cues.', why: 'Multi-caregiver bonds are protective for a baby\'s social-emotional development, siblings count too.', imageDescription: 'Older sibling talking animatedly to baby lying on a blanket, parent nearby, warm family home light.' },
  { id: 'p-8-23', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Morning Inventory', instruction: 'First thing in the morning, hold your baby and do a loving \'check\', \'Are your hands warm? Is your nose okay? How\'s that little tummy?\' like you\'re really checking in.', why: 'This ritual communicates that your baby is fully seen and that their body matters to you, it builds felt security.', imageDescription: 'Parent holding baby in the morning, gently looking over them with warm attention, soft morning bedroom light.' },
  { id: 'p-8-24', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Partner Sing-Along', instruction: 'Try singing a simple song to your baby together with a partner, both of you, simultaneously. It doesn\'t have to be musical. The togetherness is the point.', why: 'Experiencing two loved voices together helps your baby begin to understand family as a unit.', imageDescription: 'Two parents singing together to baby held between them, all three close, warm home light, genuine moment.' },
  { id: 'p-8-25', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'End of Day Thanks', instruction: 'At the end of the day, hold your baby and say three things you noticed about them: \'You looked so curious at the rattle today. You slept really well. You smiled at me.\'', why: 'Specific positive observation shapes how you see your baby, and your baby feels the warmth of being truly noticed.', imageDescription: 'Parent in a rocking chair holding sleepy baby in evening lamp light, warm and reflective mood.' },
  { id: 'p-8-26', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Voice Recording', instruction: 'Record yourself singing or talking to your baby on your phone. Play it back when someone else is caring for baby, your voice will soothe even when you\'re not there.', why: 'Hearing a caregiver\'s voice activates the same calming brain areas as their physical presence.', imageDescription: 'Parent recording themselves on a phone held up while singing to baby in their lap, warm home light.' },
  { id: 'p-8-27', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'The Worry Hold', instruction: 'When you\'re feeling anxious or overwhelmed, pick up your baby and hold them close. Take three slow breaths. Let their weight ground you.', why: 'Using physical closeness to regulate your own emotions models co-regulation and deepens your bond.', imageDescription: 'Parent holding baby close with eyes closed, taking a breath, warm quiet room, genuine human moment.' },
  { id: 'p-8-28', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Share Music You Love', instruction: 'Play your baby three songs from your own playlist, music you actually love, not baby music. Watch their face with each one.', why: 'Sharing music you genuinely love creates authentic connection, your baby senses the difference between music you perform and music you feel.', imageDescription: 'Parent holding baby listening to music from a speaker, parent\'s face lit up by a song they love, warm home light.' },
  { id: 'p-8-29', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'Watch Them With Others', instruction: 'When a trusted person is holding your baby and baby seems content, pause before taking them back. Watch them together for a full minute.', why: 'Joyfully sharing your baby with others deepens the circle of safety around them and releases you from the weight of sole responsibility.', imageDescription: 'Parent watching a grandparent hold and engage with baby, parent\'s face warm and proud, relaxed home setting.' },
  { id: 'p-8-30', category: 'play', ageRangeStart: 8, ageRangeEnd: 16, title: 'One Real Photo a Day', instruction: 'Take one photo every day this week, not posed, just a real moment. At the end of the week, look back through them together with your baby in your lap.', why: 'Daily documentation slows you down enough to truly notice your baby, reviewing it together begins to build shared visual memory.', imageDescription: 'Parent scrolling through photos on a phone with baby in their lap, pointing at pictures, warm afternoon light.' },
  { id: 's-16-1', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Cause and Effect Toy', instruction: 'Give your baby a toy that makes a sound when they hit or squeeze it. Let them figure out the connection on their own, just sit back and watch.', why: 'The moment a baby realizes their action causes a reaction is a cognitive leap, it\'s the birth of intentional thinking.', imageDescription: '5-month-old sitting with support pressing a button toy that lights up, delighted expression, warm room light.' },
  { id: 's-16-2', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Reach Across Midline', instruction: 'While your baby sits supported, hold a toy on one side and wait for them to reach across with the opposite hand. Don\'t swap the toy, make them really reach.', why: 'Crossing the midline connects the two brain hemispheres and is a precursor to reading, writing, and coordination.', imageDescription: 'Baby in supported sit reaching across their body for a toy held to the side, bright natural light.' },
  { id: 's-16-3', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Where Did It Go?', instruction: 'Let your baby watch you slowly put a small toy behind your back. Say \'where did it go?\' with a genuinely puzzled face. Bring it back and say \'there it is!\'', why: 'The earliest stirring of object permanence, the understanding that things exist even when hidden.', imageDescription: 'Parent making a puzzled expression with a toy partially hidden behind their back, baby watching, warm light.' },
  { id: 's-16-4', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Water Play Splash', instruction: 'During bath time, show your baby how to splash by slapping the water with your hand. Let them try. Let them get a bit wet, it\'s the reaction that matters.', why: 'Splashing is cause and effect at its most physical, action, result, sensation, and delight all in one hit.', imageDescription: 'Baby in a baby bath splashing enthusiastically, parent\'s hand nearby, water droplets, bright bathroom light.' },
  { id: 's-16-5', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Paper Crinkle', instruction: 'Hold a piece of crinkle paper or a noisy bag near your baby and crinkle it once. Give them the paper. Let them crinkle it themselves and discover the sound.', why: 'Producing a sound through deliberate hand movement is intentional cause-and-effect learning.', imageDescription: 'Baby sitting with support crumpling a piece of tissue paper, focused, bright warm light, close-up.' },
  { id: 's-16-6', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Name the Color', instruction: 'Each time you hand baby a toy, name its color: \'Here\'s the red ring. Now here\'s the yellow one.\' Do this consistently with the same toys.', why: 'Color words need hundreds of repetitions in context before they click, starting early is the key.', imageDescription: 'Parent handing a bright colored ring to baby, pointing at it, naming color, warm natural indoor light.' },
  { id: 's-16-7', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Drop and Watch', instruction: 'Hold a toy over the edge of the high chair tray and drop it. Say \'down it goes.\' Do it again. Then see if your baby leans to look where it went.', why: 'Looking for where a dropped object lands is one of the first signs of tracking objects in motion, proto-physics.', imageDescription: 'Parent dropping a toy from a high chair tray, baby leaning to look down, curious expression, bright kitchen light.' },
  { id: 's-16-8', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Crinkle Book Exploration', instruction: 'Give your baby a crinkle or fabric book with simple pictures and let them handle it completely, crinkle, mouth, wave, turn. Don\'t guide them.', why: 'Self-directed exploration of an object builds more cognitive understanding than guided play at this age.', imageDescription: '5-month-old holding a crinkle fabric book, exploring it with hands and mouth, bright natural light.' },
  { id: 's-16-9', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'One Thing at a Time', instruction: 'Put a single toy in front of your baby, nothing else in reach, and watch how they explore it: mouth, shake, turn, pass between hands. Time how long they stay with it.', why: 'Sustained attention on a single object is building deep focus, the opposite of the constant novelty we often offer.', imageDescription: 'Baby focused on a single wooden ring toy, mouthing it, bright minimal play space, warm natural light.' },
  { id: 's-16-10', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Mirror and Name', instruction: 'Hold your baby in front of a mirror, point to their reflection, and say their name. Point to yours and say your name. Wait for their reaction.', why: 'Learning that the face in the mirror has a name is a step toward self-recognition, one of the most profound cognitive milestones.', imageDescription: 'Parent and 5-month-old in front of a large mirror, parent pointing at reflections, both looking at the mirror.' },
  { id: 's-16-11', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Two Toy Choose', instruction: 'Hold two very different toys, one familiar, one new, at the same distance and watch which one your baby reaches for first.', why: 'Novelty preference is a sign of healthy cognitive development, the brain is designed to seek out what it hasn\'t yet learned.', imageDescription: 'Parent holding two different toys equidistant from baby, baby\'s arm reaching toward one, bright warm light.' },
  { id: 's-16-12', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Say a Word, Wait', instruction: 'Say a simple word clearly, \'ball,\' \'cat,\' \'up\', and then wait five seconds with an interested face before continuing. Do this once or twice per interaction.', why: 'Pauses after single words train your baby\'s brain to isolate and process individual vocabulary items.', imageDescription: 'Parent looking at baby with a word just said, holding an expectant pause, both face-to-face, warm light.' },
  { id: 's-16-13', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Fill and Pour', instruction: 'Give your baby two stacking cups during bath or play time. Show them putting the small cup inside the big one and taking it back out. Then let them try.', why: 'In/out and big/small are foundational spatial concepts, play like this makes them physical and real.', imageDescription: '5-month-old in a bath with two colorful stacking cups, parent showing how one fits inside the other.' },
  { id: 's-16-14', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Toy on a String', instruction: 'Tie a ribbon to a toy and place the toy just out of reach. Show baby the ribbon end is within reach. Wait to see if they figure out that pulling the ribbon gets the toy.', why: 'Using a tool (the ribbon) to get a goal (the toy) is a significant problem-solving milestone.', imageDescription: 'Baby reaching for a ribbon attached to a distant toy on a mat, concentrated expression, bright warm light.' },
  { id: 's-16-15', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Read a Recipe', instruction: 'Hold your baby in your lap while you cook and read the recipe out loud to them, seriously. Point to the ingredients as you add them.', why: 'Rich contextual language exposure, real words in real situations, is more valuable than simplified baby talk.', imageDescription: 'Parent cooking with baby on their hip, recipe card on counter, talking to baby about what they\'re doing.' },
  { id: 's-16-16', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Texture Touch and Name', instruction: 'Gather 5 household items with different textures, a sponge, a wooden spoon, a silicone mat, a soft cloth, a cold spoon, and let baby touch each. Name the feel.', why: 'Tactile vocabulary (rough, smooth, soft, cold) is learned through hands-on comparison, not definition.', imageDescription: 'Parent guiding baby\'s hand to touch different household objects on a kitchen table, warm light, engaged baby.' },
  { id: 's-16-17', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Watch Me Eat', instruction: 'Sit your baby facing you during a meal. Eat slowly and describe flavors and textures in simple words. Let them watch your face change with each taste.', why: 'Watching others eat and observing oral movement is exactly how babies prepare cognitively and physically for weaning.', imageDescription: 'Parent eating a meal across from baby in a bouncy seat, pointing at food, describing tastes, warm kitchen.' },
  { id: 's-16-18', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Stack and Knock', instruction: 'Stack two soft blocks or stacking cups and let your baby knock them down. Rebuild, knock down. Let the demolition be theirs.', why: 'Baby as the agent of cause-and-effect is more powerful than baby as observer, it builds agency and problem-solving confidence.', imageDescription: 'Baby knocking over a two-block tower, parent cheering, both delighted, bright colorful play space.' },
  { id: 's-16-19', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Blanket Lift', instruction: 'Place a toy on the floor and cover it with a light cloth while baby watches. Say \'where is it?\' and lift the cloth to reveal it. React with joy every time.', why: 'This is the earliest version of object permanence play, baby is starting to understand that hidden doesn\'t mean gone.', imageDescription: 'Parent covering a toy with a small cloth and lifting it to reveal it, baby\'s wide-eyed reaction, warm light.' },
  { id: 's-16-20', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Point at Everything', instruction: 'Hold your baby and spend 5 minutes pointing at objects around the room, naming each one. Use a clear, deliberate point, one finger, straight at the thing.', why: 'Following a pointed finger is a key joint-attention milestone, it\'s also the most natural way to learn new words.', imageDescription: 'Parent pointing clearly at different items in a room while holding baby, both looking in the same direction.' },
  { id: 's-16-21', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Outdoor Curiosity Walk', instruction: 'Take a slow walk and stop at whatever catches your baby\'s eye. Let them stare. Don\'t rush. If they reach toward something safe, let them touch it.', why: 'Following your baby\'s gaze and letting them lead the curiosity teaches them that what they find interesting matters.', imageDescription: 'Parent crouched down with baby on a path, baby reaching toward a leaf or flower on the ground, natural light.' },
  { id: 's-16-22', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Simple Shape Words', instruction: 'When you hand your baby toys, name the shape once: \'Here\'s the round one. Here\'s the cube.\' Don\'t test them, just name consistently.', why: 'Shape vocabulary starts with passive exposure long before a baby can identify shapes on request.', imageDescription: 'Parent handing a round ball and square block to baby in turn, naming them, bright play area.' },
  { id: 's-16-23', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Watch the Bubbles', instruction: 'Blow some soap bubbles in front of your baby and let them track the bubbles floating through the air. Hold one in front of them and let it pop on their hand.', why: 'Bubbles move in 3D space unpredictably, tracking them is complex visual-cognitive work, and they\'re endlessly compelling.', imageDescription: 'Parent blowing bubbles in a garden or living room, baby reaching toward one, delighted expression, soft light.' },
  { id: 's-16-24', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Describe Other People', instruction: 'When you\'re out, point to other people (at a safe distance) and describe what they\'re doing: \'That man is walking his dog. That woman has a red bag.\'', why: 'Narrating observations about other people builds social awareness and language simultaneously.', imageDescription: 'Parent and baby on a park bench, parent pointing at people nearby, baby watching, bright outdoor day.' },
  { id: 's-16-25', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Rolling Ball Watch', instruction: 'Place your baby in a supported sit and roll a ball slowly toward them. Let it bump gently against their leg. Roll it again.', why: 'Tracking a ball that comes toward them is a distinct visual skill from tracking one that moves away, both matter.', imageDescription: 'Parent rolling a soft ball toward a baby in a supported sit, ball mid-roll, bright wooden floor.' },
  { id: 's-16-26', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Which Sound Louder?', instruction: 'Shake two containers, one with a few seeds, one with lots, and let your baby listen to each. Ask \'which one is louder?\' in a warm tone, even if they can\'t answer.', why: 'Comparing acoustic intensity is early quantitative reasoning, more versus less, before numbers exist.', imageDescription: 'Parent shaking two small containers in front of baby, baby listening with head tilted, bright home setting.' },
  { id: 's-16-27', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Name the Body Parts', instruction: 'During diaper changes or bath, touch and name a new body part each time. Stick to the same ones for a week before moving on.', why: 'Consistent repetition is how body-part knowledge is built, babies need many encounters with a word before it sticks.', imageDescription: 'Parent touching baby\'s ear during a diaper change, saying the word, baby looking up, bright clean light.' },
  { id: 's-16-28', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Indoor vs Outdoor Sound', instruction: 'Hold your baby inside by an open door for a minute, listen to indoor sounds. Then step outside for a minute. Ask \'different?\'', why: 'Noticing differences between two environments is active auditory comparison, the brain is sorting and categorizing.', imageDescription: 'Parent and baby at an open front door, one moment inside and one outside, listening expression, natural light.' },
  { id: 's-16-29', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Toy in Both Hands', instruction: 'Give baby a toy in one hand. Wait for them to grasp it. Then offer a second toy for the other hand. See if they can hold both at once.', why: 'Holding two things simultaneously requires divided attention, a real cognitive challenge at this age.', imageDescription: 'Baby holding a small toy in each hand, looking from one to the other, concentrated expression, warm light.' },
  { id: 's-16-30', category: 'spark', ageRangeStart: 16, ageRangeEnd: 24, title: 'Whole and Broken', instruction: 'Show your baby a cracker or piece of fruit whole, then slowly break it in two and show both pieces. Say \'two pieces now!\'', why: 'Understanding that one object can become two is an early division concept, the sensory drama of breaking makes it memorable.', imageDescription: 'Parent snapping a cracker in two in front of a watching baby, baby\'s eyes on the transformation, warm kitchen light.' },
  { id: 'm-16-1', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Sit and Topple', instruction: 'Set your baby in a brief unsupported sit and let them topple gently to the side onto a padded mat. Stay close but let the fall happen, it teaches recovery.', why: 'Controlled falling and recovering teaches the body how to absorb and respond to balance disruption.', imageDescription: 'Baby just beginning to topple sideways from a sit on a padded mat, parent\'s hand close by, bright room.' },
  { id: 'm-16-2', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Back to Front Roll', instruction: 'With your baby on their back, place a toy on one side and help them flip to their tummy by guiding from the hip. Cheer enthusiastically when they make it.', why: 'Rolling from back to front is typically slightly harder than front to back, but once it clicks, mobility explodes.', imageDescription: 'Baby mid-roll from back to front on a colorful mat, parent\'s hand lightly at their hip, bright warm light.' },
  { id: 'm-16-3', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Tummy to Back Roll', instruction: 'During tummy time, place a toy just to one side of baby\'s shoulder. Let them reach for it until the weight shift tips them onto their back.', why: 'Reaching off balance is how most tummy-to-back rolls happen, the toy is the catalyst.', imageDescription: 'Baby mid-roll from tummy to back on a mat, arm extended, toy beside them, parent cheering nearby.' },
  { id: 'm-16-4', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Sit with Toy', instruction: 'Sit your baby between your legs on the floor. Hold a toy at their eye level and slightly forward so they reach for it without leaning back on you.', why: 'Reaching forward while sitting activates the abdominal muscles that independent sitting requires.', imageDescription: 'Baby sitting between parent\'s legs on the floor, reaching for a toy, bright natural light, wooden floor.' },
  { id: 'm-16-5', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Crawling Preview', instruction: 'Place your baby on their tummy with a toy just out of reach. Watch if they push up, pivot, or drag themselves forward. Don\'t help, give them time to problem-solve.', why: 'Pre-crawling army shuffling and pivoting are legitimate developmental steps, not things to skip past.', imageDescription: 'Baby on their tummy starting to army-crawl toward a toy, focused, bright colorful play mat.' },
  { id: 'm-16-6', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Side-Sit Play', instruction: 'Prop your baby into a side-sitting position (legs bent to one side) with their hand on the floor for support. Put toys within reach on the same side.', why: 'Side-sitting builds the asymmetrical hip strength that rolling and transitioning into crawling depend on.', imageDescription: 'Baby in a side-sit position on a mat, one hand on the floor for support, playing with a toy, warm light.' },
  { id: 'm-16-7', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Stand and Bounce', instruction: 'Hold your baby upright in a standing position (you support at the hips) and let them bounce up and down at their own pace. Don\'t do the bouncing, let their legs do it.', why: 'Self-generated bouncing builds leg strength and the sense of control over one\'s own movements.', imageDescription: 'Baby standing upright on parent\'s lap, bouncing with clear delight, parent holding hips, bright warm room.' },
  { id: 'm-16-8', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Tummy Time on Ball', instruction: 'With your baby face-down on a large exercise ball, gently tilt the ball so their head tips slightly lower than their feet. Hold securely. Then level it out.', why: 'Tipping the head below the body activates different vestibular receptors than flat tummy time, it\'s a richer workout.', imageDescription: 'Parent holding baby face-down on an exercise ball, tilting gently, baby\'s hands touching the floor, bright room.' },
  { id: 'm-16-9', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Reach Up High', instruction: 'Hold a toy above your baby\'s head, slightly higher than they can easily reach, and wait. Let them stretch, lean, and work for it.', why: 'Vertical reaching builds the shoulder stability that will later allow them to push up into sitting and crawling.', imageDescription: 'Baby reaching up high for a toy held above them, full arm extension, concentrated face, warm natural light.' },
  { id: 'm-16-10', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Mirror Tummy Time', instruction: 'Lean a baby-safe mirror against the wall and position your baby in tummy time directly in front of it. Let them try to lift toward their own reflection.', why: 'Babies who see themselves in a mirror during tummy time hold their heads up longer and with greater effort.', imageDescription: 'Baby in tummy time in front of a small propped mirror, lifting head toward reflection, bright clean light.' },
  { id: 'm-16-11', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Object Passing', instruction: 'Hold a toy out for your baby to grab, then gently tug it back slightly, not enough to take it, just enough for them to pull harder. Keep it playful.', why: 'Pulling against resistance builds grip strength, arm muscles, and the beginning of game-based motor interaction.', imageDescription: 'Parent and baby having a gentle toy tug game, both engaged and laughing, bright warm light.' },
  { id: 'm-16-12', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Rolling Over Obstacle', instruction: 'Place a small, soft rolled blanket in baby\'s path during floor time. Let them roll or crawl over it without your help.', why: 'Navigating a simple obstacle teaches the body to adapt, the foundation of complex motor problem-solving.', imageDescription: 'Baby rolling over a small rolled blanket on a mat, mid-obstacle, parent watching, bright room light.' },
  { id: 'm-16-13', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Held Stand on Ground', instruction: 'Hold your baby upright with their feet on a firm floor. Support at the hips or armpits, not at the arms. Let them push down through their legs for 30 seconds.', why: 'Brief standing against a real floor with real resistance is more valuable than standing on a soft surface.', imageDescription: 'Parent holding baby upright, baby\'s feet pressing down on a wooden floor, pushing legs straight, warm light.' },
  { id: 'm-16-14', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Pivot on Tummy', instruction: 'During tummy time, place toys in a semicircle around your baby. Watch them push and pivot their body around to reach each one.', why: 'Pivoting is the first proto-crawling movement, the arms and core work together to spin the body.', imageDescription: 'Baby pivoting in a circle during tummy time to reach toys, bright colorful mat, engaged expression.' },
  { id: 'm-16-15', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Kick and Bat Gym', instruction: 'Set up your baby under a play gym with attachments they can reach with both hands and feet. Let them bat and kick freely for 10 minutes.', why: 'Free bilateral gym play at this age builds body schema, the brain\'s map of where each limb is at any moment.', imageDescription: 'Baby under a play gym kicking and batting in all directions, full-body motion, bright room, happy face.' },
  { id: 'm-16-16', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Supported High Sit', instruction: 'Sit your baby on a firm pillow placed on the floor and sit in front of them. Hold a toy at their chest height. Give them two hands free to grab it.', why: 'The elevated instability of a pillow keeps the core active in ways flat-floor sitting doesn\'t.', imageDescription: 'Baby sitting on a small firm cushion on a wooden floor, reaching for a toy, parent nearby, warm light.' },
  { id: 'm-16-17', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Hands and Knees Try', instruction: 'Help your baby find a hands-and-knees position and gently rock them forward and back while holding their hips. Let them feel the crawling weight shift.', why: 'Experiencing the weight transfer of crawling before they can initiate it lays down the movement memory.', imageDescription: 'Baby in hands-and-knees position, parent gently rocking at hips, bright play space, warm afternoon light.' },
  { id: 'm-16-18', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Crinkle Paper Reach', instruction: 'Crinkle a piece of paper above your baby during tummy time until they look up. Hold it just high enough for them to push up fully to reach.', why: 'Sound plus visual target makes this the most motivating possible reason to achieve a full push-up in tummy time.', imageDescription: 'Baby in tummy time pushing fully up toward crinkle paper held above, arms straight, bright room.' },
  { id: 'm-16-19', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Wobble Seat', instruction: 'Sit your baby on your slightly bent knee and slowly, very gently, wobble your knee side to side. Their trunk will work constantly to stay balanced.', why: 'An unpredictably moving surface is the best possible core training equipment for a baby.', imageDescription: 'Baby sitting on a gently wobbling parent\'s knee, engaging core to balance, both smiling, warm home light.' },
  { id: 'm-16-20', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Arm Lift Stretch', instruction: 'Hold baby\'s arms at their sides and raise them slowly above their head, both together. Lower slowly. Repeat 4 times, saying \'up... and down...\'', why: 'Controlled arm overhead movement stretches the chest, builds shoulder mobility, and introduces bilateral coordination.', imageDescription: 'Parent raising baby\'s arms above their head on a changing mat, baby looking up, gentle bright light.' },
  { id: 'm-16-21', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Blanket Pull to Sit', instruction: 'Lay your baby on a firm blanket on the floor. Gently pull the corners of the blanket up so it lifts them into a sitting position. Make it slow and fun.', why: 'The unstable transition of the lifting blanket engages the core differently from a direct pull-to-sit.', imageDescription: 'Parent lifting the corners of a blanket with baby on it, baby rising toward a sit, both laughing, warm light.' },
  { id: 'm-16-22', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Back Float Kick', instruction: 'In the bath, support your baby on their back with both hands. Let their legs kick freely in the water. Count \'kick kick kick\' in a happy rhythm.', why: 'Kicking in water provides gentle resistance that builds leg strength without any impact stress.', imageDescription: 'Baby floating on back in a baby bath, kicking legs, water splashing, parent\'s hands underneath, warm light.' },
  { id: 'm-16-23', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Tummy Time on Sibling', instruction: 'If there\'s an older sibling, let them lie face-up while the baby does tummy time on their tummy. The sibling can talk or sing to motivate the head lift.', why: 'A live, responsive \'mat\' motivates more effort and makes tummy time joyful rather than effortful.', imageDescription: 'Older sibling lying on their back with baby doing tummy time on their tummy, both enjoying it, warm home light.' },
  { id: 'm-16-24', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Towel Hammock Rock', instruction: 'With another adult, each hold two ends of a large towel with baby lying inside. Sway gently from side to side in a slow, wide arc.', why: 'A wide lateral sway in a supported position is one of the most effective vestibular stimulation activities.', imageDescription: 'Two parents holding a towel hammock swaying a laughing baby between them, warm indoor light, joy.' },
  { id: 'm-16-25', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Lean and Recover', instruction: 'While baby sits supported between your legs, gently lean them 15 degrees to one side. Release your support and let them pull themselves back to center.', why: 'The active recovery to center is exactly the core-balance movement that sitting independently requires.', imageDescription: 'Parent gently leaning baby to one side, baby self-correcting back to center on a mat, warm room light.' },
  { id: 'm-16-26', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'First Army Crawl', instruction: 'Place a toy a body-length away during tummy time and wait. Some babies begin to drag or pivot toward it at this age. Give them as long as they need.', why: 'The first intentional movement toward a goal, even a tiny drag forward, is a genuine gross motor breakthrough.', imageDescription: 'Baby beginning to army-crawl toward a toy on a mat, arms pulling, belly down, determined, bright colorful mat.' },
  { id: 'm-16-27', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Roller Tummy Time', instruction: 'Place a firm foam roller under your baby\'s tummy during tummy time so their hands and feet are slightly off the ground. Stay close and let them work.', why: 'Tummy time over a roller removes floor support, forcing the core and shoulders to engage at a significantly higher level.', imageDescription: 'Baby doing tummy time balanced over a foam roller, hands and feet in air, working hard, bright clean space.' },
  { id: 'm-16-28', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Suspended Ball Bat', instruction: 'Hang a soft ball from a string at exactly hand height while baby lies on their back. Wait for them to bat it. Each time they do, gently return it and wait again.', why: 'Repeating an intentional arm movement with an immediate reward strengthens the motor learning loop dramatically.', imageDescription: 'Baby lying on back batting at a hanging soft ball, arm extended mid-swing, bright play gym, focused expression.' },
  { id: 'm-16-29', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Bounce on the Knees', instruction: 'Sit your baby upright on your knees facing you and bounce gently up and down. Let them feel the rhythm and start to anticipate the next bounce.', why: 'Rhythmic weight-bearing through the legs with a predictable pattern builds leg strength and the concept of timing.', imageDescription: 'Baby sitting on parent\'s knees bouncing, both face-to-face, baby mid-bounce with delight, warm room light.' },
  { id: 'm-16-30', category: 'move', ageRangeStart: 16, ageRangeEnd: 24, title: 'Tummy Time with Music', instruction: 'Put on an upbeat song and get down on the floor for tummy time together. Move your own head and body to the beat while facing baby at their level.', why: 'A moving, musical, face-level companion makes tummy time far more engaging, and babies lift their heads higher and longer as a result.', imageDescription: 'Parent and baby both doing tummy time face-to-face on a mat, parent moving to music, both smiling, bright room.' },
  { id: 'p-16-1', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'First Giggle Chase', instruction: 'Once you\'ve found what makes your baby giggle, a sound, a face, a gentle blow on their tummy, do it once, pause, then do it again. Drag out the pause each time.', why: 'Laughter as a shared call-and-response experience is pure bonding, and the anticipation teaches social timing.', imageDescription: 'Parent and baby in a giggling face-to-face moment on a blanket, both in full joy, bright warm room light.' },
  { id: 'p-16-2', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Watch Me Cook', instruction: 'Put your baby in a bouncy seat or high chair facing you while you cook and keep up a warm running commentary on every single thing you do.', why: 'Being included in real daily life, not just dedicated play time, builds a sense of belonging and security.', imageDescription: 'Baby in a bouncy seat in the kitchen watching parent cook, parent looking back and talking, warm kitchen light.' },
  { id: 'p-16-3', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Their Favorite Song', instruction: 'By now you\'ll have noticed which song gets the biggest reaction. Make it \'your song.\' Sing it at the same times each day. Let it mean something.', why: 'A designated song creates a shorthand for connection, your baby will begin to associate it with you and safety.', imageDescription: 'Parent singing their baby\'s favorite song, baby mid-bounce of delight, warm home light, both in the moment.' },
  { id: 'p-16-4', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Blanket Cocoon', instruction: 'Wrap yourselves together in a large blanket, you and your baby, and sit quietly for a few minutes. Let the warmth and closeness be enough.', why: 'Physical containment, being held and enclosed, is deeply soothing and bond-building at any age.', imageDescription: 'Parent and baby wrapped in a large knit blanket together on a sofa, warm lamp light, cozy and close.' },
  { id: 'p-16-5', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Gentle Tickle', instruction: 'Try a very light tickle on your baby\'s neck, belly, or feet, one spot at a time. Pause before each and watch the anticipation build.', why: 'The anticipation of a tickle is almost as joyful as the tickle itself, it teaches your baby to read social cues.', imageDescription: 'Parent gently tickling baby on a blanket, baby mid-giggle and squirm, parent\'s face full of joy, warm light.' },
  { id: 'p-16-6', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Baby-Led Music', instruction: 'Play music and follow your baby\'s energy, if they get excited, mirror the excitement; if they go calm, soften your response. Let them conduct the mood.', why: 'Following your baby\'s lead, rather than always directing, teaches them that their responses shape the world.', imageDescription: 'Parent and baby sitting together listening to music playing from a speaker, parent following baby\'s mood.' },
  { id: 'p-16-7', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Describe Their Personality', instruction: 'Out loud, to a friend, partner, or just to yourself with baby present, describe two things you\'ve noticed about your baby\'s personality this week.', why: 'Seeing your baby as a specific, emerging person (not just a baby) deepens attunement and shapes your interaction style.', imageDescription: 'Parent talking to a partner with baby in lap, gesturing warmly, describing something about the baby, home light.' },
  { id: 'p-16-8', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Settle Ritual', instruction: 'When your baby is overstimulated, develop a consistent settling sequence: dim the lights, hold them facing inward, sway, and hum one low note.', why: 'A consistent de-escalation sequence gives your baby a predictable path out of overwhelm, building emotional safety.', imageDescription: 'Parent holding baby inward in a dim room, swaying gently, baby calming, warm low lamp light.' },
  { id: 'p-16-9', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Read Their Hunger Cues', instruction: 'For one day, try responding to hunger cues before the cry, the rooting, the hand-to-mouth, the fussing. See if feeding early changes the energy of the meal.', why: 'Early cue response builds deep trust, your baby learns that their subtle signals are heard.', imageDescription: 'Parent noticing a pre-cry hungry baby in a bouncy seat, moving immediately to feed, calm kitchen light.' },
  { id: 'p-16-10', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Meet the Family', instruction: 'Make a simple family photo book, print some photos and put them in a small album. Look through it with your baby once a day and name everyone.', why: 'Recognizing multiple familiar faces and names builds a wider network of felt safety.', imageDescription: 'Parent and baby looking at a small photo album together, pointing at photos, warm afternoon light, home setting.' },
  { id: 'p-16-11', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Name Their Strength', instruction: 'Tell your baby one thing you think they\'re getting better at. \'You\'ve really been working on holding your head up. I can see how hard you try.\'', why: 'Specific, process-focused praise (not just \'clever girl\') builds a growth mindset from the very beginning.', imageDescription: 'Parent holding baby and speaking warmly and specifically to them, tender eye contact, bright home light.' },
  { id: 'p-16-12', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Water Bond', instruction: 'Make bath time a tech-free, unrushed 10 minutes every evening. Bring the same calm voice, the same songs, the same sequence. Let it be sacred.', why: 'A daily unhurried sensory ritual is one of the strongest bond-building habits you can build.', imageDescription: 'Parent bathing baby unhurriedly in a warm baby bath, soft lighting, both relaxed, peaceful evening mood.' },
  { id: 'p-16-13', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Belly Laughs Together', instruction: 'Make your baby laugh as hard as you can for 2 full minutes, zerberries, funny noises, silly faces. Let yourself fully laugh too.', why: 'Shared physical laughter releases bonding hormones in both of you simultaneously, it\'s biology.', imageDescription: 'Parent and baby in a full laughing moment on a blanket, both losing it together, warm bright home light.' },
  { id: 'p-16-14', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Outdoor Pause', instruction: 'Take your baby outside for 10 minutes and sit together quietly without any agenda. Just look and listen.', why: 'Shared stillness is underrated as a bonding experience, not all connection requires activity.', imageDescription: 'Parent sitting on a porch or in a garden with baby in their lap, both looking at the world, golden light.' },
  { id: 'p-16-15', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Narrate Their Interests', instruction: 'When you notice your baby focused on something, a shadow, a toy, your face, describe it: \'You really love that blue thing, don\'t you? What do you think it is?\'', why: 'Following and naming your baby\'s interest tells them that what captures their attention is worth attention.', imageDescription: 'Parent and baby both focused on the same thing, a shadow on the wall, parent describing it, warm light.' },
  { id: 'p-16-16', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Grandparent Video Call', instruction: 'Set up a video call with a grandparent or close relative specifically for baby. Hold baby facing the screen and let the other person sing or talk directly to them.', why: 'Multiple trusted voices and faces in your baby\'s world builds a wider sense of social safety.', imageDescription: 'Parent holding baby facing a tablet screen, grandparent visible on screen, baby watching, warm home light.' },
  { id: 'p-16-17', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Post-Nap Greeting', instruction: 'When your baby wakes from a nap, go in before they escalate to crying and greet them with a big smile and their name: \'Hi [name]! Good sleep?\'', why: 'Being greeted warmly every time they wake builds the expectation that after sleep, comfort reliably comes.', imageDescription: 'Parent leaning over a crib greeting a just-woken baby, both smiling, soft morning light, warm nursery.' },
  { id: 'p-16-18', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Quiet Hum', instruction: 'When your baby is fussy and you\'re running out of ideas, try holding them close and humming one continuous low note. No rhythm, no melody, just a single warm hum.', why: 'A consistent vibrating tone felt through your chest is uniquely regulating for a dysregulated nervous system.', imageDescription: 'Parent holding baby close, eyes closed, humming, baby calming, dim afternoon light, peaceful atmosphere.' },
  { id: 'p-16-19', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Say Their Full Name', instruction: 'Once or twice a day, use your baby\'s full name in a warm, deliberate way: \'Good morning, [Full Name]. I\'m glad you\'re here.\'', why: 'A full name said with warmth begins to build a child\'s sense of identity and the importance of who they are.', imageDescription: 'Parent leaning toward baby with a warm, slightly formal expression saying their full name, gentle home light.' },
  { id: 'p-16-20', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Read the Signs', instruction: 'Spend 10 minutes watching your baby closely. List every cue you notice, turned-away head, rubbing eyes, arched back, excited kick. Name what each one means.', why: 'The more fluently you can read your baby\'s cues, the more attuned and secure your relationship becomes.', imageDescription: 'Parent watching baby intently with a focused, loving expression, baby in a bouncy seat, warm natural light.' },
  { id: 'p-16-21', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Night Comfort Voice', instruction: 'When your baby wakes at night, respond with your voice before your body, call softly from the doorway: \'I\'m here. I\'m coming.\' This helps them begin to settle.', why: 'Learning that your voice reliably precedes your arrival reduces distress and builds anticipatory trust.', imageDescription: 'Parent in a darkened hallway outside a nursery door, calling softly toward a fussing baby, dim night light.' },
  { id: 'p-16-22', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Favorite Smell Moment', instruction: 'After bath, bury your nose in your baby\'s neck or hair and breathe them in for a long moment. Then look at them and smile.', why: 'Your baby\'s smell triggers oxytocin in you, deliberately taking a moment with it deepens your bond.', imageDescription: 'Parent nose-buried in baby\'s neck after bath, baby in a towel, parent\'s face blissful, warm bathroom light.' },
  { id: 'p-16-23', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Anticipation Pause', instruction: 'During a familiar game or song, pause right before the best part and watch your baby\'s face as they wait for it. Let the anticipation build before you deliver.', why: 'The moment your baby shows they know what\'s coming is the moment you know they trust you to follow through.', imageDescription: 'Parent pausing mid-game with baby, both in a moment of gleeful anticipation, warm bright light.' },
  { id: 'p-16-24', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'End of Week Ritual', instruction: 'Pick one thing you do every weekend together, a particular walk, a bath with a special toy, a song you only sing on Sundays. Make it a tradition from now.', why: 'Recurring rituals build a child\'s sense of time, belonging, and the comforting predictability of family life.', imageDescription: 'Parent and baby on a Saturday morning walk, both wrapped up warmly, golden morning light, familiar route.' },
  { id: 'p-16-25', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Read the Grumpy Moment', instruction: 'When your baby is hard to settle, say out loud: \'I think you might be tired. Or maybe a bit overstimulated. Let\'s just be quiet.\' Then do it, no fixing, just being.', why: 'Naming what you think your baby feels, even tentatively, models empathy and gives them a felt sense of being understood.', imageDescription: 'Parent holding a slightly fussy baby calmly, talking quietly, warm low light, unhurried and present expression.' },
  { id: 'p-16-26', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Bath as Sacred Time', instruction: 'Treat bath time this week as a completely tech-free ritual. Same songs, same sequence, same warm unhurried energy every single evening.', why: 'A daily sensory ritual done with total presence becomes one of the strongest bonding anchors of the first year.', imageDescription: 'Parent bathing baby in a warm baby bath, both relaxed and engaged, no phone visible, soft bathroom evening light.' },
  { id: 'p-16-27', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Slow Morning', instruction: 'One morning this week, resist the urge to rush. Let your baby set the pace of getting dressed, feeding, and starting the day. Follow their timeline.', why: 'A morning without rushing communicates that you have time for them, and that they are not a task to complete.', imageDescription: 'Parent and baby in pajamas taking their time over breakfast, no urgency, warm morning window light, peaceful.' },
  { id: 'p-16-28', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Describe What You See', instruction: 'Look at your baby\'s face for a full minute and then describe what you see, out loud: \'Your eyes are very dark today. You have a little crinkle by your nose when you smile.\'', why: 'Being described in loving, specific detail is one of the deepest experiences of being truly seen.', imageDescription: 'Parent gazing at baby\'s face and speaking softly, baby looking back, close-up warm natural light portrait.' },
  { id: 'p-16-29', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'The Big Reaction', instruction: 'When your baby does something new or surprising, react as big as you genuinely feel, eyes wide, gasping, laughing. Don\'t moderate your joy.', why: 'Big authentic reactions tell your baby that what they do has real impact, this is intrinsic motivation being built in real time.', imageDescription: 'Parent reacting with genuine wide-eyed delight to something baby just did, baby watching the reaction, warm light.' },
  { id: 'p-16-30', category: 'play', ageRangeStart: 16, ageRangeEnd: 24, title: 'Tell Someone About Them', instruction: 'Call or message a family member or friend today and tell them one specific thing your baby did or is doing. Make it particular, not general.', why: 'Articulating your baby\'s individuality to others deepens your own attunement, you can\'t share what you haven\'t truly noticed.', imageDescription: 'Parent on the phone looking down at baby with a proud warm expression, describing something, home morning light.' },
  { id: 's-24-1', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Find the Toy', instruction: 'Show your baby a favorite toy, then slowly cover it with a cloth while they watch. Ask \'where did it go?\' and see if they pull the cloth away.', why: 'Searching for a hidden object is the classic object permanence test, when they look, their brain has made a major leap.', imageDescription: 'Parent covering a toy with a small cloth while baby watches, baby reaching for it, bright warm room.' },
  { id: 's-24-2', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Drop and Listen', instruction: 'Hold a toy over the edge of the high chair and drop it. Listen to the sound it makes. Try a soft toy, then a metal spoon, then a plastic cup, different sounds each time.', why: 'Predicting and comparing sounds from dropped objects is early physics and auditory reasoning combined.', imageDescription: 'Baby in a high chair leaning to watch and listen as different toys are dropped, curious expression.' },
  { id: 's-24-3', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Fill the Container', instruction: 'Give your baby a container and a pile of safe objects, soft blocks, large rings, and let them fill it up. Don\'t show them, just let them discover the concept.', why: 'Filling a container is a baby\'s first experience of volume, in/out, and the satisfaction of completing a task.', imageDescription: 'Baby sitting and dropping objects into a small bucket, concentrating, bright natural light, wooden floor.' },
  { id: 's-24-4', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Two-Word Time', instruction: 'Start pairing two words consistently: \'big dog,\' \'red cup,\' \'baby\'s shoe.\' Say them slowly and clearly whenever you see the thing. Two words is plenty.', why: 'Two-word phrases introduce the concept of modification, that one word can describe another, a huge language step.', imageDescription: 'Parent holding up a red cup to a baby and saying the words, baby watching intently, warm kitchen light.' },
  { id: 's-24-5', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Stack It Up', instruction: 'Stack two or three stacking rings or cups in front of your baby. Let them take them off. When they\'re off, stack them again. Never show them how to put them back on yet.', why: 'Taking apart a stack is the first step, true understanding of the sequence comes in both directions.', imageDescription: 'Baby pulling rings off a stacking tower, looking satisfied, parent nearby, bright play area light.' },
  { id: 's-24-6', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Cause-Effect Pop-Up', instruction: 'Get a jack-in-the-box or pop-up toy. Let your baby watch you activate it first. Then guide their hand to the button or lever. Wait for the pop.', why: 'A tool that causes a dramatic, unexpected result teaches babies that mechanisms exist and can be figured out.', imageDescription: 'Baby\'s hand on a pop-up toy lever, parent\'s hand lightly guiding, moment before the surprise, warm light.' },
  { id: 's-24-7', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Which Hand?', instruction: 'Show your baby a small toy. Put both hands behind your back, put the toy in one hand, and hold both fists out. Let them tap one. Open it, win or miss, cheer both.', why: 'Holding an object in mental focus while choosing a hand requires working memory, a real cognitive milestone.', imageDescription: 'Parent holding out two fists to baby, baby tapping one hand, both in suspense, warm home light.' },
  { id: 's-24-8', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Sorting Tray Play', instruction: 'Put a muffin tin in front of your baby with one object in each cup. Let them take them out, hold them, and put them back in whichever cups they choose.', why: 'Sorting is one of the first organizational thinking skills, babies do it physically before they do it cognitively.', imageDescription: 'Baby reaching into a muffin tin full of small objects, taking one out, concentrating, warm kitchen light.' },
  { id: 's-24-9', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Name Familiar Things', instruction: 'Once a day, hold up something your baby knows well, their bottle, their lovey, and say the name clearly. Wait to see if they react to the word before they see it.', why: 'Responding to a word before seeing the object is the first sign that language comprehension is underway.', imageDescription: 'Parent holding up a bottle just named to baby, baby\'s face registering recognition, warm natural light.' },
  { id: 's-24-10', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Nested Cups', instruction: 'Give your baby a set of nesting cups. Let them bang, mouth, throw, and stack them. Don\'t show them the \'right\' way, curiosity is the whole point.', why: 'Free exploration of an open-ended toy builds more neural connections than guided demonstration at this age.', imageDescription: 'Baby surrounded by colorful nesting cups in different stages of exploration, bright play space.' },
  { id: 's-24-11', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Pages and Pictures', instruction: 'Give your baby a sturdy board book and let them turn the pages themselves. Point to one clear object on each page and name it once, simply.', why: 'Self-directed page turning builds fine motor control while the naming builds vocabulary, two skills in one.', imageDescription: 'Baby turning the page of a board book, parent pointing at a picture and naming it, warm afternoon light.' },
  { id: 's-24-12', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Body Part on Command', instruction: 'Ask \'where\'s your nose?\' and wait 5 seconds. If they don\'t respond, gently touch their nose. Stick to nose and tummy for a whole week before adding more.', why: 'Following a verbal instruction with a physical action is a critical language comprehension milestone.', imageDescription: 'Parent asking \'where\'s your nose?\' to a baby, baby reaching for their own face, warm natural light.' },
  { id: 's-24-13', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Wave Bye-Bye', instruction: 'Every single time someone leaves, wave and say \'bye-bye!\' in a consistent, bright tone. Wait for your baby to try to wave. Celebrate any approximation.', why: 'Waving is a gesture that stands for a word, the first truly symbolic communication a baby makes.', imageDescription: 'Parent and baby waving together at someone leaving through a door, both waving, warm home hallway light.' },
  { id: 's-24-14', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Animal Sounds Round', instruction: 'Make animal sounds for three animals in a row, dog, cat, cow, each time you see the picture in a book or a toy. Repeat the same three for a week.', why: 'Consistent sound-picture pairing over many repetitions is how concepts solidify into real understanding.', imageDescription: 'Parent pointing at animals in a book and making their sounds, baby watching with focused delight, warm light.' },
  { id: 's-24-15', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Find the Toy Basket', instruction: 'Show your baby where their toy basket is. Take out a toy, play, then put it back and say \'all done, back in the basket.\' Repeat until they begin to anticipate the return.', why: 'Learning that objects have a place teaches spatial memory and the concept of \'belonging somewhere.\'', imageDescription: 'Parent returning a toy to a small woven basket, baby watching, bright play room, simple tidy space.' },
  { id: 's-24-16', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Hello and Goodbye to Objects', instruction: 'Develop a habit of saying \'hello\' to familiar objects you encounter and \'goodbye\' when you leave a room, \'bye-bye, kitchen!\' Make it warm and a bit silly.', why: 'Applying social words to objects teaches the concept that words have functional uses beyond just labeling.', imageDescription: 'Parent cheerfully waving goodbye to a room with baby in arms, both exiting through a doorway, bright light.' },
  { id: 's-24-17', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Texture Comparison Board', instruction: 'Glue different textures onto cardboard, cotton wool, sandpaper, bubble wrap, velvet, and let your baby touch each section. Name the feel as they explore.', why: 'Hands-on tactile comparison builds sensory categorization, which is an early form of scientific thinking.', imageDescription: 'Baby touching sections of a homemade texture board, fascinated expression, parent nearby, warm natural light.' },
  { id: 's-24-18', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Crinkle Search', instruction: 'Hide a crinkle toy under a small blanket. Crinkle it so they can hear it but not see it. Say \'what\'s that sound?\' and let them figure out where to look.', why: 'Using sound to locate an unseen object is multi-sensory problem-solving, hearing, spatial reasoning, and memory working together.', imageDescription: 'Baby lifting a cloth to find a crinkle toy underneath, triumphant expression, bright room, parent cheering.' },
  { id: 's-24-19', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Simple Commands', instruction: 'Once a day, use one simple command with a gesture: \'give it to me\' (hand out), \'up\' (arms raised), \'no\' (gentle head shake). Be consistent and warm, never stern.', why: 'Understanding words paired with gestures is a crucial pre-language milestone, gesture often leads verbal comprehension.', imageDescription: 'Parent holding out hand and saying \'give it to me\' to a baby holding a toy, baby processing the request.' },
  { id: 's-24-20', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Show Me the Dog', instruction: 'With a book containing animals, ask \'where\'s the dog?\' and wait. Guide their hand to the picture if needed. Praise the point, not just the correct one.', why: 'Pointing to a named picture is a joint attention and vocabulary milestone, one of the most meaningful at this age.', imageDescription: 'Parent asking baby to find an animal in a book, baby\'s finger moving toward the page, warm natural light.' },
  { id: 's-24-21', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Spoon and Bowl', instruction: 'Give your baby a wooden spoon and an empty bowl during play. Let them bang, stir, and experiment. Say \'stir!\' and \'bang!\' as they do each action.', why: 'Exploring the relationship between two objects, a spoon fits in a bowl, is early relational and spatial thinking.', imageDescription: 'Baby banging a wooden spoon in a bowl on a kitchen floor, delighted expression, warm afternoon light.' },
  { id: 's-24-22', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Outside Every Day', instruction: 'Take your baby outside for at least 15 minutes daily, regardless of the weather. Let them see rain, wind, sun, overcast sky, name each one.', why: 'The natural world provides an infinite, ever-changing cognitive environment more complex than any toy.', imageDescription: 'Parent carrying baby outside in light rain, both looking at the sky, warm raincoat, puddles on path.' },
  { id: 's-24-23', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Knock Down the Tower', instruction: 'Build a three-block tower in front of your baby slowly and dramatically. Say \'ready... ready... CRASH!\' and let them knock it down. Rebuild and repeat.', why: 'Anticipating the \'crash,\' waiting for it, and then causing it is a perfect sequence of memory, timing, and agency.', imageDescription: 'Baby knocking down a block tower while parent says crash, both reacting with joy, bright colorful play mat.' },
  { id: 's-24-24', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Naming Routine', instruction: 'Pick one time of day, bath, getting dressed, breakfast, and name every object you use in order, every single day the same way.', why: 'Repeated naming in context is the most efficient vocabulary-building method known, routine makes it automatic.', imageDescription: 'Parent naming bath items to baby during bath time, holding each one up, warm bathroom light.' },
  { id: 's-24-25', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Show and Point', instruction: 'When you see something interesting outside, point to it clearly and name it before baby sees it. Then see if they follow your point to find it.', why: 'Following a pointing finger to find an object is the core of joint attention, one of the strongest language predictors.', imageDescription: 'Parent and baby both looking out a window, parent pointing at something outside, baby turning to look.' },
  { id: 's-24-26', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Self-Feeding Finger Food', instruction: 'At a mealtime, place one soft finger food piece on the tray and wait. Let baby pick it up and bring it to their mouth entirely on their own, even if it takes a while.', why: 'Self-feeding requires hand-eye coordination, grip, aim, and goal-directed thinking all at once.', imageDescription: 'Baby in a high chair focused on picking up a single puff or soft food piece, tongue out, concentrating.' },
  { id: 's-24-27', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Repeat After Me', instruction: 'Make a simple two-syllable sound, \'ba-ba,\' \'ma-ma,\' \'da-da\', and wait for your baby to try to say it back. When they do, do it again.', why: 'Syllable imitation is one of the first steps toward actual words, these exchanges are word rehearsal.', imageDescription: 'Parent and baby face-to-face, both mid-vocalization, parent making a syllable sound, baby trying it back.' },
  { id: 's-24-28', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Toy Chase', instruction: 'Roll or push a toy slowly away from your baby and say \'go get it!\' Let them crawl or reach after it without you bringing it back.', why: 'Pursuing a moving object requires spatial tracking, planning, and physical execution, a full cognitive-motor loop.', imageDescription: 'Baby crawling or reaching after a ball rolling away on a wooden floor, determined expression, bright light.' },
  { id: 's-24-29', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'Story with Actions', instruction: 'Read a simple book and add a physical action for each page: clap when a dog barks, sway when wind blows, jump when something bounces.', why: 'Pairing language with physical action dramatically increases comprehension and memory retention.', imageDescription: 'Parent reading a book to baby, arms moving in a matching action to the story, baby watching with delight.' },
  { id: 's-24-30', category: 'spark', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Peek and Find', instruction: 'Show your baby a toy, then tuck it behind your back. Immediately bring it back out from a different side, left then right. Watch their eyes track which side to expect.', why: 'Tracking an object that disappears and reappears from a different location is a more advanced object permanence challenge.', imageDescription: 'Parent bringing a toy out from a surprising side, baby\'s eyes darting to the unexpected location, warm light.' },
  { id: 'm-24-1', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Independent Sitting', instruction: 'Place your baby in a sitting position with toys within reach but no back support. Stay close to catch them. Let them balance and wobble without assistance.', why: 'The wobble IS the workout, every self-correction builds the core and spinal stability needed for all motor skills ahead.', imageDescription: '7-month-old sitting independently on a play mat, slightly off-balance, parent\'s hand hovering, bright room.' },
  { id: 'm-24-2', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Belly Crawl Chase', instruction: 'Get on the floor and army-crawl alongside your baby, matching their pace. Put a toy a few feet ahead and race toward it.', why: 'Modeling the crawling position teaches babies the pattern, movement learning through imitation is powerful.', imageDescription: 'Parent and baby both on their tummies crawling toward a toy, both mid-movement, bright colorful play mat.' },
  { id: 'm-24-3', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Reach and Fall', instruction: 'While your baby sits, hold a toy slightly out of reach. Let them lean forward to get it and let the lean tip them forward. Be ready to catch but let the fall happen.', why: 'Forward falling is a movement skill, learning to save yourself with your hands is crucial for safe independent mobility.', imageDescription: 'Baby leaning far forward from a sit to reach a toy, hands going to floor, parent spotting, bright warm light.' },
  { id: 'm-24-4', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Crawl Over a Cushion', instruction: 'Place a firm cushion in baby\'s path while they\'re on the floor. Watch them figure out how to get over it, push, roll, or crawl around.', why: 'Navigating an unexpected obstacle requires motor problem-solving, the body and brain working as a team.', imageDescription: 'Baby maneuvering over a large floor cushion, mid-effort, parent watching, bright playroom light.' },
  { id: 'm-24-5', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Pull to Stand at Couch', instruction: 'Stand your baby against a low, firm sofa and place a toy on the seat. Stay close as they push up from their knees to stand and reach.', why: 'The pull-to-stand sequence is one of the most complex gross motor achievements of the first year.', imageDescription: 'Baby pulling up on a sofa edge to standing, hands gripping, legs straightening, parent nearby, warm home light.' },
  { id: 'm-24-6', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Sitting to Crawling', instruction: 'While baby sits, place a toy just out of reach on the floor in front. Watch them transition from sitting to leaning to hands-and-knees or tummy to get it.', why: 'Transitioning between positions is more valuable than staying in any single position, it builds full-body coordination.', imageDescription: 'Baby transitioning from sit to hands and knees to reach a toy, mid-transition, bright play mat, natural light.' },
  { id: 'm-24-7', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Pincer Practice', instruction: 'Place two or three small puffs on a clean tray. Let baby try to pick them up one at a time. Celebrate every successful pincer grip.', why: 'The pincer grasp, thumb and index finger together, is one of the most important fine motor milestones of this age.', imageDescription: 'Baby\'s fingers attempting a pincer grasp on a single puff on a high chair tray, close-up, warm light.' },
  { id: 'm-24-8', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Cruise the Furniture', instruction: 'Stand your baby at one end of a low firm sofa. Put a toy at the other end. Wait and see if they step sideways along the edge to reach it.', why: 'Cruising is direct practice for walking, it builds the lateral weight shift and single-leg balance that walking requires.', imageDescription: 'Baby standing and stepping sideways along a sofa edge, holding on, reaching for a toy, warm home light.' },
  { id: 'm-24-9', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Squat and Stand', instruction: 'While your baby stands holding furniture, place a toy on the floor near their feet. Watch them squat down to pick it up, then push back to standing.', why: 'The squat-and-stand sequence is one of the most important pre-walking leg strength exercises.', imageDescription: 'Baby squatting down from standing to pick up a toy on the floor, parent nearby, bright home setting.' },
  { id: 'm-24-10', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Crawl Through a Tunnel', instruction: 'Make a tunnel using two chairs and a blanket draped over them. Go to the other end and call your baby through. Cheer loudly when they emerge.', why: 'Crawling through a confined space requires spatial awareness, problem-solving, and full-body motor coordination.', imageDescription: 'Baby crawling through a homemade blanket tunnel toward a parent at the other end, mid-crawl, warm home.' },
  { id: 'm-24-11', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Container Pour', instruction: 'During bath time, give baby two cups. Show them how to pour from one into the other, then hand them both cups to try.', why: 'Pouring requires grip, wrist rotation, aim, and cause-and-effect understanding, a complex fine motor task.', imageDescription: 'Baby in a bath trying to pour water between two cups, concentrated, water spilling, parent watching.' },
  { id: 'm-24-12', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Stair First Steps', instruction: 'Allow your baby to climb the first two stairs on hands and knees, with you spotting from directly behind. Go slowly and narrate: \'up we go!\'', why: 'Stair climbing engages core, arms, and legs simultaneously, it\'s the most comprehensive gross motor workout.', imageDescription: 'Baby climbing first two steps on hands and knees, parent directly behind spotting, natural staircase light.' },
  { id: 'm-24-13', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Kicking Through Leaves', instruction: 'Take your baby outside and let their bare or socked feet drag and kick through a pile of dry leaves or grass while you hold them upright.', why: 'Novel textured surfaces under the feet activate proprioceptive receptors and build tactile foot awareness.', imageDescription: 'Parent holding baby upright so feet touch and kick through autumn leaves, both delighted, warm fall light.' },
  { id: 'm-24-14', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Sandbox Dig', instruction: 'Sit your baby in a sandbox or tray of dry oats. Let them dig, pour, and pat the surface freely. No need to guide, their hands will find their way.', why: 'Free manual exploration of a granular surface provides dense tactile-proprioceptive feedback to developing hands.', imageDescription: 'Baby sitting in a small sandbox digging and patting the sand, focused and content, bright outdoor light.' },
  { id: 'm-24-15', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Side-Lying Play', instruction: 'Lay your baby on their side with their top knee propped forward by a small rolled blanket. Put a toy at hip level and let them reach while maintaining the side position.', why: 'Side-lying while reaching builds the rotation strength that connects rolling and crawling.', imageDescription: 'Baby lying on their side on a mat, reaching for a toy, propped in position, parent nearby, bright light.' },
  { id: 'm-24-16', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Blow Raspberries', instruction: 'Get face-to-face with your baby and blow a raspberry. Wait for them to try. When they do, do it again. Go back and forth as long as they\'ll play.', why: 'Raspberry blowing is brilliant oral motor exercise, the lip and tongue control it requires is directly linked to speech.', imageDescription: 'Parent and baby face-to-face both blowing raspberries, both mid-expression, warm playful home light.' },
  { id: 'm-24-17', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Object Throw', instruction: 'Give your baby a soft ball and demonstrate dropping it over the edge of the high chair. Then give it back. Let them drop or throw it themselves.', why: 'Releasing an object intentionally, from a grip to a throw, is a fine motor milestone as much as a gross motor one.', imageDescription: 'Baby in a high chair deliberately dropping a ball, watching it fall, curious expression, bright kitchen.' },
  { id: 'm-24-18', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Hands-Free Sit Play', instruction: 'Set baby in a sit with toys in front. Don\'t let them hold your fingers. Watch them use both hands to play while their body balances independently.', why: 'Playing with two free hands while sitting requires the trunk to stabilize independently, huge core development.', imageDescription: 'Baby sitting independently playing with two toys in both hands, completely self-supported, bright room light.' },
  { id: 'm-24-19', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Rock on All Fours', instruction: 'Help your baby get to hands and knees and rock them gently forward and back while holding their hips. Make a \'whoosh\' sound for each rock.', why: 'Rocking on all fours is the direct precursor to crawling, it teaches the body the weight-shifting rhythm.', imageDescription: 'Baby on all fours, parent gently rocking hips, baby\'s face alert and focused, bright warm play mat.' },
  { id: 'm-24-20', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Scarf Pull', instruction: 'Hold one end of a silk scarf and let your baby grab the other. Gently pull back, not enough to take it, just enough for them to pull with both hands.', why: 'Two-handed pulling builds bilateral grip strength and shoulder stability while being deeply satisfying.', imageDescription: 'Baby and parent in a gentle scarf-tug, both holding the scarf, baby pulling with concentration, warm light.' },
  { id: 'm-24-21', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Clapping Hands', instruction: 'Take baby\'s hands and clap them together softly to music. After a few times, let go and see if they continue clapping on their own.', why: 'Bilateral hand clapping is both a fine and gross motor milestone and a social-motor skill, rhythm and coordination together.', imageDescription: 'Baby beginning to clap their own hands together, delighted expression, parent watching, warm bright light.' },
  { id: 'm-24-22', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Prop Kneeling', instruction: 'Help your baby kneel upright (not sitting back on their heels) against a low surface like a coffee table. Place a toy on the surface to keep them interested.', why: 'Kneeling upright strengthens the hip extensors and prepares the body for standing and walking.', imageDescription: 'Baby kneeling upright against a low table reaching for a toy on the surface, parent spotting, warm home.' },
  { id: 'm-24-23', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Hand Transfer Challenge', instruction: 'Put a toy in baby\'s right hand. Hold your hand out on their left side. See if they transfer the toy across and hand it to you.', why: 'Intentional hand-to-hand transfer across the body\'s midline links both brain hemispheres, a coordination landmark.', imageDescription: 'Baby passing a toy from one hand to a parent\'s outstretched hand on the other side, warm natural light.' },
  { id: 'm-24-24', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Rolling Prone to Sit', instruction: 'From tummy time, show your baby how to push up and rotate onto their bottom by gently guiding their hip around. Very slowly, it\'s a lot to coordinate.', why: 'The prone-to-sit transition is a complex sequence rarely taught, most babies benefit hugely from a gentle guided experience.', imageDescription: 'Parent slowly guiding baby from tummy position onto sitting, mid-transition, colorful mat, warm room light.' },
  { id: 'm-24-25', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Upright Balance Bounce', instruction: 'Hold your baby upright standing on your thighs and slowly raise and lower your knees like a slow teeter-totter. Let them adjust and find their balance each time.', why: 'Controlled balance perturbation, throwing off and recovering balance, trains the whole vestibular-proprioceptive system.', imageDescription: 'Baby standing on parent\'s knees, knees rising and falling slowly, baby adjusting balance, warm bright room.' },
  { id: 'm-24-26', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Crawl to a Sound', instruction: 'Crawl to the other side of the room and make a sound, clapping, calling their name, jingling a key. Let baby crawl toward your voice or sound to find you.', why: 'Goal-directed crawling with an auditory target trains spatial reasoning, motor endurance, and sound localization.', imageDescription: 'Baby crawling purposefully across a room toward a parent who is clapping from the other side, determined.' },
  { id: 'm-24-27', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Tall Kneeling Play', instruction: 'Help your baby kneel upright (hips straight, not sitting back on heels) against a low coffee table with a toy on the surface. Support lightly at the hips.', why: 'Tall kneeling strengthens the hip extensors and glutes that standing and walking directly depend on.', imageDescription: 'Baby kneeling upright against a coffee table reaching for a toy on the surface, parent supporting at hips.' },
  { id: 'm-24-28', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Crawl and Carry', instruction: 'Put a soft toy in your baby\'s hand while they\'re on all fours. See if they can figure out how to crawl while holding something. Some babies tuck it under their chin.', why: 'Crawling while carrying is a dual-task motor challenge that dramatically increases coordination complexity.', imageDescription: 'Baby crawling with a soft toy clutched in one hand, finding a way to manage, bright play mat, parent watching.' },
  { id: 'm-24-29', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Standing from the Floor', instruction: 'Place a toy on a low surface. Sit your baby on the floor in front of it. Watch them figure out how to get from sitting to standing to reach it. Don\'t lift them.', why: 'Self-initiated transitions between positions build far more strength than parent-assisted ones.', imageDescription: 'Baby transitioning from floor sit to pull-to-stand at a low surface to reach a toy, mid-transition, warm light.' },
  { id: 'm-24-30', category: 'move', ageRangeStart: 24, ageRangeEnd: 32, title: 'Ball Drop into Bucket', instruction: 'Hold a wide bucket on the floor and give your baby a large soft ball. See if they drop it in. Make a big \'PLOP!\' sound every time it lands.', why: 'Aiming and releasing an object into a container requires visual-motor integration and deliberate grip release.', imageDescription: 'Baby dropping a ball into a bucket, parent making a sound, baby watching the ball land, bright warm kitchen.' },
  { id: 'p-24-1', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Pointing Game', instruction: 'When your baby points at something, follow their point immediately and name what they\'re pointing at. Don\'t redirect, honor the point every single time.', why: 'When you respond to their pointing, you teach your baby that what they notice matters to you, the deepest form of validation.', imageDescription: 'Baby pointing at something in the distance, parent turning to look and naming it, warm outdoor light.' },
  { id: 'p-24-2', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Separation Hello Ritual', instruction: 'Every time you leave your baby, say the same warm phrase: \'I\'m going now, I\'ll be back.\' Every time you return, say \'I\'m back, just like I said!\'', why: 'Consistent separation-and-return language teaches that goodbyes are temporary, the foundation of secure attachment.', imageDescription: 'Parent crouching to baby\'s level at a door, saying goodbye with a warm confident expression, bright hallway.' },
  { id: 'p-24-3', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Copy Their Move', instruction: 'Whatever your baby does, bang the table, wave an arm, bang two toys, copy it. Then wait and see if they do something new for you to copy.', why: 'When you follow your baby\'s lead, you communicate: \'What you do is interesting and worth repeating.\'', imageDescription: 'Baby and parent both banging the table with their hands, both laughing, warm kitchen light, playful mood.' },
  { id: 'p-24-4', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Feeding Closeness', instruction: 'Whether you\'re nursing, bottle feeding, or starting solids, put the phone away for the entire feed. Make eye contact, talk, and notice everything your baby does.', why: 'Undivided attention during feeding, the most frequent shared activity, compounds bonding dramatically over time.', imageDescription: 'Parent fully present during a bottle feed with baby, no phone visible, both looking at each other, warm light.' },
  { id: 'p-24-5', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Name the Experience', instruction: 'When something big happens, a loud noise, a fall, an exciting dog, say: \'That was loud! That surprised you.\' Name the experience, then hold the feeling.', why: 'Naming experiences as they happen teaches your baby that emotions can be expressed and that you understand theirs.', imageDescription: 'Parent picking up baby after a small fright, speaking calmly and warmly, naming what happened, soft home light.' },
  { id: 'p-24-6', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Comfort Protocol', instruction: 'When your baby is distressed, develop a consistent sequence: pick up, hold close, make eye contact, say their name, describe what happened. Same order every time.', why: 'A predictable comfort sequence reduces recovery time from distress and builds deep felt security over repetition.', imageDescription: 'Parent picking up a crying baby, making eye contact, speaking calmly, warm room, steady confident expression.' },
  { id: 'p-24-7', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Celebrate the Small Things', instruction: 'When your baby does anything new, however small, make a specific fuss: \'You just turned that page all by yourself! Did you feel that?\'', why: 'Specific celebration of effort and achievement (not just cuteness) builds the early architecture of intrinsic motivation.', imageDescription: 'Parent clapping and celebrating as baby completes a small self-directed task, baby\'s face lit up, warm room.' },
  { id: 'p-24-8', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'First Food Memory', instruction: 'At your baby\'s first taste of solid food, be fully present, no phone. Watch their face. Describe the flavor to them: \'That\'s sweet potato. A bit sweet, a bit earthy.\'', why: 'Being truly present at milestones creates shared memories that deepen your bond and your baby\'s sense of occasion.', imageDescription: 'Parent offering baby their first spoonful of food, both faces in the moment, high chair, warm kitchen light.' },
  { id: 'p-24-9', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Learn Their Signals', instruction: 'Write down (or voice note) three new signals you\'ve noticed from your baby this week, things they do that mean something specific. Share them with anyone who cares for them.', why: 'The more fluently you understand your baby\'s language, the more secure and seen they feel.', imageDescription: 'Parent writing in a small notebook with baby nearby on the floor, thoughtful expression, warm home light.' },
  { id: 'p-24-10', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Saying Sorry', instruction: 'If you raise your voice, lose patience, or have a hard moment, come back to your baby and say: \'I got a bit frustrated. I\'m okay now. You\'re okay.\'', why: 'Repair after a rupture, returning warmly after a hard moment, is actually more important than avoiding hard moments.', imageDescription: 'Parent kneeling at baby\'s level with a calm, warm expression after a hard moment, reaching toward baby.' },
  { id: 'p-24-11', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Night Feed Presence', instruction: 'At one night feed this week, put on a dim lamp instead of your phone screen. Look at your baby instead of something else. Just be there with them.', why: 'Night feeds are intimacy in the dark, presence in those moments builds bonds that daylight interactions can\'t.', imageDescription: 'Parent feeding baby by the soft glow of a small dim lamp at night, both in a quiet bubble, blue-warm light.' },
  { id: 'p-24-12', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Describe Their Curiosity', instruction: 'When your baby stops to study something intently, a texture, a shadow, a face, say: \'You noticed that, didn\'t you. You\'re so curious about the world.\'', why: 'Naming curiosity as a trait teaches your baby to identify with it, curiosity becomes part of how they see themselves.', imageDescription: 'Baby studying something intently, parent watching with pride and narrating, warm natural indoor light.' },
  { id: 'p-24-13', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Weekend Adventure', instruction: 'Once a week, go somewhere new with your baby, a market, a different park, a new café. Take your time. Let them lead with their eyes.', why: 'Novel shared experiences create shared memories and the feeling of being explorers together.', imageDescription: 'Parent and baby at a weekend market or new outdoor space, baby looking around with wonder, warm day light.' },
  { id: 'p-24-14', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Long Hug', instruction: 'Once a day, give your baby a full-body hug and hold it for longer than feels necessary, a full 20 seconds. Breathe deeply and let them feel you settle.', why: 'Extended physical holding communicates safety and love in a language the nervous system understands directly.', imageDescription: 'Parent holding baby in a deep full-body hug, eyes closed, baby settled, warm afternoon light.' },
  { id: 'p-24-15', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Before Bed Recap', instruction: 'Before the final feed or sleep, hold your baby and list three specific things from the day: \'We went to the park, you had sweet potato, you laughed at the dog.\'', why: 'Daily narration of shared experiences builds episodic memory and the sense of a continuous shared story.', imageDescription: 'Parent holding baby in dim evening light, speaking softly and recounting the day, cozy warm bedroom.' },
  { id: 'p-24-16', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Watch Them Play', instruction: 'For 10 minutes, do nothing but watch your baby play. No redirecting, no interfering. Just observe with genuine interest.', why: 'The experience of being watched with interested, non-judgmental attention is profoundly validating, at any age.', imageDescription: 'Parent sitting quietly nearby watching baby play independently on a mat, warm natural light, content expression.' },
  { id: 'p-24-17', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Letter to Baby', instruction: 'Write your baby a short letter, a paragraph or two, about who they are right now and what you love about them. Date it. Keep it for them.', why: 'The act of articulating your love specifically deepens your attunement, and it becomes a precious gift.', imageDescription: 'Parent writing a handwritten letter at a kitchen table with baby nearby, warm light, thoughtful expression.' },
  { id: 'p-24-18', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Photo of the Week', instruction: 'Take one photo this week that isn\'t staged, just something real and unremarkable that happened. Print it and put it somewhere you can see it.', why: 'Noticing and preserving ordinary moments of connection builds a richer sense of your shared life.', imageDescription: 'A candid, real, unposed photo of a parent and 7-month-old mid-moment, warm natural light, genuine.' },
  { id: 'p-24-19', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Grandparent Story', instruction: 'Ask a grandparent or older family member to tell your baby a story, it can be anything, even something from their own childhood. Let your baby watch their face.', why: 'Exposure to the voices, faces, and stories of extended family builds a wider sense of belonging and identity.', imageDescription: 'Grandparent telling a story to a baby in their lap, animated face, baby watching, warm family home light.' },
  { id: 'p-24-20', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Hold Without Fixing', instruction: 'When your baby is fussy and you don\'t know why, try just holding them and staying calm, no problem-solving, no pat-down, no pacing. Just be there.', why: 'Sometimes the most bonding thing is simply not leaving, presence without agenda is its own message.', imageDescription: 'Parent holding a fussy baby calmly, not pacing or fixing, sitting quietly, warm home light, composed face.' },
  { id: 'p-24-21', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Partner Handoff with Words', instruction: 'When handing your baby to another caregiver, narrate: \'You\'re going to [name] now. They love you and they\'ll take good care of you. I\'ll be back.\'', why: 'Narrated handoffs reduce transition anxiety and teach babies that change is safe and predictable.', imageDescription: 'Two parents doing a warm narrated baby handover, both present and smiling, bright home light.' },
  { id: 'p-24-22', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Sing Through the Sad', instruction: 'The next time a routine is hard, a diaper change, getting dressed, sing through it instead of talking. Any tune, any words. Keep singing until you\'re done.', why: 'Singing during hard moments reframes the experience as something shared and musical rather than adversarial.', imageDescription: 'Parent singing while doing a diaper change on a wriggly baby, both mid-interaction, warm bathroom light.' },
  { id: 'p-24-23', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Daily Gratitude Hold', instruction: 'Once a day, hold your baby and name, silently or out loud, one thing about them you\'re grateful for. Make it specific, not general.', why: 'Intentional gratitude for your specific child, practiced daily, deepens attachment and emotional attunement.', imageDescription: 'Parent holding baby quietly in a chair, eyes closed or soft, warm peaceful afternoon light, content.' },
  { id: 'p-24-24', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The New Place Anchor', instruction: 'Whenever you go somewhere new, give your baby a moment to scan the room from the safety of your arms before setting them down. Wait for them to signal readiness.', why: 'Respecting your baby\'s need to survey before engaging teaches them to trust their own nervous system signals.', imageDescription: 'Parent holding baby in a new environment, both scanning the room calmly, baby leaning but secure, warm natural light.' },
  { id: 'p-24-25', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Daily Check-In', instruction: 'Once a day, get down to your baby\'s level, on the floor, and spend five minutes just being present with them, watching what they do without directing anything.', why: 'Being truly at their level, physically and attentionally, is one of the most equalizing and connecting things you can do.', imageDescription: 'Parent sitting cross-legged on the floor at baby\'s level, watching baby play, warm natural light, relaxed.' },
  { id: 'p-24-26', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Transition Warning', instruction: 'Start giving your baby a one-minute warning before any transition: \'In a minute we\'re going to stop and have a bath.\' Say it the same way every time.', why: 'Predictable transitions reduce anxiety and build the sense that you are a reliable, communicative partner.', imageDescription: 'Parent crouching near baby playing, giving a gentle heads-up gesture, warm home light, unhurried expression.' },
  { id: 'p-24-27', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Full Presence Meal', instruction: 'At one meal today, put everything away, phone, TV, any distraction. Give every bite your full, interested attention. Watch how the meal changes.', why: 'A fully present mealtime communicates that eating together is a social and connected act, not a task.', imageDescription: 'Parent spooning food to baby with full eye contact, no distractions, warm kitchen light, both engaged.' },
  { id: 'p-24-28', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Mirror Play Together', instruction: 'Stand in front of a full-length mirror with your baby and spend two minutes exploring, make faces, point to each other, look at your reflection together.', why: 'Shared mirror time builds self-recognition, social mirroring, and a physical sense of the two of you as a unit.', imageDescription: 'Parent and baby both in front of a large mirror, both making expressions, both looking at the reflections.' },
  { id: 'p-24-29', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'Bedtime Touch', instruction: 'As the very last thing before your baby goes to sleep, hold their hand or stroke their cheek for 30 seconds in silence. Make it the same gesture every night.', why: 'A consistent, gentle physical farewell before sleep signals safety and gives the nervous system permission to let go.', imageDescription: 'Parent\'s hand gently stroking a drowsy baby\'s cheek in dim nursery light, both still, soft and peaceful.' },
  { id: 'p-24-30', category: 'play', ageRangeStart: 24, ageRangeEnd: 32, title: 'The Long Look', instruction: 'Find one quiet moment this week where you and your baby just look at each other without doing anything else for a full two minutes. Let the silence be enough.', why: 'Sustained mutual gaze with no agenda is one of the most intimate bonding experiences available, and we rarely allow ourselves it.', imageDescription: 'Parent and baby in a quiet face-to-face gaze, both still, warm golden afternoon light, deeply present moment.' },
  { id: 's-32-1', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Drawer Exploration', instruction: 'Set up a low kitchen drawer with safe items, a wooden spoon, a silicone lid, a small plastic bowl. Let your baby open it and take everything out entirely on their own.', why: 'Self-directed exploration of real household objects builds more neural connections per minute than any toy can.', imageDescription: 'Baby pulling items out of a low kitchen drawer on the floor, delighted, parent nearby but not intervening.' },
  { id: 's-32-2', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Object Function Play', instruction: 'Hand your baby a hairbrush, a cup, and a phone (not real). Watch what they do with each, do they bring the brush to their hair? The cup to their mouth?', why: 'Using objects according to their function is symbolic thinking, one of the biggest cognitive leaps of the first year.', imageDescription: 'Baby bringing a hairbrush toward their own head, concentration on their face, parent watching, warm home light.' },
  { id: 's-32-3', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Follow the Instruction', instruction: 'Ask your baby to \'give me the ball\' while holding your hand out. If they hand it over, celebrate. If not, model it and try again tomorrow.', why: 'Following a spoken instruction with no visual cue is a major language comprehension milestone.', imageDescription: 'Parent holding hand out toward baby asking for a ball, baby processing the request, warm home light.' },
  { id: 's-32-4', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Ball in the Cup', instruction: 'Show your baby a small ball and a cup. Put the ball into the cup and tip it out. Hand both to your baby and wait, no demonstration needed.', why: 'Reproducing a sequence they just watched is imitation learning, how most skills are acquired in the first year.', imageDescription: 'Baby trying to put a ball into a cup on a high chair tray, focused, parent watching, warm kitchen light.' },
  { id: 's-32-5', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Turn-Taking Song', instruction: 'Sing half a line of a familiar song and pause. Wait for your baby to fill in the gap, even with a babble or a squeal. Then sing the next half.', why: 'Anticipated turn-taking in a structured sequence is language comprehension and memory working together.', imageDescription: 'Parent pausing mid-song, expectant face, baby vocalizing in the gap, warm home light, both delighted.' },
  { id: 's-32-6', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Post It Box', instruction: 'Give your baby a small box with a slit cut in the lid and some flat poker chips or large flat lids. Show them one posting motion, then step back.', why: 'Posting objects into a slot is one of the most cognitively and physically complex fine motor tasks at this age.', imageDescription: 'Baby concentrating on posting a flat disc into a box slit, tongue out, focused, bright warm play space.' },
  { id: 's-32-7', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'What\'s in the Bag?', instruction: 'Put three familiar objects in a fabric bag. Let your baby reach in without looking and pull one out. Say the name the moment they pull it out.', why: 'Identifying an object by touch alone, without seeing it, is tactile-cognitive integration.', imageDescription: 'Baby reaching into a fabric drawstring bag, pulling out a toy, surprised expression, warm light.' },
  { id: 's-32-8', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Simple Pretend Play', instruction: 'Pretend to feed baby\'s teddy with a spoon. Say \'yum yum!\' Then hand the spoon to your baby and the teddy bear and see if they copy.', why: 'Pretend play, even a single action like feeding a doll, is an early form of symbolic representation.', imageDescription: 'Parent pretending to feed a teddy bear with a spoon, baby watching intently, then reaching for the spoon.' },
  { id: 's-32-9', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Matching Pairs', instruction: 'Find two identical objects, two blocks the same color, two matching lids, and show them side by side. Say \'same!\' Then add one different one.', why: 'Recognizing \'same\' and \'different\' is categorization, the basis of all future sorting, math, and logic.', imageDescription: 'Parent holding two matching objects side by side in front of baby, pointing, warm natural light.' },
  { id: 's-32-10', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Name the Action', instruction: 'Narrate action words alongside what baby does: \'You\'re pushing. Now you\'re pulling. You\'re sitting. Now you\'re standing.\' Keep the tone interested, not instructional.', why: 'Action words (verbs) are harder to acquire than nouns, hearing them consistently in context speeds their comprehension.', imageDescription: 'Parent narrating while baby does an action on the floor, both engaged, warm natural home light.' },
  { id: 's-32-11', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Which Box?', instruction: 'Use three small boxes. Hide a toy under one while baby watches, then cover all three with cloths. Ask \'which one?\' Let them lift each cloth to find it.', why: 'Remembering which one hid the toy after a brief delay is working memory, this is a real cognitive experiment.', imageDescription: 'Baby lifting cloths from small boxes looking for a hidden toy, focused, parent watching, warm bright room.' },
  { id: 's-32-12', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Categorizing Toys', instruction: 'Give your baby a mixed pile of toys and two bowls. Say \'these go in here\' as you put one kind in each bowl, then hand baby the mixed pile. Watch what they do.', why: 'Even attempting to sort objects by type is a remarkable cognitive act, and most 9-month-olds will try.', imageDescription: 'Baby attempting to sort different toys into two bowls, parent watching, bright warm play space.' },
  { id: 's-32-13', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Bigger vs Smaller', instruction: 'Place a big block and a small block side by side. Pick up the big one and say \'big!\' Pick up the small one and say \'little!\' Do it together ten times across a few days.', why: 'Size words are some of the most useful early adjectives, they need repetition in context to click.', imageDescription: 'Parent holding big and small blocks up to baby, naming them, baby watching, warm bright natural light.' },
  { id: 's-32-14', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Imitate My Sound', instruction: 'Make a new sound, clucking, lip-popping, clicking, and watch to see if your baby tries to copy it. If they make their own version, that counts.', why: 'Sound imitation at this age moves beyond vowel copying into precise oral motor mimicry, complex speech preparation.', imageDescription: 'Parent and baby face-to-face, both making a new sound, lips in motion, warm bright home light.' },
  { id: 's-32-15', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Simple Two-Step', instruction: 'Give your baby two-step instructions with a gesture: \'Get the ball and bring it to me.\' Demonstrate first, then let them try. Celebrate the attempt.', why: 'Processing a two-step instruction is a major working memory and language milestone.', imageDescription: 'Parent giving a two-step instruction to baby with hand gestures, baby processing and beginning to act, warm light.' },
  { id: 's-32-16', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Container Nesting', instruction: 'Give your baby a big bowl and a small bowl. Watch whether they try to put the small inside the big. If not, do it slowly yourself and hand them back.', why: 'Understanding that one object fits inside another is spatial reasoning, a foundational STEM concept.', imageDescription: 'Baby attempting to nest one bowl inside another on the floor, concentrating, parent watching, warm kitchen light.' },
  { id: 's-32-17', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'First Word Watch', instruction: 'Start listening for consistent approximations your baby makes: \'ba\' for bottle, \'da\' for dog. When you hear one, respond to it as though it\'s the real word.', why: 'Treating consistent babbles as real words is the most effective way to encourage those babbles to become first words.', imageDescription: 'Parent responding with delight to a baby\'s babble, leaning in, animated expression, warm home light.' },
  { id: 's-32-18', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Look Where I Point', instruction: 'Point at something across the room and say its name. Watch your baby\'s eyes follow your point. Start with interesting things, a dog, a window, a colorful object.', why: 'Following a point to something across space is joint attention, the single strongest predictor of language development.', imageDescription: 'Parent pointing clearly across a room, baby turning to follow the point, both looking at the same thing.' },
  { id: 's-32-19', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Yes and No', instruction: 'Ask your baby simple questions with an obvious answer, \'Are you hungry? Yes? Or no?\', and nod or shake your head with each option. Keep it warm and playful.', why: 'Learning the meaning of \'yes\' and \'no\' through consistent pairing with nods and shakes is a pre-verbal communication milestone.', imageDescription: 'Parent asking a yes/no question with an exaggerated nod or head shake, baby watching the gesture, warm light.' },
  { id: 's-32-20', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'More vs All Done', instruction: 'At every meal, use \'more\' (hand out) and \'all done\' (palms up/out) consistently with the same gesture and tone. Eventually your baby will start to use them back.', why: '\'More\' and \'all done\' are typically the first two functional signs or words, they represent genuine communication.', imageDescription: 'Parent doing the \'more\' gesture with hands at high chair, baby watching, warm bright kitchen setting.' },
  { id: 's-32-21', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Book Naming Daily', instruction: 'Pick one board book and read it every day for a week. By the end, pause before saying the word on each page and see if your baby looks at the right picture.', why: 'Repeated reading of the same book creates deep word-picture associations faster than reading many different books.', imageDescription: 'Parent and baby reading the same board book together, baby pointing at a page, warm lamp light.' },
  { id: 's-32-22', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Copy the Clap', instruction: 'Clap your hands in a simple rhythm, one-two-three, and wait. See if your baby claps back. Try different rhythms once they\'re copying the first one.', why: 'Copying a rhythmic pattern requires auditory processing, short-term memory, and bilateral motor output simultaneously.', imageDescription: 'Parent clapping a rhythm, baby beginning to clap back, both engaged, warm living room light.' },
  { id: 's-32-23', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Request', instruction: 'Hold a food item and wait for your baby to request it, a reach, a vocalization, a look. Only give it when there\'s a clear communicative signal.', why: 'Waiting for a communicative signal before giving something teaches baby that communication is effective and necessary.', imageDescription: 'Baby reaching and vocalizing toward food parent is holding, parent waiting and responding to the signal.' },
  { id: 's-32-24', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Roll and Retrieve', instruction: 'Roll a ball under a sofa or chair so it\'s just barely visible. Ask \'where did it go?\' Let them crawl around to look for and retrieve it.', why: 'Spatial reasoning, tracking an object that moved out of sight in a predictable direction, is a significant cognitive milestone.', imageDescription: 'Baby crawling around to retrieve a ball that rolled under furniture, parent narrating, bright room light.' },
  { id: 's-32-25', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Scribble Play', instruction: 'Give your baby a large chunky crayon and a big sheet of paper taped to the floor. Let them hold the crayon and make any marks, don\'t guide the hand.', why: 'Voluntary mark-making is an early creative-cognitive act, the discovery that the hand can leave a trace.', imageDescription: 'Baby lying on floor scribbling with a chunky crayon on a large sheet of paper, focused, warm natural light.' },
  { id: 's-32-26', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Watch and Copy Me', instruction: 'Slowly bang two blocks together three times, then hand them to your baby. Don\'t say anything. See if they try to do the same thing.', why: 'Deferred imitation, copying an action without verbal instruction, is a sophisticated cognitive skill.', imageDescription: 'Parent demonstrating banging two blocks together, then handing them to baby who tries to copy, warm light.' },
  { id: 's-32-27', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Put It Back', instruction: 'After your baby takes something out of a container, hold the container near them and say \'back in.\' Wait. If they don\'t put it back, do it yourself and try again.', why: 'Reversing an action, putting back what was taken out, requires understanding sequences in both directions.', imageDescription: 'Baby attempting to put a toy back into a box, parent nearby holding the box, warm bright room.' },
  { id: 's-32-28', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Sticker Peel', instruction: 'Put a large round sticker on the back of your baby\'s hand. Watch them notice it and try to peel it off. Help only if they\'ve been working on it for more than a minute.', why: 'Peeling a sticker requires pincer grip, problem-solving, and the persistence to work through a frustrating fine motor challenge.', imageDescription: 'Baby staring at a sticker on the back of their own hand, trying to peel it off, concentrated, bright warm light.' },
  { id: 's-32-29', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Closed Box', instruction: 'Put a favorite toy inside a shoebox with a lid. Hand the box to your baby without showing what\'s inside. Watch them investigate, shake, turn, eventually open.', why: 'Figuring out that a closed container might have something inside, and how to open it, is a multi-step problem-solving sequence.', imageDescription: 'Baby turning and shaking a closed shoebox, trying to open it, determined expression, warm home light.' },
  { id: 's-32-30', category: 'spark', ageRangeStart: 32, ageRangeEnd: 40, title: 'Point to Show Me', instruction: 'Ask your baby \'can you show me the [dog/light/cup]?\' and wait. Give them 10 full seconds. If they point or look at the right thing, react with genuine delight.', why: 'Pointing to show understanding of a named object is a major receptive vocabulary milestone.', imageDescription: 'Baby pointing toward a named object, parent reacting with delight, bright home setting, warm natural light.' },
  { id: 'm-32-1', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Walking Along the Wall', instruction: 'Stand your baby at the start of a long wall with a toy at the end. Watch them cruise step by step along the wall toward it.', why: 'Long stretches of cruising build sustained single-leg balance, every step is a balance challenge.', imageDescription: 'Baby cruising along a wall toward a toy at the far end, one hand on the wall, stepping, warm home light.' },
  { id: 'm-32-2', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Climbing Chair Challenge', instruction: 'Place a low, stable step stool near a sofa. Let your baby explore climbing onto and off it, always supervised. Don\'t lift them on; let them figure it out.', why: 'Self-initiated climbing builds far more strength and body confidence than parent-assisted climbing.', imageDescription: 'Baby pulling themselves up onto a low step stool, parent spotting closely, bright playroom light.' },
  { id: 'm-32-3', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Push the Box', instruction: 'Place a large cardboard box in front of your baby and encourage them to push it across the floor while walking or cruising behind it.', why: 'Pushing a heavy object while walking builds trunk stability, leg strength, and the forward lean needed for walking.', imageDescription: 'Baby pushing a large cardboard box across a wooden floor, walking behind it, parent cheering, bright room.' },
  { id: 'm-32-4', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Walk Between People', instruction: 'Sit facing a partner, two feet apart. Encourage your baby to walk or step between you, holding each person\'s hands in turn.', why: 'The two-foot gap forces your baby to commit to each step independently, real walking practice.', imageDescription: 'Baby stepping between two seated adults, holding one hand and then letting go, bright warm living room.' },
  { id: 'm-32-5', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Carry the Toy', instruction: 'Give your baby a soft toy to hold while they cruise along furniture. See if they can hold the toy in one hand while using the other hand for balance.', why: 'Carrying something while balancing is a dual-task challenge that dramatically increases motor complexity.', imageDescription: 'Baby cruising furniture while clutching a toy in one hand, concentrating, warm home light.' },
  { id: 'm-32-6', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Roll Down a Ramp', instruction: 'Prop a firm board or book under one end of a book, creating a small ramp. Let your baby roll a ball down it and watch it go. Hand the ball back each time.', why: 'Rolling down a ramp introduces spatial direction, velocity, and cause-effect thinking alongside the motor act of rolling.', imageDescription: 'Baby sending a ball down a small ramp made of a book, watching it roll away, focused, warm room light.' },
  { id: 'm-32-7', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'First Steps Practice', instruction: 'Stand your baby two steps away from you. Hold out your arms and call them. Let them take those two steps to reach you, support them only at the very last second.', why: 'Even one unassisted step is a motor miracle, every small attempt builds the balance and confidence walking requires.', imageDescription: 'Baby taking first wobbly steps toward parent\'s outstretched arms, mid-step, parent beaming, bright home.' },
  { id: 'm-32-8', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Crawl Upstairs Safely', instruction: 'On carpeted stairs with you directly behind, let your baby crawl up as many steps as they want, one at a time. Teach them to turn and come down feet first.', why: 'Stair climbing is gross motor gold: arms, legs, and core all working together in a complex sequence.', imageDescription: 'Baby crawling up carpeted stairs, parent directly behind, focused, bright staircase, safe and supervised.' },
  { id: 'm-32-9', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Drum with Both Hands', instruction: 'Give your baby two sticks or wooden spoons and a drum (or pot). Let them drum with both hands at once. Make it a musical session, play music and join in.', why: 'Bilateral rhythmic drumming builds coordination, bilateral integration, and the motor expression of rhythm.', imageDescription: 'Baby drumming with two sticks on a pot or drum, both arms in motion, parent clapping along, warm light.' },
  { id: 'm-32-10', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Pick Up and Drop In', instruction: 'Put a pile of large pom poms or blocks near a wide container. Let baby pick them up one at a time and drop them in. Then tip the container out and repeat.', why: 'Deliberate pick-up-and-drop-in is a fine motor milestone requiring precise grip, release, and spatial aim.', imageDescription: 'Baby dropping objects one by one into a wide container, focused, satisfied, warm bright play space.' },
  { id: 'm-32-11', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Standing on Grass', instruction: 'Stand your baby barefoot on the grass and hold them lightly at the hips while they get used to the uneven surface. Let them push down and feel the give.', why: 'Uneven natural ground activates far more proprioceptive receptors in the feet than any indoor surface.', imageDescription: 'Baby standing barefoot on grass with parent holding at hips, toes curling, bright outdoor daylight.' },
  { id: 'm-32-12', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Kicking a Ball', instruction: 'Stand your baby and roll a large soft ball slowly toward their feet. Let them figure out what to do with it, most babies will make an accidental or deliberate kick.', why: 'Kicking a ball requires standing balance, weight transfer, and intentional limb movement all at once.', imageDescription: 'Baby standing with a soft ball at their feet, mid-kick or reaching to bat it, parent nearby, outdoor or bright room.' },
  { id: 'm-32-13', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Clapping Rhythm', instruction: 'Clap a simple 3-beat rhythm slowly. Wait for baby to clap back, any clapping counts. Then change the rhythm slightly.', why: 'Rhythmic clapping requires bilateral coordination, timing, and auditory-motor integration.', imageDescription: 'Baby clapping enthusiastically while parent claps a rhythm, both smiling, warm bright home light.' },
  { id: 'm-32-14', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'High Chair Reach Down', instruction: 'Deliberately drop a toy from the high chair tray and ask baby to lean down and get it. Hold them safe at the waist as they reach.', why: 'Leaning and reaching below the support surface while maintaining a seat is a core and balance challenge.', imageDescription: 'Baby in a high chair leaning down to pick up a toy from the floor, parent steadying them, warm kitchen.' },
  { id: 'm-32-15', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Unstable Floor Walk', instruction: 'Lay a couch cushion flat on the floor and let your baby stand and cruise across it while holding your hands.', why: 'Unstable surfaces like foam activate the ankle, knee, and hip stabilizers far more intensively than firm floors.', imageDescription: 'Baby walking across a soft cushion on the floor holding parent\'s hands, wobbling and concentrating, warm room.' },
  { id: 'm-32-16', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Peg and Board', instruction: 'Give your baby a chunky peg board or shape sorter and let them attempt to place pegs in holes. Celebrate any attempt, contact with the hole is a win.', why: 'Fitting a peg into a hole requires grip, aim, and spatial rotation, complex hand-eye coordination.', imageDescription: 'Baby concentrating on fitting a chunky peg into a peg board, tongue out, focused, warm bright play space.' },
  { id: 'm-32-17', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Squeezy Ball', instruction: 'Give your baby a squishy stress ball or a textured rubber ball. Watch them squeeze, roll, and squash it. Challenge them to pass it from hand to hand.', why: 'Squeezing with grip strength and releasing builds the hand musculature that fine motor skills depend on.', imageDescription: 'Baby squeezing a squishy ball with both hands, fascinated by the give, bright play area, warm light.' },
  { id: 'm-32-18', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Walking Downhill', instruction: 'Find a very gentle slope and walk your baby down it holding both their hands. Let them feel the shift forward in their weight.', why: 'Downhill walking is actually more challenging than flat, the forward lean requires active braking and hip control.', imageDescription: 'Parent walking baby down a gentle grassy slope, both hands held, baby concentrated, bright outdoor light.' },
  { id: 'm-32-19', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Throw and Chase', instruction: 'Throw a soft ball a short distance and say \'go get it!\' Let baby crawl or walk after it. Roll it back. Keep the loop going.', why: 'Pursuing a thrown object trains spatial prediction, the brain calculating where a ball will end up before getting there.', imageDescription: 'Baby crawling quickly toward a ball that was thrown, determined expression, bright open floor space.' },
  { id: 'm-32-20', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Tower Build', instruction: 'Place two blocks in front of your baby and put one on top of the other slowly. Hand the third block to your baby. Wait to see if they place it on top.', why: 'Intentional block stacking requires grip precision, spatial aim, and fine motor control, a major fine motor milestone.', imageDescription: 'Baby carefully placing a block on a small tower, focused, parent nearby but not helping, warm bright room.' },
  { id: 'm-32-21', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Reaching to Standing', instruction: 'Place a toy on a low table just above the height where your baby can reach it while kneeling. Let them figure out they need to stand to get it.', why: 'Self-motivated pull-to-stand, with a goal driving the effort, builds strength far faster than assisted standing.', imageDescription: 'Baby pulling themselves to standing at a low table to reach a toy on the surface, parent spotting, warm home.' },
  { id: 'm-32-22', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Sensory Bin Dig', instruction: 'Fill a shallow bin with dry pasta or cooked, cooled spaghetti. Let baby sit in or beside it and dig, scoop, and explore with both hands.', why: 'Bilateral manual exploration of a loose medium builds fine motor strength, tactile processing, and hand independence.', imageDescription: 'Baby digging both hands into a bin of dry pasta, fascinated expression, parent nearby, bright kitchen light.' },
  { id: 'm-32-23', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Step Over the Line', instruction: 'Put a strip of tape on the floor and show your baby how to step over it while walking, holding your hand. Go back and forth across the line several times.', why: 'Stepping over a low obstacle requires deliberate hip and knee lift, a building block for navigating the real world.', imageDescription: 'Baby stepping over a tape line on the floor holding parent\'s hand, lifting foot deliberately, warm home light.' },
  { id: 'm-32-24', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Walking on a Cushion', instruction: 'Lay a large floor cushion flat and hold your baby\'s hands as they walk across it. The unstable surface will make every step an active balance challenge.', why: 'Unstable surfaces activate ankle, knee, and hip stabilizers far more intensively than firm floors, rich balance training.', imageDescription: 'Baby walking across a large soft floor cushion holding parent\'s hands, wobbling and adjusting, bright room.' },
  { id: 'm-32-25', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Object Transfer Walk', instruction: 'Stand at one side of the room with a basket. Ask your baby to pick up a toy on the floor and bring it to the basket. Model it once, then let them try.', why: 'Walking while carrying an object and placing it in a container chains three motor tasks into one meaningful sequence.', imageDescription: 'Baby toddling or cruising toward a basket carrying a toy, focused, parent cheering, bright open room.' },
  { id: 'm-32-26', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Kick the Balloon', instruction: 'Blow up a balloon and place it near your standing baby\'s feet. Say \'kick it!\' Watch them figure out how to balance on one leg long enough to make contact.', why: 'Kicking a balloon requires single-leg balance, weight transfer, and the coordination of a deliberate leg swing.', imageDescription: 'Baby kicking a balloon with one foot, other foot on the floor, parent nearby, bright open room light.' },
  { id: 'm-32-27', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'First Tool Use', instruction: 'Show your baby how to use a spoon to bang a drum (or pot). Hand them the spoon and the drum. Step back.', why: 'Using one object to act on another is the earliest definition of tool use, a significant cognitive-motor milestone.', imageDescription: 'Baby banging a pot with a spoon with focus and satisfaction, parent watching, warm kitchen setting.' },
  { id: 'm-32-28', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Up the Ramp', instruction: 'Prop a firm board at a 10-degree angle by resting one end on a low book. Hold your baby\'s hands as they walk up and down it.', why: 'An inclined surface recruits different leg muscles than flat walking, it\'s balance and strength training in one.', imageDescription: 'Parent and baby walking up and down a gently inclined board, both holding hands, bright warm room light.' },
  { id: 'm-32-29', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Crawl Through Leaves', instruction: 'On a dry day, pile up dry autumn leaves in the garden and let your baby crawl through them. The crinkle sound and texture makes every move an exploration.', why: 'Crawling through a novel, variable outdoor texture builds proprioceptive awareness and motor adaptability.', imageDescription: 'Baby crawling through a pile of dry autumn leaves in a garden, delighted at the crunch and sensation, golden light.' },
  { id: 'm-32-30', category: 'move', ageRangeStart: 32, ageRangeEnd: 40, title: 'Bounce and Catch', instruction: 'Bounce a large soft ball once in front of your sitting or standing baby. Say \'catch!\' and let it roll into their arms or belly. Celebrate any contact.', why: 'Receiving a moving object requires spatial prediction, timing, and bilateral arm response, all emerging at this age.', imageDescription: 'Baby bracing for a softly bounced ball rolling toward them, arms out, parent nearby, bright open floor space.' },
  { id: 'p-32-1', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'First Word Celebration', instruction: 'The moment you hear a consistent approximation of a word, celebrate it like it\'s the greatest thing that\'s ever happened. \'You said THAT! Did you hear what you just said?\'', why: 'The emotional response to a first word tells your baby that communication has enormous social power.', imageDescription: 'Parent\'s face in full delight as baby babbles a first word approximation, both in a joyful close-up.' },
  { id: 'p-32-2', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Follow Their Crawl', instruction: 'Follow your baby wherever they crawl, be their shadow for 10 minutes. Name everything they go toward, touch, or study. Let them entirely lead.', why: 'Following your baby\'s agenda communicates that their choices and interests are worth following.', imageDescription: 'Parent crawling behind baby across a living room floor, both in motion, warm natural light, joyful energy.' },
  { id: 'p-32-3', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Comfort Corner', instruction: 'Designate one corner of the room as your \'cozy spot\', a bean bag, cushions, or a blanket fort. Use it only for calm bonding activities, not play.', why: 'A consistent physical location associated with calm and closeness becomes an emotional anchor.', imageDescription: 'Parent and baby in a cozy cushion corner under soft light, both relaxed and close, warm bedroom light.' },
  { id: 'p-32-4', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Name Their Preference', instruction: 'When your baby clearly prefers something, a toy, a food, a person, say it out loud: \'You really love the blue cup, don\'t you. That\'s your favorite one.\'', why: 'Naming preferences validates your baby\'s identity and teaches them that their likes and dislikes are real and visible.', imageDescription: 'Parent commenting warmly on baby\'s clear toy preference, baby holding preferred toy, warm home light.' },
  { id: 'p-32-5', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Predictable Goodbye', instruction: 'Every time you leave the room, say your baby\'s name + \'I\'m going to the kitchen, I\'ll be right back.\' Return reliably. They\'re tracking this.', why: 'Reliable predictions followed by reliable returns build the neural pathway that anxious separation gradually dissolves.', imageDescription: 'Parent at a doorway looking back at baby on a mat, calm expression, saying goodbye before leaving.' },
  { id: 'p-32-6', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Laugh at Yourself', instruction: 'The next time you drop something or do something silly, laugh at yourself in front of your baby. Big, genuine, unworried laughter.', why: 'Watching you respond to imperfection with laughter teaches your baby that mistakes aren\'t dangerous.', imageDescription: 'Parent laughing at a small mistake in front of an amused 9-month-old, warm authentic home moment.' },
  { id: 'p-32-7', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Active Listening', instruction: 'When your baby babbles a long \'sentence,\' listen all the way to the end with the same interested face you\'d give an adult. Then respond as if you understood.', why: 'Being listened to completely is one of the most validating experiences, it teaches baby that their communication matters.', imageDescription: 'Parent listening intently to baby\'s babbling with a genuinely interested face, nodding, warm home light.' },
  { id: 'p-32-8', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Comfort in a New Place', instruction: 'When you go somewhere new, give your baby a moment to look around from the safety of your arms before putting them down. Let them signal when they\'re ready.', why: 'Respecting your baby\'s need to survey before engaging teaches them to trust their own regulatory signals.', imageDescription: 'Parent holding baby in a new environment, both scanning the room calmly, baby leaning but secure, warm light.' },
  { id: 'p-32-9', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Silliness Hour', instruction: 'Once a week, dedicate 20 minutes to being completely silly with your baby, no agenda, no learning goals, just whatever makes them dissolve into laughter.', why: 'Shared silliness is one of the purest forms of connection and play, it needs no justification.', imageDescription: 'Parent making an absurd face at a hysterically giggling baby on a blanket, pure joy, warm bright room.' },
  { id: 'p-32-10', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Tell Them a Story', instruction: 'Make up a simple story about your baby as the hero, \'Once there was a baby called [name] who was very curious...\', and tell it at bedtime.', why: 'Being the hero of a story builds identity and the feeling of being seen and celebrated.', imageDescription: 'Parent in dim evening light telling a story to a drowsy baby, warm lamp, animated but quiet expression.' },
  { id: 'p-32-11', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Curiosity Response', instruction: 'Whenever your baby shows curiosity, crawling toward something new, staring at something, respond with curiosity of your own: \'Oh! What\'s THAT?\' Go look together.', why: 'Matching and amplifying your baby\'s curiosity teaches them that wonder is valuable and worth pursuing.', imageDescription: 'Parent and baby both leaning toward something interesting on the floor, matching expressions of curiosity.' },
  { id: 'p-32-12', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Separation Recovery', instruction: 'When you return after any separation, take 60 seconds to fully reconnect before doing anything else, kneel to their level, say their name, get their eyes.', why: 'The return after separation is as important as the goodbye, full reconnection resets the attachment bond.', imageDescription: 'Parent kneeling to baby\'s level on return, making eye contact, baby reaching up, warm home hallway light.' },
  { id: 'p-32-13', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'First Book Together', instruction: 'Read your baby\'s favorite book together, but this time let them turn every page themselves. Follow their pace completely. Go back to any page they want.', why: 'Allowing baby to lead a shared activity at their own pace is joint attention on their terms, deeply bonding.', imageDescription: 'Baby turning a page in a board book, parent leaning close watching, both in a reading nook, warm lamp light.' },
  { id: 'p-32-14', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Physical Delight', instruction: 'Find one physical thing that sends your baby into pure delight, a particular bounce, a spin, a zerbert, and save it for moments when you need a connection reset.', why: 'Having a reliable shared joy that both of you love creates a shorthand for connection and warmth.', imageDescription: 'Parent doing their baby\'s favorite physical game, baby in hysterics, pure joy, warm bright light.' },
  { id: 'p-32-15', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Invite, Don\'t Instruct', instruction: 'Instead of \'do this,\' try \'should we try this?\' Instead of demonstrating, hold out the toy and let baby decide what to do with it.', why: 'Inviting rather than instructing gives your baby agency, which builds both confidence and trust in you.', imageDescription: 'Parent holding out a toy with an open questioning expression, baby reaching for it on their own terms.' },
  { id: 'p-32-16', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Photo Book of Them', instruction: 'Make a small photo book of your baby\'s own face at different ages. Show it to them and say their name and age at each picture: \'That\'s you at 2 months! And here at 6!\'', why: 'Seeing their own face at different ages helps build a narrative sense of self, who I was, who I am now.', imageDescription: 'Parent showing baby a small homemade photo book of themselves, baby reaching for their own picture.' },
  { id: 'p-32-17', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Touch Tour', instruction: 'Lay your baby in your lap and do a slow, loving touch tour, forehead, ears, shoulders, elbows, knees, toes, saying each body part in a warm, calm voice.', why: 'A loving physical inventory communicates complete attention and care for every part of who they are.', imageDescription: 'Parent doing a gentle body tour of baby lying in their lap, touching each part, warm afternoon light.' },
  { id: 'p-32-18', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Repair Moment', instruction: 'After any difficult feeding, bedtime, or activity, take 30 seconds to hold your baby and say: \'That was hard. But we got through it. We\'re good.\'', why: 'Post-difficulty warmth teaches your baby that hard things end and closeness follows, one of the most powerful lessons of childhood.', imageDescription: 'Parent holding baby calmly after a hard moment, both settling, warm room light, expression of relief and warmth.' },
  { id: 'p-32-19', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Music Memory', instruction: 'Play the same 3 songs from when your baby was tiny. Watch their reaction, some babies clearly recognize early musical memories.', why: 'Musical memory is often the earliest and most persistent form of memory, sharing it is a form of shared history.', imageDescription: 'Parent playing familiar songs from a phone or speaker to baby, watching for recognition, warm home light.' },
  { id: 'p-32-20', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Evening Recap', instruction: 'At bath or bedtime, briefly narrate the day back to your baby: \'Today we went to the park... you had avocado... the dog made you laugh.\' Use the same calm tone every night.', why: 'Daily recaps build episodic memory and a sense of narrative continuity, your baby is learning that days have stories.', imageDescription: 'Parent holding baby in dim evening bath light, narrating the day quietly, baby listening, peaceful atmosphere.' },
  { id: 'p-32-21', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Trust the Pause', instruction: 'When your baby is working on something hard, resist the urge to help. Sit with the discomfort of watching them struggle. Step in only if they signal they want you.', why: 'Watching your baby struggle without rushing in communicates: \'I believe you can do this.\' That is a profound message.', imageDescription: 'Parent sitting nearby watching baby work on something challenging, hands in lap, resisting urge to intervene.' },
  { id: 'p-32-22', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Delight Inventory', instruction: 'Spend 10 minutes listing everything your baby is currently delighted by, specific objects, sounds, faces, games. Then find a way to give them two of those things today.', why: 'Actively tracking what delights your particular baby deepens attunement and makes you a more responsive, attuned partner.', imageDescription: 'Parent jotting in a small notebook, baby nearby on a mat, parent looking up at baby with a warm observant smile.' },
  { id: 'p-32-23', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Peek-a-Boo with Hiding', instruction: 'Hide behind a door or around a corner so your baby can\'t see you. Call their name. Pop out. The full disappear-reappear cycle is more powerful than hands-over-face.', why: 'A full-body hide-and-reappear builds object permanence and trust simultaneously, they learn you come back.', imageDescription: 'Parent popping out from behind a door frame to a delighted crawling baby, both in a joyful reveal, warm light.' },
  { id: 'p-32-24', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Mood Match', instruction: 'Next time your baby is in a bright, energetic mood, match it fully, be as animated and energetic as they are. When they calm, slow down with them.', why: 'Mood matching is the physical practice of attunement, it tells your baby that their emotional state is seen and mirrored.', imageDescription: 'Parent and baby both in an animated, energetic playful moment, both bouncing or waving, warm bright room.' },
  { id: 'p-32-25', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Put the Phone Away', instruction: 'For the first 30 minutes after your baby wakes from their longest nap, put your phone in another room. Be completely available.', why: 'Full presence during a baby\'s peak alert window is when bonding and learning happen most intensively.', imageDescription: 'Parent sitting with phone-free hands on the floor fully engaged with baby, bright afternoon light, no devices visible.' },
  { id: 'p-32-26', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Comfort Object Introduction', instruction: 'If your baby doesn\'t have a lovey yet, introduce one now. Sleep with it for a night first, then give it consistently for naps and night sleep.', why: 'A comfort object that carries your scent is a portable piece of you, it extends your felt presence when you can\'t be there.', imageDescription: 'Baby holding a small soft lovey, parent nearby, baby exploring it with hands and mouth, warm room light.' },
  { id: 'p-32-27', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'The Goodbye Practice', instruction: 'Practice short separations deliberately: say goodbye clearly, leave for two minutes, come back, and make your return warm and matter-of-fact. Repeat.', why: 'Practicing small separations with reliable returns is how separation anxiety is gradually and gently worked through.', imageDescription: 'Parent at a doorway saying a calm warm goodbye to baby with a caregiver, then returning, bright home hallway.' },
  { id: 'p-32-28', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Their Favorite Person Day', instruction: 'Whoever your baby is currently most attached to, let that person be the primary caregiver for a full day. Don\'t compete or redirect. Just let the bond be.', why: 'Respecting and supporting your baby\'s current attachment hierarchy builds security, not dependency.', imageDescription: 'Baby reaching toward their favorite caregiver with joy, that person responding immediately, warm home light.' },
  { id: 'p-32-29', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Say It While You Feel It', instruction: 'The next time you feel a wave of love for your baby, that catch in your chest, say it right then, out loud, to them. \'Right now I just love you so much.\'', why: 'Spontaneous authentic expressions of love land differently than routine ones, your baby will feel the difference.', imageDescription: 'Parent holding baby and saying something from the heart, eyes soft and direct, warm afternoon home light.' },
  { id: 'p-32-30', category: 'play', ageRangeStart: 32, ageRangeEnd: 40, title: 'Morning Cuddle', instruction: 'Build in 10 minutes of quiet cuddle time first thing in the morning before the day starts, before getting dressed, before eating, before anything.', why: 'Beginning the day with physical closeness and no agenda sets a tone of warmth and security for everything that follows.', imageDescription: 'Parent and baby in a morning cuddle in bed or on a sofa, both still waking up, soft morning light, peaceful.' },
  { id: 's-40-1', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Real Word', instruction: 'Listen for a word your baby uses consistently to mean something specific, even \'ba\' for ball. When you hear it in context, respond to it as the real word.', why: 'Responding to first words as genuine communication is what transforms them from sounds into language.', imageDescription: 'Baby pointing and vocalizing a first word at something, parent responding with delight, warm home light.' },
  { id: 's-40-2', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Shape Sorter Intro', instruction: 'Give your baby a shape sorter with just two shapes, start with the circle, since it doesn\'t need to be rotated. Show once, then hand it back.', why: 'Getting a shape through the right hole requires spatial rotation thinking, one of the first geometric concepts.', imageDescription: 'Baby concentrating on inserting a circle into a shape sorter, tongue out, focused, warm bright play space.' },
  { id: 's-40-3', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Make the Call', instruction: 'Give your baby a toy phone or your switched-off phone. Hold one to your ear and say \'hello!\' See if they bring it to their own ear.', why: 'Using an object symbolically (phone = conversation) shows that symbolic understanding is well underway.', imageDescription: 'Baby holding a toy phone or switched-off phone to their ear, parent watching and smiling, warm home light.' },
  { id: 's-40-4', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Request Response', instruction: 'When your baby reaches and vocalizes toward something, wait for them to make a clear communicative attempt before giving it. Even one second of waiting teaches volumes.', why: 'Communicative intent, actively requesting, is the bridge between babbling and first words.', imageDescription: 'Baby reaching and vocalizing toward something on a shelf, parent waiting for the signal, warm home light.' },
  { id: 's-40-5', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Stacking Three Blocks', instruction: 'Slowly stack three blocks while your baby watches. Hand them a block and see if they try to add it. React with genuine surprise and delight if they do.', why: 'Building upward requires spatial planning, grip accuracy, and the intention to create, a genuine cognitive leap.', imageDescription: 'Baby placing a block on top of a two-block tower, concentrating, parent in delight, bright warm play space.' },
  { id: 's-40-6', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Two-Part Instruction', instruction: 'Give a two-part instruction: \'Get the ball and put it in the box.\' Demonstrate it once, then give a fresh ball and box and wait.', why: 'Following a two-part instruction requires sequencing and working memory, a brain function that\'s just coming online.', imageDescription: 'Baby following a two-step instruction, mid-action with a ball and a box, parent watching, warm home setting.' },
  { id: 's-40-7', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Say No Shake', instruction: 'When your baby reaches for something off-limits, shake your head \'no\' in a calm, consistent way, no raised voice, just the clear head shake. Wait for the pause.', why: 'Stopping an action in response to \'no\' is inhibitory control, one of the most important executive functions.', imageDescription: 'Baby pausing their reach for something, parent doing a calm head shake, moment of processing, warm light.' },
  { id: 's-40-8', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Read Together Daily', instruction: 'Make 10 minutes of book time a non-negotiable daily ritual. Let your baby choose the book. Read it once, then read whatever they want as long as they\'re interested.', why: 'Daily shared reading is the single most impactful language activity a parent can do in the first year.', imageDescription: 'Parent and baby reading a board book together on a sofa, baby pointing at pictures, warm afternoon light.' },
  { id: 's-40-9', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Sign for More', instruction: 'Every time your baby wants more food or a toy continued, bring their hands together (fingertips touching) and say \'more?\' Do this consistently for a week.', why: 'Baby signing \'more\' is often the first true word, signing gives language a physical form babies can produce before speech.', imageDescription: 'Parent demonstrating the \'more\' sign with baby\'s hands at the high chair, both focused, warm kitchen light.' },
  { id: 's-40-10', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Pretend Feed the Bear', instruction: 'Hold a teddy bear and offer it pretend food with a spoon: \'Here you go, bear, yum yum!\' Then hand the spoon to your baby and hold the bear toward them.', why: 'Pretend feeding requires understanding that actions can be performed on behalf of another, symbolic empathy.', imageDescription: 'Baby bringing a spoon toward a teddy bear, going along with the pretend play, parent watching, warm home.' },
  { id: 's-40-11', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Cause Reaction Toy', instruction: 'Give your baby a toy that does something dramatic when activated. After they figure it out, turn it so the button is slightly harder to find. Let them problem-solve.', why: 'Varying the challenge once a toy is mastered keeps engagement high and deepens cognitive flexibility.', imageDescription: 'Baby problem-solving with a cause-and-effect toy, trying different approaches, determined, warm bright room.' },
  { id: 's-40-12', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Show Me Your Shoe', instruction: 'Ask your baby to \'show me your shoe\' while sitting across from them. Wait 5 seconds before pointing. See if they look down at their own shoe first.', why: 'Responding to body-part words by looking or touching is a major receptive language milestone at this age.', imageDescription: 'Baby looking down at their own shoe after a parent asks about it, parent watching warmly, bright home light.' },
  { id: 's-40-13', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Count Everything', instruction: 'Count stairs, blocks, bites, and steps out loud: \'One step, two steps, three steps!\' Keep it the same rhythm, the same voice, every time.', why: 'Number words heard in context hundreds of times are the foundation of future counting and math.', imageDescription: 'Parent counting steps on stairs with baby in their arms, both going up, parent pointing at each step.' },
  { id: 's-40-14', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Where\'s Mama?', instruction: 'Leave the room briefly, just out of sight, and call your baby\'s name. Watch whether they crawl or walk to look for you.', why: 'Searching for a person who left the room shows that people, like objects, exist when absent, a major emotional-cognitive insight.', imageDescription: 'Baby crawling through a doorway looking for a parent who called their name, determined expression, warm home.' },
  { id: 's-40-15', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Your Own Name', instruction: 'Start regularly using your baby\'s name before a request: \'[Name], can you give that to me?\' Watch over time for them to look up or respond to just their name.', why: 'Reliably responding to their own name is an 11-month milestone, and consistent use is what teaches it.', imageDescription: 'Parent calling baby\'s name across a room, baby turning to look, bright natural home light, eye contact.' },
  { id: 's-40-16', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Introduce Pretend Play', instruction: 'Pretend to drink from an empty cup with a big \'ahhhh\' sound. Put the cup near baby. See if they try to drink from it too.', why: 'Imitating a pretend action is the first form of symbolic play, the cognitive breakthrough that all make-believe depends on.', imageDescription: 'Baby bringing an empty cup to their mouth in imitation of parent, both in the middle of the game, warm light.' },
  { id: 's-40-17', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'What Goes Together?', instruction: 'Present your baby with three objects: a cup and a spoon (which go together) and a block (which doesn\'t). See if they pair the cup and spoon spontaneously.', why: 'Identifying functional pairs, objects that go together, is relational reasoning beginning.', imageDescription: 'Baby picking up a cup and placing a spoon in it, experimenting, parent watching with interest, warm light.' },
  { id: 's-40-18', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Second Hiding Spot', instruction: 'With baby watching, hide a toy under one cloth, then move it to a second cloth. See if they search the second cloth or the first one (where they last saw it).', why: 'Following an object that visibly changes location is advanced object permanence, most babies of this age begin to track it correctly.', imageDescription: 'Baby lifting the second cloth to find a toy that was moved, triumphant expression, warm bright room.' },
  { id: 's-40-19', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Solve the Container', instruction: 'Put a toy inside a box and close the lid (don\'t lock it). Hand it to your baby. Wait and see if they figure out that the lid opens.', why: 'The closed container problem, understanding that something is inside and figuring out how to open it, is pure problem solving.', imageDescription: 'Baby concentrating on opening a box to retrieve a toy inside, twisting the lid, focused, warm light.' },
  { id: 's-40-20', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Point and Name', instruction: 'Every time your baby points at something, go to it with them, touch it, and name it slowly. Always respond to the point, never ignore it.', why: 'The pointing gesture is the most powerful language-learning engine a baby has, responding to it accelerates vocabulary exponentially.', imageDescription: 'Parent and baby both looking at something baby pointed to, parent naming it clearly, warm outdoor light.' },
  { id: 's-40-21', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Color Match Game', instruction: 'Put a red block in a red bowl and a yellow block in a yellow bowl while baby watches. Take them out, mix them, and hand them back one at a time.', why: 'Color matching, not just naming, is the first use of color as a sorting criterion.', imageDescription: 'Baby placing a block into a matching colored bowl, concentrating, parent watching, bright warm room light.' },
  { id: 's-40-22', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Story About Today', instruction: 'Every evening, briefly tell your baby what happened today as if it were a mini story: \'Today we woke up, then you had porridge, then we saw a cat!\'', why: 'Narrating the day\'s events builds episodic memory, sequencing, and the first seeds of autobiographical thinking.', imageDescription: 'Parent telling baby their day story in the evening, both on a sofa, baby listening, warm lamp light.' },
  { id: 's-40-23', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Read the Same Book Differently', instruction: 'Read a familiar book but this time pause on each page and ask a question: \'What\'s that? What do you think the duck is doing?\' Take the answer seriously.', why: 'Moving from passive listening to interactive engagement with a book transforms reading into conversation.', imageDescription: 'Parent and baby reading a familiar book, parent pointing with a questioning look, baby responding, warm light.' },
  { id: 's-40-24', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Up and Over', instruction: 'Stack two books to make a low step. Put a toy on the other side. Let your baby figure out how to get the toy, over, around, or through.', why: 'A simple physical obstacle requires spatial planning, baby must mentally model the path before moving.', imageDescription: 'Baby going over or around a low two-book obstacle to reach a toy, problem-solving, warm bright room.' },
  { id: 's-40-25', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Outdoor Number Hunt', instruction: 'On a walk, count things together: \'I see one dog. Now two birds. There are three flowers.\' Keep the numbers low, one, two, three is plenty.', why: 'Counting real things in the real world is how mathematical concepts become concrete.', imageDescription: 'Parent crouching with baby on a walk, both pointing at something, bright outdoor light, warm day.' },
  { id: 's-40-26', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Familiar Face, New Emotion', instruction: 'Show your baby a photo of a familiar person, grandparent or sibling, with a clearly different expression from how they normally look. Talk about the expression.', why: 'Recognizing the same person with different emotions is a higher-order social-cognitive skill.', imageDescription: 'Parent showing a photo to baby of someone they know, talking about the expression, bright home setting.' },
  { id: 's-40-27', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Name Their First Words', instruction: 'Keep a note on your phone of every consistent word approximation your baby produces. Review it weekly. Share the list with anyone who cares for them.', why: 'Tracking first words keeps you attentive to language development and celebrates every addition to their vocabulary.', imageDescription: 'Parent looking at their phone notes with a proud smile, baby nearby on the floor, warm natural home light.' },
  { id: 's-40-28', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Empty Box', instruction: 'Give your baby a completely empty box. Just that. Watch what they do with it over 10 minutes, sit in it, put things in it, wear it, tear it.', why: 'Open-ended objects with no predetermined use stimulate divergent thinking, the root of creativity and problem-solving.', imageDescription: 'Baby sitting inside or exploring a large empty cardboard box, completely absorbed, parent watching, warm room.' },
  { id: 's-40-29', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'Copy the Sequence', instruction: 'In front of your baby, bang a block, clap your hands, then bang again, in that exact order. Do it twice. Then hand them the block and wait.', why: 'Copying a three-step sequence requires working memory, observation, and motor reproduction, advanced imitation learning.', imageDescription: 'Baby watching a parent do a short sequence, then trying to copy it, concentrated, warm bright play space.' },
  { id: 's-40-30', category: 'spark', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Broken Toy', instruction: 'Give your baby a toy that needs a simple fix to work, a lid that needs closing, a piece that fell off. Watch how long they work on it before giving up or asking for help.', why: 'Persistence in the face of a broken or stuck object is an early executive function, a key predictor of learning.', imageDescription: 'Baby studying a toy that isn\'t working properly, trying different approaches, focused, warm home light.' },
  { id: 'm-40-1', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Solo Steps', instruction: 'Stand your baby between you and a partner, two feet apart. Let go. Call their name from the other side. Be exultant whenever they attempt it.', why: 'Solo steps require full single-leg balance, forward lean, and the courage to let go, cheer every single attempt.', imageDescription: 'Baby taking first solo steps between two parents, arms out, huge concentrated expression, bright room, joy.' },
  { id: 'm-40-2', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walking on a Slope', instruction: 'Find a gentle grassy slope and hold your baby\'s hands while walking up it, then down. The different muscle demands up vs. down are both important.', why: 'Inclined surfaces recruit different muscle groups than flat walking, building the full leg-strength spectrum.', imageDescription: 'Parent and baby walking hand-in-hand up a gentle grassy slope, both concentrating, bright outdoor light.' },
  { id: 'm-40-3', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Kick the Ball Forward', instruction: 'Roll a ball toward your baby\'s feet while they stand. Say \'kick it!\' and wait. Eventually they\'ll connect, when they do, make the biggest fuss.', why: 'A deliberate kick with one foot requires full single-leg balance on the other foot, a walking prerequisite.', imageDescription: 'Baby kicking a ball with one foot while balancing on the other, parent reacting with joy, bright open space.' },
  { id: 'm-40-4', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Carry the Watering Can', instruction: 'Give your baby a small watering can with a little water in it and show them how to pour it over a plant or patch of garden.', why: 'Carrying and purposeful pouring integrates strength, wrist control, aim, and the sense of real contribution.', imageDescription: 'Baby carrying a tiny watering can with both hands, pouring over a plant, concentrated, outdoor warm light.' },
  { id: 'm-40-5', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Stair Mastery', instruction: 'Practice going up and down stairs safely, up on hands and knees, down feet first on the tummy. Make each direction equally familiar and celebrated.', why: 'Safe stair management is both a practical life skill and a complex gross motor achievement.', imageDescription: 'Baby coming down stairs safely feet first on tummy, parent spotting, natural staircase, bright home light.' },
  { id: 'm-40-6', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walk Between Furniture', instruction: 'Set up a course of sofas and chairs two to three steps apart. Encourage your baby to walk between them, holding each piece of furniture between leaps.', why: 'The gap between furniture pieces is where independent walking happens, each traversal is a solo-steps rehearsal.', imageDescription: 'Baby stepping between two pieces of furniture, letting go for a moment, parent encouraging, bright home.' },
  { id: 'm-40-7', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Roll and Throw', instruction: 'Sit facing your baby and roll a soft ball back and forth. Then graduate to a very short underhand throw, just enough for them to bat or catch it.', why: 'The transition from rolling to throwing requires a different motor pattern: release, aim, and follow-through.', imageDescription: 'Parent and baby rolling a ball back and forth on a wooden floor, both engaged, warm bright room.' },
  { id: 'm-40-8', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Squat and Carry', instruction: 'Let your baby pick something up from the floor while standing, squatting, grabbing, and returning to standing, without holding on to anything.', why: 'A free-standing squat-and-stand is one of the most complex balance-strength tasks of the first year.', imageDescription: 'Baby squatting to pick something up from the floor, free-standing, concentrating, parent spotting, bright room.' },
  { id: 'm-40-9', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Balance Beam Walk', instruction: 'Put a piece of tape along the floor and walk your baby along it holding one hand. Encourage them to keep their feet on the line.', why: 'Walking a narrow path trains lateral balance and proprioceptive awareness in ways that open floor walking doesn\'t.', imageDescription: 'Baby walking along a tape line on the floor holding parent\'s hand, concentrating on the line, warm home light.' },
  { id: 'm-40-10', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Pop Bubbles Standing', instruction: 'Blow bubbles around your standing baby and watch them swipe, grab, and pop them while maintaining their balance.', why: 'Standing and reaching in different directions challenges balance dynamically, more complex than static standing.', imageDescription: 'Baby standing and reaching in different directions to pop bubbles, wobbling and correcting, warm room light.' },
  { id: 'm-40-11', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Duplo First Build', instruction: 'Give your baby two Duplo-style large bricks and show them how to click them together. Then add a third for them to try. The click itself is deeply satisfying.', why: 'Connecting bricks requires fine motor precision, two-hand coordination, and directional spatial understanding.', imageDescription: 'Baby clicking two large Duplo bricks together, focused and concentrating, parent watching, warm bright room.' },
  { id: 'm-40-12', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Ball in the Bucket', instruction: 'Stand a low bucket one step away from your baby. Hand them a ball and say \'throw it in!\' Even dropping it in counts, celebrate every attempt.', why: 'Aiming for a container while standing builds the visual-motor integration that throwing, catching, and sports will need.', imageDescription: 'Baby tossing a ball toward a small bucket, mid-throw expression, parent cheering, bright warm room.' },
  { id: 'm-40-13', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Freestanding Play', instruction: 'Set up toys on the floor where your baby will have to stand without holding anything to reach or play with them. Don\'t offer your hand unless they need it.', why: 'Freestanding, standing without holding anything, is the direct gateway to independent walking.', imageDescription: 'Baby standing freely without support, playing with something on the floor, concentrating, bright warm room.' },
  { id: 'm-40-14', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Dancing', instruction: 'Put on a fast song and dance in front of your baby, exaggerated, ridiculous, fun. Watch to see if they start to bounce, sway, or wave in response.', why: 'Moving the body in response to music is a complex integration of auditory and motor systems, and pure joy.', imageDescription: 'Baby bouncing and swaying to music while parent dances in front of them, both delighted, bright living room.' },
  { id: 'm-40-15', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Turn Pages', instruction: 'Let your baby turn the pages of a thick board book by themselves. Keep the book flat on the floor so both hands are free to grab the page.', why: 'Turning a single thick page requires pincer grip, wrist turn, and spatial aim, a fine motor achievement.', imageDescription: 'Baby turning a thick board book page on the floor, concentrating on the task, parent nearby, warm light.' },
  { id: 'm-40-16', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walk and Carry', instruction: 'Give your baby a lightweight soft toy to carry while walking. See if they can hold it in one arm while using their balance to walk.', why: 'Carrying while walking requires the brain to manage dual motor tasks, a major coordination challenge.', imageDescription: 'Baby walking with a soft toy tucked under one arm, concentrating on balance, parent watching, bright home.' },
  { id: 'm-40-17', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Obstacle Course', instruction: 'Create a simple baby obstacle course: crawl through a tunnel, walk around a chair, climb over a cushion, sit on a pillow. Go through it together at their pace.', why: 'A multi-stage course builds motor sequencing, planning and executing a series of movements in order.', imageDescription: 'Baby navigating a simple home obstacle course, mid-stage, parent cheering, bright playroom light.' },
  { id: 'm-40-18', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Gentle Push Off', instruction: 'Stand your baby against a wall. Hold your hands out at their chest height, one step away. Let them push off the wall and take that first step toward you.', why: 'Pushing off a surface to walk toward a target is the exact motor sequence of first independent steps.', imageDescription: 'Baby pushing off a wall toward parent\'s outstretched hands, one step, mid-air, parent reaching, bright room.' },
  { id: 'm-40-19', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Sand Walk', instruction: 'Take your baby to a beach or sandbox and walk them barefoot across the sand. Let them feel the different resistances, dry sand, wet sand, packed.', why: 'Walking on varying surfaces is one of the richest proprioceptive-motor experiences available to a developing walker.', imageDescription: 'Baby walking barefoot on sand, feet sinking slightly, parent holding one hand, bright outdoor beach light.' },
  { id: 'm-40-20', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Ramp and Walk', instruction: 'Prop a wooden board at a 10-degree angle. Let your baby walk up and down it holding your hand. Go slowly and name what their feet are doing.', why: 'An inclined surface requires forward and backward weight adjustment, a balance skill flat walking doesn\'t teach.', imageDescription: 'Baby walking up a gently inclined board holding parent\'s hand, concentrating, bright room light.' },
  { id: 'm-40-21', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walk Down a Step', instruction: 'Find one low step (1–2 inches). Hold your baby\'s hand and walk them off the step forward. Say \'step down!\' Make it a big deal each time.', why: 'A small forward step off a surface requires controlled forward weight shift, a balance skill that flat walking doesn\'t develop.', imageDescription: 'Baby stepping down one small step holding parent\'s hand, weight shifting forward, careful expression, bright home.' },
  { id: 'm-40-22', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Chase Me', instruction: 'Shuffle away from your baby on the floor and say \'come get me!\' Let them crawl or toddle after you. Move just fast enough to keep them chasing.', why: 'Purposeful pursuit of a moving target builds motor endurance, spatial tracking, and the motivation to move.', imageDescription: 'Parent shuffling away on all fours while baby crawls gleefully after them, both laughing, bright room.' },
  { id: 'm-40-23', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Throw Overhand', instruction: 'Demonstrate an overhand throw of a soft ball. Hand your baby the ball and say \'throw it!\' Any variation of raising the arm counts as a win.', why: 'An overhand throw requires the arm to pass behind the body, a different motor pattern from dropping or pushing, involving rotation.', imageDescription: 'Baby raising arm to throw a soft ball, mid-action, parent ready to receive, bright open floor, warm light.' },
  { id: 'm-40-24', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walking Backward', instruction: 'Hold both your baby\'s hands and walk backward slowly, leading them forward. Then try to walk them backward a few steps too, gently pulling their hands.', why: 'Walking backward is a vestibular and proprioceptive challenge that flat forward walking can never provide.', imageDescription: 'Parent leading baby to walk forward while parent walks backward, both facing each other, bright room, fun energy.' },
  { id: 'm-40-25', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Posting Letters', instruction: 'Make a tall narrow slot in a cereal box and collect pieces of stiff card. Show your baby how to post the card through the slot. Make a satisfying sound when each one goes in.', why: 'Posting through a narrow slot requires precise grip, orientation, and wrist control, one of the more complex fine motor tasks at this age.', imageDescription: 'Baby concentrating on posting a card through a narrow slot in a box, tongue out, focused, warm kitchen light.' },
  { id: 'm-40-26', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Seated Ball Roll', instruction: 'Sit facing your baby about two feet apart. Roll a ball to them and say \'roll it back!\' Wait. When they push it in any direction, celebrate.', why: 'Turn-taking with a ball teaches motor timing, visual tracking, and the emerging concept of reciprocal play.', imageDescription: 'Parent and baby sitting on a floor rolling a ball back and forth between them, both engaged, warm bright room.' },
  { id: 'm-40-27', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Push the Chair', instruction: 'Show your baby how to push a lightweight chair across a smooth floor. Let them try. If it moves, even slightly, celebrate.', why: 'Moving a large heavy object teaches the physical concept of force, effort equals movement, in a satisfying, real way.', imageDescription: 'Baby gripping the back of a lightweight chair and pushing it across a smooth floor, determined, bright room.' },
  { id: 'm-40-28', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Walking on Tiptoes', instruction: 'Hold your baby\'s hands and walk forward on your tiptoes together. Say \'up, up, up!\' as you go. Try to do three steps on tiptoe.', why: 'Tiptoe walking strengthens the calf and ankle muscles and introduces deliberate postural control.', imageDescription: 'Parent and baby walking on tiptoes holding hands, both elevated on toes, bright room, playful energy.' },
  { id: 'm-40-29', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'Reach Behind', instruction: 'While your baby stands, hold a toy just behind and to one side of them. Let them turn and reach for it without toppling.', why: 'Reaching behind the body while standing requires full trunk rotation and significant balance, a complex upright challenge.', imageDescription: 'Baby turning to reach behind them for a toy while standing, off-balance but managing, parent spotting, warm light.' },
  { id: 'm-40-30', category: 'move', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Tricycle Ride', instruction: 'If you have a push-along baby trike or ride-on, put your baby on it and push them slowly. Let them feel the forward movement and grip the handlebars.', why: 'Riding a vehicle, even a pushed one, builds the sense of self as a moving agent in space, distinct from walking.', imageDescription: 'Baby sitting on a small ride-on toy being pushed by a parent, gripping the handles, bright outdoor light.' },
  { id: 'p-40-1', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Their First Birthday Story', instruction: 'A few days before the first birthday, begin telling your baby the story of the day they were born, in warm, simple words. Tell it again on the day.', why: 'Origin stories are some of the most powerful identity-shaping gifts a parent can give.', imageDescription: 'Parent holding baby close, telling them something important in a warm quiet moment, soft home light.' },
  { id: 'p-40-2', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Acknowledge the Hard', instruction: 'When your baby falls, express frustration, or fails at something, validate it before fixing: \'That was hard. You\'re frustrated. That makes sense.\'', why: 'Validated frustration resolves faster than redirected frustration, and the validation is a form of deep respect.', imageDescription: 'Parent kneeling at baby\'s level after a small frustration, matching their feeling warmly, calm expression.' },
  { id: 'p-40-3', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Look Back', instruction: 'Find one early photo of your baby, from their first weeks, and look at it together. Tell them: \'This was you when you were very new.\'', why: 'Sharing early photos of your baby with your baby is the beginning of shared history, and a beautiful ritual.', imageDescription: 'Parent showing baby a phone screen with a photo of themselves as a newborn, baby reaching for the screen.' },
  { id: 'p-40-4', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Shared Meal Time', instruction: 'Eat the same meal together, whatever the baby-safe version is, at the same table, at the same time. Make it feel like a family dinner even if it\'s just two of you.', why: 'Sharing meals creates social rhythm, belonging, and the sense that food is a communal, pleasurable experience.', imageDescription: 'Parent and baby eating together at a table, both mid-meal, warm kitchen light, relaxed and happy atmosphere.' },
  { id: 'p-40-5', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Let Them Lead the Walk', instruction: 'On your next walk, let your baby set the pace and direction, within safety. Follow them. Go wherever they point or toddle toward, even if it\'s a patch of mud.', why: 'A walk where the baby leads is a profound message: your direction is worth following.', imageDescription: 'Baby toddling ahead on a path, parent following behind, both outdoors in bright natural light, joyful scene.' },
  { id: 'p-40-6', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Talk to Them Like a Person', instruction: 'Have one real conversation with your baby today, tell them something you\'re thinking about or something that happened. Don\'t simplify it. Trust them to listen.', why: 'Being spoken to as an equal, not as an infant, builds a child\'s sense of dignity and intelligence.', imageDescription: 'Parent talking seriously and warmly to baby, both sitting together, baby listening, warm natural light.' },
  { id: 'p-40-7', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Hug on Demand', instruction: 'When your baby reaches for you to be picked up, pick them up immediately whenever possible. Don\'t let them wait if you can help it.', why: 'Reliable, immediate physical comfort in response to a request is one of the clearest messages of secure attachment.', imageDescription: 'Parent immediately reaching down to pick up a reaching baby, both making eye contact, warm home light.' },
  { id: 'p-40-8', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Weekend Snuggle Time', instruction: 'Build in 20 minutes of unstructured couch or blanket time on weekend mornings, no activities, no toys. Just being together in soft clothes.', why: 'Unstructured closeness without agenda builds the sense that you simply enjoy being with them.', imageDescription: 'Parent and baby in pajamas on a sofa on a morning, cuddled up, warm morning light, relaxed weekend feel.' },
  { id: 'p-40-9', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'What You Made Me Think', instruction: 'Tell your baby today: \'When you did [X], it made me think [Y].\' Even something tiny. \'When you pointed at the bird, it made me think you love noticing things.\'', why: 'Being told the effect of your actions on someone else is the foundation of empathy and relational awareness.', imageDescription: 'Parent telling baby something they noticed about them, baby listening, warm natural home light, close.' },
  { id: 'p-40-10', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Matching Pajamas', instruction: 'Once this month, put on matching (or coordinating) PJs and take a photo. It\'s completely silly. It\'s also a shared identity moment.', why: 'Rituals of togetherness, however small, build the fabric of a child\'s sense of family and belonging.', imageDescription: 'Parent and baby in matching or coordinating pajamas, both in a cheerful morning mood, warm bedroom light.' },
  { id: 'p-40-11', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Running Commentary', instruction: 'For one hour today, narrate your inner experience out loud: \'I\'m feeling a bit tired. I\'m really happy we went outside. That lunch was nice.\' Your baby is listening.', why: 'Children who hear inner experience narrated develop richer inner language and emotional vocabulary.', imageDescription: 'Parent talking openly to baby while doing daily tasks, baby nearby listening, warm natural home light.' },
  { id: 'p-40-12', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Celebrate the Near Miss', instruction: 'When your baby almost does something, almost stacks the block, almost said the word, celebrate the attempt: \'You almost had it! You were SO close!\'', why: 'Effort celebration is far more powerful for long-term motivation than result celebration.', imageDescription: 'Baby mid-attempt at something challenging, parent with genuinely excited expression for the try, warm light.' },
  { id: 'p-40-13', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Family Ritual', instruction: 'Establish one thing you will do every Sunday (or every weekend) as a family unit, a pancake breakfast, a particular park walk, a family bath. Start it this week.', why: 'Family rituals are a child\'s earliest experience of \'us\', a sense of collective identity that is deeply protective.', imageDescription: 'Family doing a warm repeatable weekend ritual together, bright morning light, relaxed and joyful atmosphere.' },
  { id: 'p-40-14', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Thank You Practice', instruction: 'When your baby hands you something, say \'thank you\' properly, pause, eye contact, warm tone. Model the full social ritual.', why: 'Observing gratitude in context is how babies begin to understand that social acknowledgment matters.', imageDescription: 'Parent saying a genuine \'thank you\' to baby after being handed something, eye contact, warm home light.' },
  { id: 'p-40-15', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Watch Them Sleep', instruction: 'Once a week, spend 60 seconds watching your sleeping baby, just watching, with appreciation. Then leave them to it.', why: 'Deliberately appreciating your child in a quiet moment deepens your bond even when they\'re not aware of it.', imageDescription: 'Parent standing at the door of a nursery watching a sleeping baby, warm lamp light, peaceful expression.' },
  { id: 'p-40-16', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Meet Another Baby', instruction: 'Arrange regular time with another baby of similar age, a class, a playdate, a park meetup. Let them observe each other, they don\'t need to interact yet.', why: 'Observing another baby is how babies begin to develop social interest, the foundation of peer connection.', imageDescription: 'Two babies sitting near each other watching each other, two parents nearby, bright natural outdoor light.' },
  { id: 'p-40-17', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Forgiveness Repair', instruction: 'If you had a hard week, less present, more stressed than usual, acknowledge it simply: \'I was a bit distracted this week. I\'m here now.\'', why: 'Repair is the skill that matters more than perfection. Teaching your child that relationships can be restored is invaluable.', imageDescription: 'Parent with a soft expression holding baby close, eyes meeting, a moment of warmth after a hard week.' },
  { id: 'p-40-18', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Birthday Letter', instruction: 'Write your baby a letter for their first birthday. Describe who they are right now, what you love about them, and one thing you hope for their life. Seal it and save it.', why: 'Articulating your love at a milestone crystallizes the relationship at this point in time, a gift that grows over years.', imageDescription: 'Parent writing a letter at a table with a small birthday candle nearby, warm intimate light, thoughtful face.' },
  { id: 'p-40-19', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Hand in Hand', instruction: 'Walk somewhere together, even just to the kitchen, holding hands the whole way. No rush. Match your pace to theirs.', why: 'Walking hand in hand at their pace is one of the most physically direct experiences of partnership.', imageDescription: 'Parent and toddling baby walking hand in hand slowly across a room, both from behind, warm morning light.' },
  { id: 'p-40-20', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'One Full Day of Yes', instruction: 'For one day, say yes to every safe request, every \'up,\' every reach, every invitation to look at something together. Follow every signal.', why: 'A day of consistent responsiveness creates a dense, vivid bonding experience for both of you.', imageDescription: 'Parent saying yes to baby reaching up to be held, immediately bending down, warm joyful home light.' },
  { id: 'p-40-21', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Year in Review', instruction: 'Print or pull up photos from each month of your baby\'s first year. Look through them together. Name what was happening in each one.', why: 'A visual narrative of the year is your baby\'s first autobiographical story, the beginning of knowing who they are over time.', imageDescription: 'Parent and baby flipping through a photo album or phone together on a sofa, pointing at pictures, warm home light.' },
  { id: 'p-40-22', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'What You\'ve Learned', instruction: 'Tell your baby three things you\'ve learned from them this year. Not about them, from them. Be honest and specific.', why: 'Expressing what your baby has taught you tells them that their existence has changed and enriched you, the deepest form of appreciation.', imageDescription: 'Parent holding baby and speaking warmly, baby listening, golden afternoon light, intimate and reflective tone.' },
  { id: 'p-40-23', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'First Shared Book Choice', instruction: 'Put three board books on the floor. Let your baby crawl or walk to the one they want. Read that one, twice if they want. Let the choice be fully theirs.', why: 'Respecting your baby\'s autonomous choice, even in something small, builds agency and tells them their preferences matter.', imageDescription: 'Baby crawling toward a specific book on the floor, parent watching which one, warm natural light, books spread out.' },
  { id: 'p-40-24', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Silliness with No Purpose', instruction: 'Spend 20 minutes being completely ridiculous with your baby, no learning, no development goal, no reason. Just whatever makes both of you laugh.', why: 'Play without purpose is often the most connecting play of all. It communicates: I am here for the sheer joy of you.', imageDescription: 'Parent being completely silly with a hysterical baby on a blanket, both in full unguarded laughter, warm room.' },
  { id: 'p-40-25', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Tell Them Your Favorite Memory', instruction: 'Tell your baby about your single favorite memory from their first year. Say it like you\'re telling a story. Use their name. Include details.', why: 'Telling a child the story of a moment that mattered to you teaches them that they have already created memories worth keeping.', imageDescription: 'Parent holding baby and telling a story with a warm, slightly emotional expression, soft afternoon home light.' },
  { id: 'p-40-26', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'The Hand Holding Walk', instruction: 'Walk somewhere together holding hands, just hand in hand with no other agenda, matching their toddling pace the whole way.', why: 'Walking hand in hand at their speed, going nowhere in particular, is one of the simplest and most bonding physical experiences.', imageDescription: 'Parent and baby walking hand in hand from behind, both in casual clothes, warm natural light, unhurried pace.' },
  { id: 'p-40-27', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Let Them Say No', instruction: 'Offer something to your baby, a food, a toy, and if they turn away or push it back, say \'okay! No thank you!\' and honor it completely.', why: 'Having your \'no\' respected builds self-agency and teaches your baby that their preferences have real power.', imageDescription: 'Baby turning away from an offered food, parent nodding and accepting the refusal warmly, high chair, bright kitchen.' },
  { id: 'p-40-28', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Full Eye Contact Feed', instruction: 'For one mealtime today, give your baby full eye contact for the entire meal, look up when you spoon, smile when they open their mouth, react to every expression.', why: 'Feeding with full eye contact turns every mealtime into a dense bonding experience, one of the most frequent opportunities you have.', imageDescription: 'Parent spooning food to baby with warm full eye contact, both mid-interaction, bright kitchen, no distractions.' },
  { id: 'p-40-29', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Name the Hard Thing', instruction: 'Think of one genuinely hard part of this year. Say it out loud, to yourself or your baby: \'That was hard. And we got through it. That took something from both of us.\'', why: 'Acknowledging difficulty honestly, not just celebrating wins, models emotional realism and self-compassion.', imageDescription: 'Parent holding baby with a reflective, honest but warm expression, quiet room, late afternoon light, real moment.' },
  { id: 'p-40-30', category: 'play', ageRangeStart: 40, ageRangeEnd: 48, title: 'Promise Them Something', instruction: 'Make your baby one promise, something small and keepable, and say it out loud: \'I promise I will always come back when I leave. I promise.\'', why: 'A spoken promise is a relational contract, making it out loud deepens your own commitment and gives your baby a felt anchor.', imageDescription: 'Parent looking directly at baby with a serious, loving expression making a promise, warm home light, intimate.' },
  ...dailyActivities12to18RealWeeks,
  ...dailyActivities18to24RealWeeks,
];

function toLocalizedActivity(activity: RawActivity): HomeActivity {
  const greek = homeActivitiesGreek[activity.id as keyof typeof homeActivitiesGreek];
  return {
    ...activity,
    title: { en: activity.title, el: greek?.title ?? "Κείμενο δραστηριότητας διαθέσιμο σύντομα." },
    instruction: { en: activity.instruction, el: greek?.instruction ?? "Οδηγίες δραστηριότητας διαθέσιμες σύντομα." },
    why: { en: activity.why, el: greek?.why ?? "Εξήγηση δραστηριότητας διαθέσιμη σύντομα." },
  };
}

export const dailyActivities: HomeActivity[] = dailyActivitiesRaw.map(toLocalizedActivity);

export const exploreActivities: ExploreActivity[] = exploreActivities24;
